// ═══════════════════════════════════════════════════════════════
// BOOT
// ═══════════════════════════════════════════════════════════════

async function boot() {
  try {
    const { data: { session } } = await supabase.auth.getSession()

    if (session?.user) {
      const { data: maestro } = await supabase
        .from('maestros')
        .select('*')
        .eq('user_id', session.user.id)
        .single()

      if (maestro) {
        STATE.maestro = maestro
        showStudentSelector()
      } else {
        showLoginView()
      }
    } else {
      showLoginView()
    }
  } catch (err) {
    console.error('Boot error:', err)
    showLoginView()
  }
}

