import postulantesData from '../../../assets/data/mocks/postulantes.json'
import { puedeTransicionar, aplicarTransicion } from '../domain/postuladoStateMachine.js'

const delay = (ms = 50) => new Promise((resolve) => setTimeout(resolve, ms))

// Variable en memoria para persistir cambios durante la sesión de tests / demo
export let data = [...postulantesData]

// Helper para resetear la base de datos en memoria (muy útil para tests)
export function resetMockData() {
  data = [...postulantesData]
}

/**
 * Obtiene un postulante por ID.
 */
export async function obtenerPostulante(id) {
  await delay()
  return data.find((p) => p.id === id) ?? null
}

/**
 * Cambia el estado de un postulante en memoria.
 */
export async function actualizarEstadoPostulante(id, nuevoEstado, meta = {}) {
  await delay()
  const index = data.findIndex((p) => p.id === id)
  if (index === -1) {
    throw new Error(`Postulante con ID ${id} no encontrado`)
  }

  const postulanteActual = data[index]

  // Usar la máquina de estados pura para validar y aplicar
  const postulanteActualizado = aplicarTransicion(postulanteActual, nuevoEstado, meta)

  // Guardar en memoria
  data[index] = postulanteActualizado

  return postulanteActualizado
}

/**
 * Lista postulantes filtrados por mes de creación.
 * @param {number} year
 * @param {number} month  (1-12)
 */
export async function listarPostulantesPorMes(year, month) {
  await delay()
  return data.filter((p) => {
    if (!p.created_at) return false
    const date = new Date(p.created_at)
    return date.getFullYear() === year && date.getMonth() + 1 === month
  })
}

/**
 * Lista postulantes registrados en un rango de fechas, ordenados por fecha descendente.
 * @param {string} desde - ISO date string (ej. '2026-01-01')
 * @param {string} hasta - ISO date string (ej. '2026-06-30')
 * @returns {Promise<object[]>}
 */
export async function listarPostulantesPorRango(desde, hasta) {
  await delay()
  const desdeTime = new Date(desde).getTime()
  const hastaTime = new Date(hasta + 'T23:59:59.999Z').getTime()

  return data
    .filter((p) => {
      if (!p.created_at) return false
      const time = new Date(p.created_at).getTime()
      return time >= desdeTime && time <= hastaTime
    })
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
}

/**
 * Lista citas agendadas en un rango de fechas.
 */
export async function listarCitas(desde, hasta) {
  await delay()
  const start = new Date(desde).getTime()
  const end = new Date(hasta).getTime()

  return data
    .filter((p) => {
      if (!p.fecha_cita) return false
      const time = new Date(p.fecha_cita).getTime()
      return time >= start && time <= end
    })
    .sort((a, b) => new Date(a.fecha_cita) - new Date(b.fecha_cita))
}

/**
 * Verifica si hay conflicto de cita en un slot dado (±30 min).
 */
export async function hayConflictoCita(fechaHora, excludeId = null) {
  await delay()
  const targetTime = new Date(fechaHora).getTime()
  if (isNaN(targetTime)) {
    throw new Error('Fecha/Hora de cita inválida')
  }

  const margen = 30 * 60 * 1000 // 30 minutos en ms

  return data.some((p) => {
    if (excludeId && p.id === excludeId) return false
    if (!p.fecha_cita) return false

    // Solo verificar conflicto si está en estado de cita_agendada o reprogramado
    if (p.estado !== 'cita_agendada' && p.estado !== 'reprogramado') return false

    const time = new Date(p.fecha_cita).getTime()
    return Math.abs(time - targetTime) <= margen
  })
}

/**
 * Agrega una nota de seguimiento.
 */
export async function agregarNota(id, nota) {
  await delay()
  const index = data.findIndex((p) => p.id === id)
  if (index === -1) {
    throw new Error(`Postulante con ID ${id} no encontrado`)
  }

  const postulante = data[index]
  const notasPrevias = postulante.notas_seguimiento || postulante.notes || ''
  const nuevasNotas = notasPrevias ? `${notasPrevias}\n${nota}`.trim() : nota.trim()

  const postulanteActualizado = {
    ...postulante,
    notas_seguimiento: nuevasNotas,
  }

  data[index] = postulanteActualizado
  return postulanteActualizado
}

/**
 * Elimina permanentemente un postulante de la base de datos en memoria.
 * @param {string} id
 * @returns {Promise<boolean>}
 */
export async function eliminarPostulante(id) {
  await delay()
  const index = data.findIndex((p) => p.id === id)
  if (index === -1) {
    throw new Error(`Postulante con ID ${id} no encontrado`)
  }

  // Eliminar el registro del array en memoria
  data.splice(index, 1)

  return true
}

import { loadJsonMock } from '../../../core/utils/loadJsonMock.js'

const MOCK_DATA_PATH = '/assets/data/mocks/alumnos.json'

export class AlumnoTimeline {
  constructor(container) {
    this.container = container
    this.alumnoId = null
    this.eventos = []
    this.diasAMostrar = 30
  }

  async load(alumnoId) {
    this.alumnoId = alumnoId
    const data = await loadJsonMock(MOCK_DATA_PATH)
    const alumno = data.alumnos?.find(a => a.id === alumnoId)
    if (!alumno) {
      this.renderEmpty()
      return
    }
    this.eventos = this.parsearEventos(alumno)
    this.render()
  }

  parsearEventos(alumno) {
    const eventos = []
    const now = new Date()
    for (let i = 0; i < this.diasAMostrar; i++) {
      const fecha = new Date(now)
      fecha.setDate(fecha.getDate() - i)
      const fechaStr = fecha.toISOString().split('T')[0]
      if (Math.random() > 0.6) {
        eventos.push({
          id: `evt-${i}`,
          fecha: fechaStr,
          tipo: this.getTipoAleatorio(),
          descripcion: this.getDescripcionAleatoria(),
          icon: this.getIconoAleatorio()
        })
      }
    }
    return eventos.sort((a, b) => new Date(b.fecha) - new Date(a.fecha))
  }

  getTipoAleatorio() {
    const tipos = ['asistencia', 'clase', 'observacion', 'progreso', 'meta']
    return tipos[Math.floor(Math.random() * tipos.length)]
  }

  getDescripcionAleatoria() {
    const descs = [
      'Asistió a clase',
      'Completó练习',
      'Recibió observación positiva',
      'Advancó en su progreso',
      'Completó objetivo de gamificación'
    ]
    return descs[Math.floor(Math.random() * descs.length)]
  }

  getIconoAleatorio() {
    const icons = ['bi-calendar-check', 'bi-music-note', 'bi-chat-dots', 'bi-graph-up', 'bi-trophy']
    return icons[Math.floor(Math.random() * icons.length)]
  }

  render() {
    this.container.innerHTML = `
      <div class="alumno-timeline">
        <div class="timeline-header mb-3">
          <h6 class="fw-bold text-muted">Últimos ${this.diasAMostrar} días</h6>
        </div>
        <div class="timeline-list">
          ${this.eventos.length === 0
            ? '<p class="text-muted small">Sin eventos registrados</p>'
            : this.eventos.map(e => `
              <div class="timeline-item d-flex align-items-start mb-3">
                <div class="timeline-icon me-3">
                  <i class="bi ${e.icon}"></i>
                </div>
                <div class="flex-grow-1">
                  <div class="fw-medium">${e.descripcion}</div>
                  <small class="text-muted">${this.formatFecha(e.fecha)}</small>
                </div>
              </div>
            `).join('')
          }
        </div>
        ${this.eventos.length > 0 ? '<button class="btn btn-link btn-sm" id="timeline-load-more">Cargar más...</button>' : ''}
      </div>
    `

    const loadMoreBtn = document.getElementById('timeline-load-more')
    if (loadMoreBtn) {
      loadMoreBtn.addEventListener('click', () => this.cargarMas())
    }
  }

  renderEmpty() {
    this.container.innerHTML = `
      <div class="alumno-timeline">
        <p class="text-muted small">Selecciona un alumno para ver su timeline</p>
      </div>
    `
  }

  formatFecha(fechaStr) {
    const fecha = new Date(fechaStr)
    const hoy = new Date()
    const diff = Math.floor((hoy - fecha) / (1000 * 60 * 60 * 24))
    if (diff === 0) return 'Hoy'
    if (diff === 1) return 'Ayer'
    return fecha.toLocaleDateString('es-DO', { day: 'numeric', month: 'short' })
  }

  async cargarMas() {
    this.diasAMostrar += 30
    await this.load(this.alumnoId)
  }
}

export function createAlumnoTimeline(container) {
  return new AlumnoTimeline(container)
}

export function renderAlumnoTimeline(container, alumnoId) {
  const timeline = createAlumnoTimeline(container)
  timeline.load(alumnoId)
}

/**
 * Generador de reporte mensual de inscripciones — El Sistema Punta Cana
 */

import jsPDF from 'jspdf'
import autoTable from 'jspdf-autotable'

const BRAND_PRIMARY = [0, 86, 179]
const BRAND_ACCENT  = [255, 193, 7]
const BRAND_DARK    = [30, 30, 30]

const MESES = [
  '', 'Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio',
  'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre',
]

function pad(val, fallback = '—') {
  const s = String(val ?? '').trim()
  return s || fallback
}

function edad(fechaStr) {
  if (!fechaStr) return '—'
  try {
    const [y, m, d] = fechaStr.split('-').map(Number)
    const hoy = new Date()
    let age = hoy.getFullYear() - y
    if (hoy.getMonth() + 1 < m || (hoy.getMonth() + 1 === m && hoy.getDate() < d)) age--
    return String(age)
  } catch { return '—' }
}

function interesLabel(val) {
  return { cantar: 'Cantar', instrumento: 'Instrumento', ambas: 'Ambas' }[val] ?? pad(val)
}

function drawHeader(doc, title, subtitle) {
  const W = doc.internal.pageSize.getWidth()
  doc.setFillColor(...BRAND_PRIMARY)
  doc.rect(0, 0, W, 26, 'F')
  doc.setFillColor(...BRAND_ACCENT)
  doc.rect(0, 26, W, 2, 'F')
  doc.setTextColor(255, 255, 255)
  doc.setFontSize(14)
  doc.setFont('helvetica', 'bold')
  doc.text('El Sistema Punta Cana', 14, 10)
  doc.setFontSize(10)
  doc.setFont('helvetica', 'normal')
  doc.text(title, 14, 18)
  doc.setFontSize(7.5)
  doc.text(subtitle, 14, 24)
  doc.setTextColor(...BRAND_DARK)
}

function drawFooter(doc, page, total) {
  const W = doc.internal.pageSize.getWidth()
  const H = doc.internal.pageSize.getHeight()
  doc.setFillColor(...BRAND_PRIMARY)
  doc.rect(0, H - 8, W, 8, 'F')
  doc.setTextColor(255, 255, 255)
  doc.setFontSize(6.5)
  const fecha = new Date().toLocaleDateString('es-DO', { day: '2-digit', month: 'long', year: 'numeric' })
  doc.text(`El Sistema Punta Cana — Generado: ${fecha}`, 10, H - 3)
  doc.text(`Página ${page} de ${total}`, W - 10, H - 3, { align: 'right' })
}

/**
 * Genera el PDF del reporte mensual de inscripciones.
 *
 * @param {object[]} alumnos  - lista de alumnos del mes
 * @param {number}   year
 * @param {number}   month    - 1-based
 * @returns {jsPDF}
 */
export function generarReporteMensual(alumnos, year, month) {
  const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'letter' })
  const W = doc.internal.pageSize.getWidth()
  const mesLabel = `${MESES[month]} ${year}`
  const generadoEn = new Date().toLocaleDateString('es-DO', { day: '2-digit', month: 'long', year: 'numeric' })

  // ── Portada / resumen ──────────────────────────────────────────────────
  drawHeader(doc,
    `REPORTE DE INSCRIPCIONES — ${mesLabel.toUpperCase()}`,
    `Generado: ${generadoEn} · Total inscritos: ${alumnos.length}`
  )

  // Cuadro de estadísticas rápidas
  const totalConConocimientos  = alumnos.filter(a => a.tiene_conocimientos_musicales === true).length
  const totalSinConocimientos  = alumnos.filter(a => a.tiene_conocimientos_musicales === false || a.requiere_iniciacion_musical).length
  const totalSubsidio          = alumnos.filter(a => a.beneficiario_subsidio_estado === true).length
  const totalMonoparental      = alumnos.filter(a => a.familia_monoparental === true).length
  const totalAutorizaFotos     = alumnos.filter(a => a.autoriza_fotos_redes === true).length

  autoTable(doc, {
    startY: 36,
    margin: { left: 10, right: 10 },
    theme: 'grid',
    head: [['Total inscritos', 'Con conocimientos', 'Requieren iniciación', 'Beneficiarios subsidio', 'Fam. monoparental', 'Autorizan fotos']],
    body: [[
      alumnos.length,
      totalConConocimientos,
      totalSinConocimientos,
      totalSubsidio,
      totalMonoparental,
      totalAutorizaFotos,
    ]],
    headStyles: { fillColor: BRAND_PRIMARY, textColor: 255, fontStyle: 'bold', fontSize: 8, halign: 'center' },
    bodyStyles: { halign: 'center', fontSize: 11, fontStyle: 'bold' },
  })

  // ── Tabla principal ────────────────────────────────────────────────────
  const tableStartY = doc.lastAutoTable.finalY + 6

  const rows = alumnos.map((a, i) => [
    i + 1,
    pad(a.nombre_completo),
    edad(a.fecha_nacimiento),
    pad(a.nacionalidad),
    pad(a.municipio_residencia),
    pad(a.representante_nombre) + '\n' + pad(a.representante_tlf),
    interesLabel(a.interes_musical),
    pad(a.instrumento_interes),
    a.requiere_iniciacion_musical ? 'Sí' : 'No',
    a.acepta_pago_600 ? 'Sí' : 'No',
  ])

  autoTable(doc, {
    startY: tableStartY,
    margin: { left: 10, right: 10 },
    theme: 'striped',
    head: [['#', 'Nombre completo', 'Edad', 'Nac.', 'Municipio', 'Representante / Tlf', 'Interés', 'Instrumento', 'Iniciación', 'Pagó 600']],
    body: rows,
    headStyles: { fillColor: BRAND_PRIMARY, textColor: 255, fontStyle: 'bold', fontSize: 7.5 },
    bodyStyles: { fontSize: 7, cellPadding: 1.5 },
    alternateRowStyles: { fillColor: [240, 245, 255] },
    columnStyles: {
      0:  { cellWidth: 7,  halign: 'center' },
      1:  { cellWidth: 42 },
      2:  { cellWidth: 10, halign: 'center' },
      3:  { cellWidth: 14 },
      4:  { cellWidth: 20 },
      5:  { cellWidth: 42 },
      6:  { cellWidth: 16 },
      7:  { cellWidth: 22 },
      8:  { cellWidth: 15, halign: 'center' },
      9:  { cellWidth: 14, halign: 'center' },
    },
    didDrawPage: (data) => {
      const totalPages = doc.internal.getNumberOfPages()
      drawFooter(doc, data.pageNumber, totalPages)
    },
  })

  // ── Segunda tabla: datos socioculturales (nueva página) ───────────────
  if (alumnos.length > 0) {
    doc.addPage()
    drawHeader(doc,
      `PERFIL SOCIOCULTURAL — ${mesLabel.toUpperCase()}`,
      `Información motivacional y social de los alumnos inscritos`
    )

    const rowsSocial = alumnos.map((a, i) => [
      i + 1,
      pad(a.nombre_completo),
      pad(a.centro_estudios),
      pad(a.grado_nivel),
      a.padres_en_vida === 'ambos' ? 'Ambos' : a.padres_en_vida === 'solo_madre' ? 'Solo madre' : a.padres_en_vida === 'solo_padre' ? 'Solo padre' : a.padres_en_vida === 'ninguno' ? 'Ninguno' : '—',
      a.familia_monoparental ? 'Sí' : 'No',
      a.beneficiario_subsidio_estado ? 'Sí' : 'No',
      pad(a.por_que_unirse).slice(0, 80) + (pad(a.por_que_unirse).length > 80 ? '…' : ''),
      pad(a.musico_favorito),
    ])

    autoTable(doc, {
      startY: 36,
      margin: { left: 10, right: 10 },
      theme: 'striped',
      head: [['#', 'Nombre', 'Colegio', 'Grado', 'Padres en vida', 'Monopar.', 'Subsidio', '¿Por qué se unió?', 'Músico favorito']],
      body: rowsSocial,
      headStyles: { fillColor: BRAND_PRIMARY, textColor: 255, fontStyle: 'bold', fontSize: 7.5 },
      bodyStyles: { fontSize: 7, cellPadding: 1.5 },
      alternateRowStyles: { fillColor: [240, 245, 255] },
      columnStyles: {
        0: { cellWidth: 7, halign: 'center' },
        1: { cellWidth: 38 },
        2: { cellWidth: 38 },
        3: { cellWidth: 16 },
        4: { cellWidth: 20 },
        5: { cellWidth: 14, halign: 'center' },
        6: { cellWidth: 14, halign: 'center' },
        7: { cellWidth: 55 },
        8: { cellWidth: 28 },
      },
      didDrawPage: (data) => {
        const totalPages = doc.internal.getNumberOfPages()
        drawFooter(doc, data.pageNumber, totalPages)
      },
    })
  }

  // Fix footer page count now that all pages are known
  const totalPages = doc.internal.getNumberOfPages()
  for (let p = 1; p <= totalPages; p++) {
    doc.setPage(p)
    drawFooter(doc, p, totalPages)
  }

  return doc
}

/**
 * Descarga el reporte mensual como PDF.
 */
export function descargarReporteMensual(alumnos, year, month) {
  const MESES_SHORT = ['', 'enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio',
    'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre']
  const doc = generarReporteMensual(alumnos, year, month)
  doc.save(`reporte-inscripciones-${MESES_SHORT[month]}-${year}.pdf`)
}

