source:
import {
  listarPostulantesPorMes,
  listarPostulantesPorRango,
  sincronizarPostulantes,
  eliminarPostulante,
} from '../../api/postulantesApi.js'
import { ESTADO_LABELS, ESTADO_COLOR } from '../../domain/postuladoStateMachine.js'
import { descargarPdfPostulados } from '../../domain/generarPdfPostulados.js'
import { router } from '../../../../core/router/router.js'

/**
 * Helper: primer día del mes como string YYYY-MM-DD
 */
function primerDiaMes() {
  const now = new Date()
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`
}

/**
 * Helper: último día del mes como string YYYY-MM-DD
 */
function ultimoDiaMes() {
  const now = new Date()
  const ultimo = new Date(now.getFullYear(), now.getMonth() + 1, 0)
  return `${ultimo.getFullYear()}-${String(ultimo.getMonth() + 1).padStart(2, '0')}-${String(ultimo.getDate()).padStart(2, '0')}`
}

// Estado interno de la vista con paginación
const state = {
  year: new Date().getFullYear(),
  month: new Date().getMonth() + 1, // 1-12
  postulantes: [],
  filtroEstado: 'todos',
  cargando: false,
  page: 1,
  limit: 50,
  pdfDesde: primerDiaMes(),
  pdfHasta: ultimoDiaMes(),
}

const MESES = [
  'Enero',
  'Febrero',
  'Marzo',
  'Abril',
  'Mayo',
  'Junio',
  'Julio',
  'Agosto',
  'Septiembre',
  'Octubre',
  'Noviembre',
  'Diciembre',
]

/**
 * Determina el mejor nombre disponible para mostrar un postulante.
 * El campo nombre_completo a veces contiene valores incorrectos del Google Form
 * (respuestas de otras preguntas concatenadas). Esta función detecta esos casos
 * y cae al mejor fallback disponible.
 */
// Palabras que indican que el campo contiene algo que NO es un nombre de persona
const PALABRAS_NO_NOMBRE =
  /\b(alumno|alumna|puede|asistir|depende|transporte|p[uú]blico|propio|padres|amigos|familiares|punta\s*cana|veron|ver[oó]n|bávaro|bavaro|friusa|cortecito|ciudad|pueblo|municipio|sector|calle|avenida|disponibilidad|extracu|actividades|limitada|posible|haré|hare|cristiano|evang[eé]lico|cat[oó]lico)\b/i

function esNombrePersona(texto) {
  if (!texto || texto.length === 0) return false
  const t = texto.trim()
  // Demasiado largo para ser un nombre
  if (t.length > 70) return false
  // Contiene comas (múltiples valores CSV pegados)
  if (t.includes(',')) return false
  // Más de 5 palabras → probablemente una frase o dirección
  if (t.split(/\s+/).length > 5) return false
  // Contiene palabras que claramente no son de un nombre
  if (PALABRAS_NO_NOMBRE.test(t)) return false
  // Debe tener al menos una letra mayúscula (nombres propios)
  if (!/[A-ZÁÉÍÓÚÑ]/.test(t)) return false
  // Debe tener al menos 2 palabras O ser al menos 4 chars (nombres cortos como "Ana")
  if (t.length < 4) return false
  return true
}

function resolverNombre(p) {
  // Candidatos en orden de confianza
  const candidatos = [p.nombre_completo, p.madre_nombre, p.padre_nombre, p.representante_nombre]
  const valido = candidatos.map((v) => (v ?? '').trim()).find((v) => esNombrePersona(v))

  return valido ?? 'Sin nombre registrado'
}

function resolverIniciales(nombre) {
  return (
    nombre
      .split(' ')
      .filter((w) => w.length > 0)
      .slice(0, 2)
      .map((w) => w[0].toUpperCase())
      .join('') || '?'
  )
}

/**
 * Recolecta todos los números de WhatsApp disponibles de un postulante,
 * en orden de preferencia, con su etiqueta de origen.
 * @returns {{ label: string, numero: string }[]}
 */
function resolverTelefonos(p) {
  return [
    { persona: p.madre_nombre, numero: p.madre_tlf_whatsapp, rol: 'Madre' },
    { persona: p.padre_nombre, numero: p.padre_tlf_whatsapp, rol: 'Padre' },
    {
      persona: p.representante_nombre,
      numero: p.representante_tlf || p.telefono_representante,
      rol: 'Representante',
    },
    { persona: null, numero: p.telefono_alumno, rol: 'Alumno' },
  ]
    .filter(({ numero }) => {
      const n = (numero ?? '').trim()
      return n.length >= 7 && !/^(sin definir|no tiene|n\/a)$/i.test(n)
    })
    .map(({ persona, numero, rol }) => ({
      rol,
      nombre: esNombrePersona(persona ?? '') ? persona.trim() : null,
      numero: numero.trim(),
    }))
}

/**
 * Devuelve el primer número disponible, o null si no hay ninguno.
 */
function resolverTelefonoPrincipal(p) {
  return resolverTelefonos(p)[0]?.numero ?? null
}

function formatearNumero(n) {
  const d = n.replace(/\D/g, '')
  if (d.length === 10) return `${d.slice(0, 3)}-${d.slice(3, 6)}-${d.slice(6)}`
  return n
}

export async function renderPostuladosView(container) {
  state.filtroEstado = 'todos'
  state.page = 1 // Reset de página al recargar
  await cargarDatos(container)
}

async function cargarDatos(container) {
  try {
    state.cargando = true
    renderSkeleton(container)

    const todos = await listarPostulantesPorMes(state.year, state.month)
    // Solo postulantes con al menos un número de WhatsApp contactable
    state.postulantes = todos.filter((p) => resolverTelefonoPrincipal(p) !== null)
    state.cargando = false

    renderContent(container)
  } catch (error) {
    state.cargando = false
    renderError(container, error.message)
  }
}

function renderSkeleton(container) {
  container.innerHTML = `
    <div class="container-fluid py-4 px-3 px-md-4">
      <div class="d-flex justify-content-between align-items-center mb-4 flex-wrap gap-3">
        <div>
          <h1 class="h3 fw-bold mb-1">Módulo de Postulados</h1>
          <p class="text-secondary mb-0">Gestión de admisiones y pipeline de postulaciones</p>
        </div>
      </div>
      <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
        <div class="text-center">
          <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Cargando...</span>
          </div>
          <p class="text-muted mt-2">Cargando postulados...</p>
        </div>
      </div>
    </div>
  `
}

function renderError(container, message) {
  container.innerHTML = `
    <div class="container py-5">
      <div class="alert alert-danger shadow-sm border-0 d-flex flex-column align-items-center p-4 rounded-3 text-center" role="alert">
        <i class="bi bi-exclamation-triangle-fill text-danger fs-1 mb-3"></i>
        <h4 class="alert-heading fw-bold">Hubo un problema al cargar los datos</h4>
        <p class="mb-4">${message}</p>
        <button class="btn btn-primary" id="btn-error-retry">
          <i class="bi bi-arrow-clockwise me-1"></i> Reintentar
        </button>
      </div>
    </div>
  `

  document
    .getElementById('btn-error-retry')
    ?.addEventListener('click', () => renderPostuladosView(container))
}

function renderPipelineGraphic(counts, total) {
  if (total === 0) return ''

  const steps = [
    { key: 'postulado', label: 'Postulados' },
    { key: 'contactado', label: 'Contactados' },
    { key: 'cita_agendada', label: 'Con Cita' },
    { key: 'documentos_ok', label: 'Docs OK' },
    { key: 'inscrito', label: 'Inscritos' },
  ]

  const textSummary = steps
    .map((step) => {
      const val = counts[step.key] || 0
      return val > 0
        ? `<span class="text-body-secondary fw-medium">${val}</span> <span class="text-muted">${step.label}</span>`
        : null
    })
    .filter(Boolean)
    .join('<span class="text-muted mx-2">/</span>')

  return `
    <div class="mb-4 mt-2 px-1 small tracking-wide">
      ${textSummary}
    </div>
  `
}

function renderContent(container) {
  let list = getFilteredPostulantes()

  list.sort((a, b) => {
    const dateA = new Date(a.fecha_postulacion || a.created_at)
    const dateB = new Date(b.fecha_postulacion || b.created_at)
    return dateB - dateA
  })

  const totalRecords = list.length
  const totalPages = Math.ceil(totalRecords / state.limit) || 1

  if (state.page > totalPages) state.page = totalPages
  if (state.page < 1) state.page = 1

  const startIndex = (state.page - 1) * state.limit
  const endIndex = Math.min(startIndex + state.limit, totalRecords)
  const paginatedList = list.slice(startIndex, endIndex)

  const counts = getCountsByStatus()

  container.innerHTML = `
    <div class="container-fluid py-4 px-3 px-md-4 max-w-7xl mx-auto">
      
      <!-- MINIMALIST HEADER -->
      <div class="d-flex flex-column flex-md-row justify-content-between align-items-md-end mb-1 gap-3">
        <div>
          <h1 class="h2 fw-bold text-body tracking-tight mb-0">Postulados</h1>
        </div>
        
        <div class="d-flex align-items-center gap-4">
          <div class="d-flex align-items-center">
            <button class="btn btn-link text-body-secondary p-1 text-decoration-none" id="btn-month-prev">
              <i class="bi bi-chevron-left"></i>
            </button>
            <span class="fw-semibold text-body mx-3 fs-6">
              ${MESES[state.month - 1]} ${state.year}
            </span>
            <button class="btn btn-link text-body-secondary p-1 text-decoration-none" id="btn-month-next">
              <i class="bi bi-chevron-right"></i>
            </button>
          </div>
          
          <button class="btn btn-link text-decoration-none text-primary fw-medium p-0" id="btn-sync">
            <span class="spinner-border spinner-border-sm d-none me-1" id="sync-spinner"></span>
            <i class="bi bi-arrow-repeat me-1" id="sync-icon"></i> Sincronizar
          </button>
        </div>
      </div>

      <!-- DATE RANGE + PDF DOWNLOAD -->
      <div class="d-flex flex-wrap align-items-center gap-3 mb-2">
        <div class="d-flex align-items-center gap-2">
          <label for="pdf-desde" class="form-label small text-body-secondary mb-0">Desde</label>
          <input type="date" class="form-control form-control-sm" id="pdf-desde" value="${state.pdfDesde}">
        </div>
        <div class="d-flex align-items-center gap-2">
          <label for="pdf-hasta" class="form-label small text-body-secondary mb-0">Hasta</label>
          <input type="date" class="form-control form-control-sm" id="pdf-hasta" value="${state.pdfHasta}">
        </div>
        <button class="btn btn-outline-primary btn-sm" id="btn-descargar-pdf">
          <span class="spinner-border spinner-border-sm d-none me-1" id="pdf-spinner"></span>
          <i class="bi bi-file-earmark-pdf me-1" id="pdf-icon"></i> Descargar PDF
        </button>
      </div>

      <!-- PIPELINE SUMMARY -->
      ${renderPipelineGraphic(counts, state.postulantes.length)}

      <!-- MINIMALIST TABS -->
      <div class="d-flex gap-4 overflow-x-auto border-bottom border-secondary-subtle mb-4 scrollbar-hidden" style="white-space: nowrap;">
        <button class="btn btn-link px-1 pb-2 text-decoration-none rounded-0 border-0 ${state.filtroEstado === 'todos' ? 'text-body fw-bold border-bottom border-primary border-2' : 'text-body-secondary'}" data-filter="todos">
          Todos <span class="ms-1 small text-body-secondary">${state.postulantes.length}</span>
        </button>
        ${Object.entries(ESTADO_LABELS)
          .map(([key, label]) => {
            const count = counts[key] || 0
            if (count === 0 && state.filtroEstado !== key) return '' // Ocultar estados vacíos para no saturar
            const active = state.filtroEstado === key
            return `
            <button class="btn btn-link px-1 pb-2 text-decoration-none rounded-0 border-0 ${active ? 'text-body fw-bold border-bottom border-primary border-2' : 'text-body-secondary'}" data-filter="${key}">
              ${label} <span class="ms-1 small text-body-secondary">${count}</span>
            </button>
          `
          })
          .join('')}
      </div>

      <!-- MAIN CONTENT AREA -->
      <div class="bg-transparent">
        ${paginatedList.length === 0 ? renderEmptyState() : renderTable(paginatedList)}
        
        <!-- MINIMALIST PAGINATION -->
        ${
          totalRecords > 0
            ? `
          <div class="d-flex justify-content-between align-items-center mt-5 pt-4 border-top border-secondary-subtle">
            <span class="text-body-secondary small">
              ${startIndex + 1}-${endIndex} de ${totalRecords}
            </span>
            <div class="d-flex gap-3">
              <button class="btn btn-link text-decoration-none text-body p-0 ${state.page === 1 ? 'opacity-25' : ''}" id="btn-page-prev" ${state.page === 1 ? 'disabled' : ''}>
                <i class="bi bi-arrow-left"></i> Anterior
              </button>
              <button class="btn btn-link text-decoration-none text-body p-0 ${state.page === totalPages ? 'opacity-25' : ''}" id="btn-page-next" ${state.page === totalPages ? 'disabled' : ''}>
                Siguiente <i class="bi bi-arrow-right"></i>
              </button>
            </div>
          </div>
        `
            : ''
        }
      </div>
  `

  attachEvents(container)
}

function getFilteredPostulantes() {
  if (state.filtroEstado === 'todos') {
    return [...state.postulantes]
  }
  return state.postulantes.filter((p) => p.estado === state.filtroEstado)
}

function getCountsByStatus() {
  const counts = {}
  Object.keys(ESTADO_LABELS).forEach((k) => (counts[k] = 0))
  state.postulantes.forEach((p) => {
    const est = p.estado || 'postulado'
    if (counts[est] !== undefined) {
      counts[est]++
    }
  })
  return counts
}

function renderEmptyState() {
  return `
    <div class="text-center py-5 my-5">
      <h5 class="text-body-secondary fw-normal">No hay postulantes</h5>
    </div>
  `
}

function renderTable(list) {
  // Generador de filas HTML para Escritorio
  const desktopRows = list
    .map((p) => {
      const telefonos = resolverTelefonos(p)
      const phonesHTML = telefonos
        .map(({ rol, nombre, numero }) => {
          const digits = numero.replace(/\D/g, '')
          const waUrl = `https://wa.me/${digits}?text=${encodeURIComponent('Hola, le contactamos de El Sistema Punta Cana.')}`
          const etiqueta = nombre ? `${nombre} (${rol})` : rol
          return `<a href="${waUrl}" target="_blank" rel="noopener" class="d-flex align-items-center gap-2 text-decoration-none text-body mb-1" title="${etiqueta}">
        <i class="bi bi-whatsapp text-success small"></i>
        <span class="small">${formatearNumero(numero)}</span>
        <span class="text-body-secondary small fw-light">· ${etiqueta}</span>
      </a>`
        })
        .join('')

      const rawDate = p.fecha_postulacion || p.created_at
      const dateStr = rawDate
        ? new Date(rawDate).toLocaleDateString('es-ES', {
            day: '2-digit',
            month: 'short',
            year: 'numeric',
          })
        : '-'
      const estadoColor = ESTADO_COLOR[p.estado || 'postulado']
      const estadoLabel = ESTADO_LABELS[p.estado || 'postulado']

      return `
      <tr class="cursor-pointer" data-id="${p.id}">
        <td class="py-3">
          <div class="fw-medium text-body">${resolverNombre(p)}</div>
          ${
            estadoLabel
              ? `
          <div class="d-flex align-items-center gap-1 mt-1">
            <i class="bi bi-circle-fill text-${estadoColor}" style="font-size: 8px;"></i>
            <span class="text-body-secondary small">${estadoLabel}</span>
          </div>
          `
              : ''
          }
        </td>
        <td class="py-3 align-middle">
          <div class="d-flex flex-column justify-content-center">${phonesHTML}</div>
        </td>
        <td class="text-body-secondary small py-3 align-middle">${dateStr}</td>
        <td class="text-end pe-2 py-3 align-middle">
          <button class="btn btn-link text-body-secondary p-0 hover-danger btn-delete-postulante" data-id="${p.id}" data-name="${resolverNombre(p)}" title="Eliminar">
            <i class="bi bi-x-lg"></i>
          </button>
        </td>
      </tr>
    `
    })
    .join('')

  // Generador de lista limpia para Móvil (en vez de tarjetas pesadas)
  const mobileList = list
    .map((p) => {
      const telefonos = resolverTelefonos(p)
      const phonesHTML = telefonos
        .map(({ rol, nombre, numero }) => {
          const digits = numero.replace(/\D/g, '')
          const waUrl = `https://wa.me/${digits}?text=${encodeURIComponent('Hola, le contactamos de El Sistema Punta Cana.')}`
          return `<a href="${waUrl}" target="_blank" rel="noopener" class="text-decoration-none text-body me-3 mb-2 d-inline-flex align-items-center gap-1">
        <i class="bi bi-whatsapp text-success"></i> <span class="small fw-medium">${formatearNumero(numero)}</span>
      </a>`
        })
        .join('')

      const rawDate = p.fecha_postulacion || p.created_at
      const dateStr = rawDate
        ? new Date(rawDate).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })
        : '-'
      const estadoColor = ESTADO_COLOR[p.estado || 'postulado']
      const estadoLabel = ESTADO_LABELS[p.estado || 'postulado']

      return `
      <div class="border-bottom border-secondary-subtle py-3 cursor-pointer" data-id="${p.id}">
        <div class="d-flex justify-content-between align-items-start mb-2">
          <div>
            <div class="fw-semibold text-body fs-6">${resolverNombre(p)}</div>
            ${
              estadoLabel
                ? `
            <div class="d-flex align-items-center gap-1 mt-1">
              <i class="bi bi-circle-fill text-${estadoColor}" style="font-size: 8px;"></i>
              <span class="text-body-secondary small">${estadoLabel}</span>
            </div>
            `
                : ''
            }
          </div>
          <div class="text-end">
            <span class="text-body-secondary small d-block mb-1">${dateStr}</span>
          </div>
        </div>
        <div class="mt-2">
          ${phonesHTML}
        </div>
      </div>
    `
    })
    .join('')

  return `
    <div class="w-100">
      <!-- VISTA ESCRITORIO -->
      <div class="d-none d-md-block table-responsive">
        <table class="table align-middle mb-0 border-transparent">
          <thead>
            <tr>
              <th class="border-bottom border-secondary-subtle text-body-secondary fw-normal small pb-3">Postulante</th>
              <th class="border-bottom border-secondary-subtle text-body-secondary fw-normal small pb-3">Contacto</th>
              <th class="border-bottom border-secondary-subtle text-body-secondary fw-normal small pb-3">Fecha</th>
              <th class="border-bottom border-secondary-subtle text-end pe-2 fw-normal small pb-3">Acción</th>
            </tr>
          </thead>
          <tbody>
            ${desktopRows}
          </tbody>
        </table>
      </div>

      <!-- VISTA MÓVIL (Lista limpia) -->
      <div class="d-block d-md-none">
        ${mobileList}
      </div>
    </div>
  `
}

function attachEvents(container) {
  // Prevenir propagación de eventos en los links de WhatsApp para no gatillar la navegación al perfil
  container.querySelectorAll('.btn-wa-link').forEach((el) => {
    el.addEventListener('click', (e) => {
      e.stopPropagation()
    })
  })

  // Selector de mes ←
  document.getElementById('btn-month-prev')?.addEventListener('click', () => {
    state.month--
    if (state.month < 1) {
      state.month = 12
      state.year--
    }
    state.page = 1 // Reset de página al cambiar de mes
    cargarDatos(container)
  })

  // Selector de mes →
  document.getElementById('btn-month-next')?.addEventListener('click', () => {
    state.month++
    if (state.month > 12) {
      state.month = 1
      state.year++
    }
    state.page = 1 // Reset de página al cambiar de mes
    cargarDatos(container)
  })

  // Botón Sincronizar
  document.getElementById('btn-sync')?.addEventListener('click', async () => {
    const btn = document.getElementById('btn-sync')
    const spinner = document.getElementById('sync-spinner')
    const icon = document.getElementById('sync-icon')

    try {
      btn.disabled = true
      spinner.classList.remove('d-none')
      icon.classList.add('d-none')

      const result = await sincronizarPostulantes()

      alert(
        `Sincronización exitosa. Registros procesados: ${result.total_rows || result.upserted || 0}`,
      )
      state.page = 1
      cargarDatos(container)
    } catch (error) {
      alert(`Error al sincronizar: ${error.message}`)
      btn.disabled = false
      spinner.classList.add('d-none')
      icon.classList.remove('d-none')
    }
  })

  // Clicks en las pills de filtros
  container.querySelectorAll('[data-filter]').forEach((pill) => {
    pill.addEventListener('click', (e) => {
      const filter = e.currentTarget.getAttribute('data-filter')
      state.filtroEstado = filter
      state.page = 1 // Reset de página al filtrar
      renderContent(container)
    })
  })

  // Clicks en las filas de la tabla para navegar al perfil del postulado
  container.querySelectorAll('.hover-table-row').forEach((element) => {
    element.addEventListener('click', (e) => {
      const id = e.currentTarget.getAttribute('data-id')
      router.navigate('postulado', { id })
    })
  })

  // Escuchar clicks de eliminar postulación (con confirmación previa y parada de propagación)
  container.querySelectorAll('.btn-delete-postulante').forEach((btn) => {
    btn.addEventListener('click', async (e) => {
      e.stopPropagation() // Previene que se navegue al perfil al hacer clic en eliminar

      const button = e.currentTarget
      const id = button.getAttribute('data-id')
      const name = button.getAttribute('data-name')

      if (
        confirm(
          `¿Estás seguro de que deseas eliminar permanentemente la postulación de "${name}"?\n\nEsta acción eliminará el registro de la base de datos de forma irreversible.`,
        )
      ) {
        try {
          button.disabled = true
          await eliminarPostulante(id)
          alert('Postulación eliminada con éxito')
          cargarDatos(container) // Recargar el listado
        } catch (error) {
          alert(`Error al eliminar: ${error.message}`)
          button.disabled = false
        }
      }
    })
  })

  // Botón Descargar PDF por rango de fechas
  document.getElementById('btn-descargar-pdf')?.addEventListener('click', async () => {
    const desde = document.getElementById('pdf-desde')?.value
    const hasta = document.getElementById('pdf-hasta')?.value
    const btn = document.getElementById('btn-descargar-pdf')
    const spinner = document.getElementById('pdf-spinner')
    const icon = document.getElementById('pdf-icon')

    if (!desde || !hasta) {
      alert('Debe seleccionar una fecha de inicio y una fecha de fin.')
      return
    }

    if (desde > hasta) {
      alert('La fecha "Desde" no puede ser posterior a la fecha "Hasta".')
      return
    }

    try {
      btn.disabled = true
      spinner.classList.remove('d-none')
      icon.classList.add('d-none')

      const postulantes = await listarPostulantesPorRango(desde, hasta)

      if (!postulantes || postulantes.length === 0) {
        alert('No hay postulados registrados en el rango de fechas seleccionado.')
        return
      }

      descargarPdfPostulados(postulantes, desde, hasta)
    } catch (error) {
      alert(`Error al generar el PDF: ${error.message}`)
    } finally {
      btn.disabled = false
      spinner.classList.add('d-none')
      icon.classList.remove('d-none')
    }
  })

  // Paginación: Anteriores (Más recientes)
  document.getElementById('btn-page-prev')?.addEventListener('click', () => {
    if (state.page > 1) {
      state.page--
      renderContent(container)
    }
  })

  // Paginación: Siguientes (Más antiguos)
  document.getElementById('btn-page-next')?.addEventListener('click', () => {
    state.page++
    renderContent(container)
  })
}

import { obtenerAlumnosPorMes } from '../api/alumnosApi.js'
import { descargarReporteMensual } from '../domain/generarReporteMensual.js'
import { openEditAlumnoModal } from '../domain/editarAlumnoModal.js'

const MESES = [
  '',
  'Enero',
  'Febrero',
  'Marzo',
  'Abril',
  'Mayo',
  'Junio',
  'Julio',
  'Agosto',
  'Septiembre',
  'Octubre',
  'Noviembre',
  'Diciembre',
]

const CAMPOS_REQUERIDOS = [
  { key: 'fecha_nacimiento', label: 'Fecha de nacimiento' },
  { key: 'nacionalidad', label: 'Nacionalidad' },
  { key: 'municipio_residencia', label: 'Municipio de residencia' },
  { key: 'sector_calle_numero', label: 'Dirección / Sector' },
  { key: 'madre_nombre', label: 'Nombre de la madre' },
  { key: 'madre_tlf_whatsapp', label: 'Teléfono de la madre' },
  { key: 'representante_nombre', label: 'Nombre del representante' },
  { key: 'representante_parentesco', label: 'Parentesco del representante' },
  { key: 'representante_tlf', label: 'Teléfono del representante' },
  { key: 'interes_musical', label: 'Interés musical' },
  { key: 'instrumento_interes', label: 'Instrumento de interés' },
  { key: 'centro_estudios', label: 'Centro de estudios' },
  { key: 'acepta_pago_600', label: 'Acepta pago RD$600' },
  { key: 'autoriza_fotos_redes', label: 'Autoriza fotos/redes' },
]

function buildMonthOptions() {
  const hoy = new Date()
  let html = ''
  for (let i = 0; i < 24; i++) {
    const d = new Date(hoy.getFullYear(), hoy.getMonth() - i, 1)
    const y = d.getFullYear()
    const m = d.getMonth() + 1
    const selected = i === 0 ? 'selected' : ''
    html += `<option value="${y}-${m}" ${selected}>${MESES[m]} ${y}</option>`
  }
  return html
}

function edad(fechaStr) {
  if (!fechaStr) return null
  try {
    const [y, m, d] = fechaStr.split('-').map(Number)
    const hoy = new Date()
    let age = hoy.getFullYear() - y
    if (hoy.getMonth() + 1 < m || (hoy.getMonth() + 1 === m && hoy.getDate() < d)) age--
    return age
  } catch {
    return null
  }
}

function campoCompleto(val) {
  if (val === null || val === undefined) return false
  if (typeof val === 'boolean') return true
  if (typeof val === 'string') return val.trim() !== ''
  return true
}

function calcularCompletitud(alumno) {
  const camposFaltantes = CAMPOS_REQUERIDOS.filter((c) => !campoCompleto(alumno[c.key]))
  const completados = CAMPOS_REQUERIDOS.length - camposFaltantes.length
  const porcentaje = Math.round((completados / CAMPOS_REQUERIDOS.length) * 100)
  let estado
  if (porcentaje === 100) estado = 'completa'
  else if (porcentaje >= 70) estado = 'casi_completa'
  else estado = 'incompleta'

  return { completados, total: CAMPOS_REQUERIDOS.length, porcentaje, camposFaltantes, estado }
}

function badgeHtml(estado, porcentaje) {
  const styles = {
    completa: { rgb: 'var(--bs-success-rgb)', color: 'var(--bs-success)' },
    casi_completa: { rgb: 'var(--bs-warning-rgb)', color: 'var(--bs-warning)' },
    incompleta: { rgb: 'var(--bs-danger-rgb)', color: 'var(--bs-danger)' },
  }
  const s = styles[estado]
  const label =
    estado === 'completa'
      ? 'Completa'
      : `${porcentaje}% — ${estado === 'casi_completa' ? 'Faltan campos' : 'Incompleta'}`
  const icon =
    estado === 'completa'
      ? 'bi-check-circle-fill'
      : estado === 'casi_completa'
        ? 'bi-exclamation-circle-fill'
        : 'bi-x-circle-fill'

  return `<span class="badge border px-2 py-1"
            style="background-color: rgba(var(--bs-${estado === 'completa' ? 'success' : estado === 'casi_completa' ? 'warning' : 'danger'}-rgb), 0.12); color: var(--bs-${estado === 'completa' ? 'success' : estado === 'casi_completa' ? 'warning' : 'danger'}); border-color: rgba(var(--bs-${estado === 'completa' ? 'success' : estado === 'casi_completa' ? 'warning' : 'danger'}-rgb), 0.3) !important;">
            <i class="bi ${icon} me-1"></i>${label}
          </span>`
}

function renderResumen(alumnos) {
  if (!alumnos.length) return ''
  const total = alumnos.length
  const completas = alumnos.filter((a) => calcularCompletitud(a).estado === 'completa').length
  const incompletas = alumnos.filter((a) => calcularCompletitud(a).estado === 'incompleta').length
  const casiCompletas = alumnos.filter(
    (a) => calcularCompletitud(a).estado === 'casi_completa',
  ).length

  return `
    <div class="row g-3 mt-1 mb-2">
      <div class="col-6 col-md-3">
        <div class="card text-center border-primary h-100">
          <div class="card-body py-3">
            <div class="fs-2 fw-bold text-primary">${total}</div>
            <div class="small text-muted">Total inscritos</div>
          </div>
        </div>
      </div>
      <div class="col-6 col-md-3">
        <div class="card text-center border-success h-100">
          <div class="card-body py-3">
            <div class="fs-2 fw-bold text-success">${completas}</div>
            <div class="small text-muted">Completas</div>
          </div>
        </div>
      </div>
      <div class="col-6 col-md-3">
        <div class="card text-center border-warning h-100">
          <div class="card-body py-3">
            <div class="fs-2 fw-bold text-warning-emphasis">${casiCompletas}</div>
            <div class="small text-muted">Casi completas</div>
          </div>
        </div>
      </div>
      <div class="col-6 col-md-3">
        <div class="card text-center border-danger h-100">
          <div class="card-body py-3">
            <div class="fs-2 fw-bold text-danger">${incompletas}</div>
            <div class="small text-muted">Incompletas</div>
          </div>
        </div>
      </div>
    </div>`
}

function renderLista(alumnos) {
  if (!alumnos.length) {
    return `<div class="alert alert-info mt-3">
              <i class="bi bi-info-circle me-2"></i>No hay alumnos inscritos en este período.
            </div>`
  }

  const items = alumnos
    .map((a, i) => {
      const { porcentaje, camposFaltantes, estado, completados, total } = calcularCompletitud(a)
      const telefono = a.representante_tlf || a.madre_tlf_whatsapp || '—'
      const edadVal = edad(a.fecha_nacimiento)
      const edadStr = edadVal !== null ? `${edadVal} años` : ''

      const missingBadges =
        camposFaltantes.length > 0
          ? `<div class="d-flex flex-wrap gap-1 mt-1">
             ${camposFaltantes
               .slice(0, 4)
               .map(
                 (c) =>
                   `<span class="badge reporte-theme-badge border px-1 py-0" style="font-size:.6rem;">${c.label}</span>`,
               )
               .join('')}
             ${camposFaltantes.length > 4 ? `<span class="badge reporte-theme-badge border px-1 py-0" style="font-size:.6rem">+${camposFaltantes.length - 4}</span>` : ''}
           </div>`
          : ''

      return `
      <div class="list-group-item list-group-item-action px-3 py-2" data-alumno-id="${a.id}" role="button">
        <div class="d-flex align-items-center gap-3">
          <div class="flex-shrink-0 text-center" style="width:28px">
            <span class="text-muted small">${i + 1}</span>
          </div>
          <div class="flex-grow-1 min-width-0">
            <div class="fw-semibold text-truncate">${a.nombre_completo || '—'}</div>
            <div class="small text-muted">
              ${telefono !== '—' ? `<i class="bi bi-telephone me-1"></i>${telefono}` : ''}
              ${edadStr ? `<span class="ms-2"><i class="bi bi-calendar3 me-1"></i>${edadStr}</span>` : ''}
            </div>
            ${missingBadges}
          </div>
          <div class="flex-shrink-0 text-end ms-2">
            ${badgeHtml(estado, porcentaje)}
            <div class="small text-muted mt-1">${completados}/${total}</div>
          </div>
          <div class="flex-shrink-0 text-muted">
            <i class="bi bi-arrow-up-right-square"></i>
          </div>
        </div>
      </div>`
    })
    .join('')

  return `
    <div class="card shadow-sm mt-3">
      <div class="card-header bg-white py-2 d-flex justify-content-between align-items-center">
        <span class="fw-semibold small text-muted">ALUMNOS INSCRITOS</span>
        <span class="badge reporte-theme-badge rounded-pill">${alumnos.length}</span>
      </div>
      <div class="list-group list-group-flush" id="lista-inscritos">
        ${items}
      </div>
    </div>`
}

function initOpenEditOnClick(container) {
  container.addEventListener('click', (e) => {
    const item = e.target.closest('[data-alumno-id]')
    if (!item) return
    const id = item.dataset.alumnoId
    if (!id) return
    const btn = item.closest('#reporte-resultado')?.querySelector('#btn-filtrar')
    openEditAlumnoModal(id, {
      onSaved: () => btn?.click(),
    })
  })
}

export async function renderReporteInscripcionesMes(container) {
  const hoy = new Date()
  let currentYear = hoy.getFullYear()
  let currentMonth = hoy.getMonth() + 1
  let alumnosActuales = []

  async function cargar(year, month) {
    const resultDiv = container.querySelector('#reporte-resultado')
    if (resultDiv)
      resultDiv.innerHTML = `
      <div class="text-center py-4">
        <div class="spinner-border text-primary" role="status"></div>
        <p class="mt-2 text-muted">Cargando inscritos de ${MESES[month]} ${year}...</p>
      </div>`

    try {
      alumnosActuales = await obtenerAlumnosPorMes(year, month)

      if (resultDiv) {
        resultDiv.innerHTML = renderResumen(alumnosActuales) + renderLista(alumnosActuales)
        initOpenEditOnClick(resultDiv)
      }

      const btnPdf = container.querySelector('#btn-descargar-pdf')
      if (btnPdf) {
        btnPdf.disabled = alumnosActuales.length === 0
        btnPdf.textContent =
          alumnosActuales.length > 0
            ? `Descargar PDF (${alumnosActuales.length} alumnos)`
            : 'Sin inscritos'
      }
    } catch (err) {
      console.error(err)
      if (resultDiv)
        resultDiv.innerHTML = `
        <div class="alert alert-danger mt-3">
          <i class="bi bi-exclamation-triangle me-2"></i>Error al cargar los datos. Por favor intenta de nuevo.
        </div>`
    }
  }

  container.innerHTML = `
    <div class="container-fluid py-3">
      <div class="d-flex align-items-center justify-content-between mb-3 flex-wrap gap-2">
        <div>
          <h4 class="mb-0"><i class="bi bi-file-earmark-bar-graph me-2 text-primary"></i>Reporte de Inscripciones</h4>
          <p class="text-muted small mb-0">Alumnos inscritos por mes — El Sistema Punta Cana</p>
        </div>
        <button id="btn-descargar-pdf" class="btn btn-primary" disabled>
          <i class="bi bi-file-earmark-pdf me-2"></i>Descargar PDF
        </button>
      </div>

      <div class="card shadow-sm">
        <div class="card-body pb-2">
          <div class="row align-items-end g-2">
            <div class="col-auto">
              <label class="form-label mb-1 small fw-semibold">Período</label>
              <select id="select-mes" class="form-select form-select-sm" style="min-width:180px">
                ${buildMonthOptions()}
              </select>
            </div>
            <div class="col-auto">
              <button id="btn-filtrar" class="btn btn-outline-primary btn-sm">
                <i class="bi bi-search me-1"></i>Consultar
              </button>
            </div>
          </div>
        </div>
      </div>

      <div id="reporte-resultado"></div>
    </div>`

  container.querySelector('#btn-filtrar')?.addEventListener('click', () => {
    const val = container.querySelector('#select-mes')?.value ?? ''
    const [y, m] = val.split('-').map(Number)
    if (y && m) {
      currentYear = y
      currentMonth = m
      cargar(y, m)
    }
  })

  container.querySelector('#btn-descargar-pdf')?.addEventListener('click', () => {
    try {
      descargarReporteMensual(alumnosActuales, currentYear, currentMonth)
    } catch (e) {
      console.error('Error generando PDF:', e)
      alert('Error al generar el PDF. Por favor intenta de nuevo.')
    }
  })

  cargar(currentYear, currentMonth)
}

import { supabase } from '../../../lib/supabaseClient.js'

// ─── CONSTANTES ──────────────────────────────────────────────────────────────

export const ESTADOS = {
  PRESENTE: 'presente',
  AUSENTE: 'ausente',
  JUSTIFICADO: 'justificado',
  TARDE: 'tarde',
}

// Map UI abbreviations to database values
const ESTADO_MAP = {
  P: ESTADOS.PRESENTE,
  A: ESTADOS.AUSENTE,
  J: ESTADOS.JUSTIFICADO,
  T: ESTADOS.TARDE,
  presente: ESTADOS.PRESENTE,
  ausente: ESTADOS.AUSENTE,
  justificado: ESTADOS.JUSTIFICADO,
  tarde: ESTADOS.TARDE,
}

function mapEstado(estado) {
  if (!estado) return ESTADOS.PRESENTE
  return ESTADO_MAP[estado] || estado
}

// Etiquetas cortas para UI
export const ESTADO_LABEL = {
  presente: { short: 'P', label: 'Presente', css: 'success' },
  ausente: { short: 'A', label: 'Ausente', css: 'danger' },
  justificado: { short: 'J', label: 'Justificado', css: 'warning' },
}

// ─── HELPERS ─────────────────────────────────────────────────────────────────

function throwError(msg, err) {
  console.error(msg, err?.message)
  throw new Error(msg)
}

function isUniqueConstraintError(error) {
  const message = error?.message?.toLowerCase() || ''
  return (
    message.includes('unique constraint') ||
    message.includes('duplicate key') ||
    message.includes('uk_asistencias') ||
    (message.includes('unique') && message.includes('duplicate'))
  )
}

// ─── 1. TIMELINE AGRUPADO POR FECHA ─────────────────────────────────────────
// Retorna: { fecha, sesiones[] } agrupado para el timeline de la vista principal

export async function getSesionesPorRango({
  fechaInicio,
  fechaFin,
  periodoId,
  claseId,
  maestroId,
} = {}) {
  let query = supabase
    .from('sesiones_clase')
    .select(
      `
      id,
      fecha,
      hora_inicio,
      hora_fin,
      tema_principal,
      observaciones_generales,
      estado,
      clase_id,
      clases (
        id,
        nombre,
        instrumento,
        maestro_principal_id,
        maestros!fk_clases_maestro_principal (
          id,
          nombre_completo
        )
      ),
      asistencias (
        id,
        estado
      )
    `,
    )
    .order('fecha', { ascending: false })
    .order('hora_inicio', { ascending: true })

  if (fechaInicio) query = query.gte('fecha', fechaInicio)
  if (fechaFin) query = query.lte('fecha', fechaFin)
  if (claseId) query = query.eq('clase_id', claseId)

  // Filtrar por período si se provee
  if (periodoId) {
    const { data: periodo } = await supabase
      .from('periodos')
      .select('fecha_inicio, fecha_fin')
      .eq('id', periodoId)
      .single()

    if (periodo) {
      if (!fechaInicio) query = query.gte('fecha', periodo.fecha_inicio)
      if (!fechaFin) query = query.lte('fecha', periodo.fecha_fin)
    }
  }

  const { data, error } = await query
  if (error) throwError('No se pudieron cargar las sesiones', error)

  // Transformar y agregar conteos P/A/J
  const sesiones = (data || []).map((sc) => {
    const ayudas = sc.asistencias || []
    return {
      sesionId: sc.id,
      fecha: sc.fecha,
      horaInicio: sc.hora_inicio,
      horaFin: sc.hora_fin,
      temaPrincipal: sc.tema_principal,
      observacionesGenerales: sc.observaciones_generales,
      estado: sc.estado,
      claseId: sc.clase_id,
      claseNombre: sc.clases?.nombre ?? '—',
      instrumento: sc.clases?.instrumento ?? '—',
      maestroId: sc.clases?.maestro_principal_id ?? null,
      maestroNombre: sc.clases?.maestros?.nombre_completo ?? '—',
      totalPresentes: ayudas.filter((a) => a.estado === ESTADOS.PRESENTE).length,
      totalAusentes: ayudas.filter((a) => a.estado === ESTADOS.AUSENTE).length,
      totalJustificados: ayudas.filter((a) => a.estado === ESTADOS.JUSTIFICADO).length,
      totalRegistros: ayudas.length,
    }
  })

  // Filtrar por maestro si se provee (a través de la clase)
  let sesionesFiltradas = sesiones
  if (maestroId) {
    sesionesFiltradas = sesiones.filter((s) => {
      return s.maestroId && s.maestroId.toString() === maestroId.toString()
    })
  }

  // Agrupar por fecha → { '2026-05-02': [sesion, sesion], ... }
  return agruparPorFecha(sesionesFiltradas)
}

function agruparPorFecha(sesiones) {
  const map = new Map()
  for (const s of sesiones) {
    if (!map.has(s.fecha)) map.set(s.fecha, [])
    map.get(s.fecha).push(s)
  }
  // Retornar array ordenado descendente por fecha
  return Array.from(map.entries())
    .sort(([a], [b]) => b.localeCompare(a))
    .map(([fecha, sesiones]) => ({ fecha, sesiones }))
}

// ─── 2. DETALLE COMPLETO DE UNA SESIÓN (para el modal) ──────────────────────
// Retorna: { sesion, asistencias[], observaciones[] }

export async function getDetalleSesion(sesionId) {
  if (!sesionId) throwError('Se requiere sesionId')

  // Sesión + clase + maestro
  const { data: sc, error: errSc } = await supabase
    .from('sesiones_clase')
    .select(
      `
      id, fecha, hora_inicio, hora_fin,
      tema_principal, observaciones_generales, estado,
      clases (
        nombre, instrumento,
        maestros!fk_clases_maestro_principal ( nombre_completo )
      )
    `,
    )
    .eq('id', sesionId)
    .single()

  if (errSc) throwError('No se pudo cargar la sesión', errSc)

  // Asistencias + alumnos
  const { data: asistencias, error: errA } = await supabase
    .from('asistencias')
    .select(
      `
      id, estado, justificacion_texto, observaciones, alumno_id,
      alumnos ( id, nombre_completo )
    `,
    )
    .eq('sesion_clase_id', sesionId)
    .order('alumnos(nombre_completo)', { ascending: true })

  if (errA) throwError('No se pudieron cargar las asistencias', errA)

  // Justificaciones separadas (por falta de FK directa)
  const { data: justificaciones } = await supabase
    .from('justificaciones')
    .select('motivo, descripcion, archivo_url, estado, alumno_id')
    .eq('sesion_id', sesionId)

  const justificacionesMap = {}
  if (justificaciones) {
    justificaciones.forEach((j) => {
      justificacionesMap[j.alumno_id] = j
    })
  }

  // Observaciones por alumno vinculadas a esta sesión
  const { data: observaciones, error: errO } = await supabase
    .from('observaciones_alumnos')
    .select(
      `
      id, tipo, observacion, titulo, descripcion, prioridad,
      alumnos ( id, nombre_completo )
    `,
    )
    .eq('sesion_clase_id', sesionId)

  if (errO) throwError('No se pudieron cargar las observaciones', errO)

  // Contenidos trabajados (link a planificación)
  const { data: contenidos, error: errC } = await supabase
    .from('contenidos_sesion')
    .select(
      `
      id, descripcion, nivel_logro,
      planificaciones ( titulo, contenidos )
    `,
    )
    .eq('sesion_clase_id', sesionId)

  if (errC) throwError('No se pudieron cargar los contenidos', errC)

  return {
    sesion: {
      id: sc.id,
      fecha: sc.fecha,
      horaInicio: sc.hora_inicio,
      horaFin: sc.hora_fin,
      temaPrincipal: sc.tema_principal,
      observacionesGenerales: sc.observaciones_generales,
      estado: sc.estado,
      claseNombre: sc.clases?.nombre ?? '—',
      instrumento: sc.clases?.instrumento ?? '—',
      maestroNombre: sc.clases?.maestros?.nombre_completo ?? '—',
    },
    asistencias: (asistencias || []).map((a) => ({
      id: a.id,
      estado: a.estado,
      justificacionTexto: a.justificacion_texto,
      observacion: a.observaciones,
      alumnoId: a.alumno_id,
      alumnoNombre: a.alumnos?.nombre_completo ?? '—',
      justificacion: justificacionesMap[a.alumno_id] ?? null,
    })),
    observaciones: (observaciones || []).map((o) => ({
      id: o.id,
      tipo: o.tipo,
      titulo: o.titulo,
      descripcion: o.descripcion ?? o.observacion,
      prioridad: o.prioridad,
      alumnoId: o.alumnos?.id,
      alumnoNombre: o.alumnos?.nombre_completo ?? '—',
    })),
    contenidos: (contenidos || []).map((c) => ({
      id: c.id,
      descripcion: c.descripcion,
      nivelLogro: c.nivel_logro,
      planTitulo: c.planificaciones?.titulo,
    })),
  }
}

// ─── 3. REPORTE COMPLETO DEL PERÍODO (para exportar) ─────────────────────────
// Retorna estructura plana lista para Excel/PDF/MD

export async function getReporteCompleto({ fechaInicio, fechaFin, periodoId } = {}) {
  // Reutilizamos el timeline agrupado
  const grupos = await getSesionesPorRango({ fechaInicio, fechaFin, periodoId })

  // Para cada sesión del timeline, cargamos el detalle completo
  const sesionIds = grupos.flatMap((g) => g.sesiones.map((s) => s.sesionId))

  if (sesionIds.length === 0) return { grupos: [], sesiones: [], resumen: _resumenVacio() }

  const { data: asistencias, error } = await supabase
    .from('asistencias')
    .select(
      `
      id, estado, justificacion_texto, sesion_clase_id, alumno_id,
      alumnos ( id, nombre_completo )
    `,
    )
    .in('sesion_clase_id', sesionIds)
    .order('alumnos(nombre_completo)', { ascending: true })

  if (error) throwError('No se pudo generar el reporte', error)

  const { data: justificacionesData } = await supabase
    .from('justificaciones')
    .select('motivo, descripcion, alumno_id, sesion_id')
    .in('sesion_id', sesionIds)

  const justificacionesMap = {}
  if (justificacionesData) {
    justificacionesData.forEach((j) => {
      justificacionesMap[`${j.sesion_id}_${j.alumno_id}`] = j
    })
  }

  // Indexar asistencias por sesion_clase_id
  const asistenciasPorSesion = {}
  for (const a of asistencias || []) {
    if (!asistenciasPorSesion[a.sesion_clase_id]) {
      asistenciasPorSesion[a.sesion_clase_id] = []
    }
    asistenciasPorSesion[a.sesion_clase_id].push({
      alumnoNombre: a.alumnos?.nombre_completo ?? '—',
      estado: a.estado,
      justificacionTexto: a.justificacion_texto,
      justificacionMotivo:
        justificacionesMap[`${a.sesion_clase_id}_${a.alumno_id}`]?.motivo ?? null,
    })
  }

  // Enriquecer el timeline con los detalles de asistencia
  const gruposConDetalle = grupos.map((grupo) => ({
    fecha: grupo.fecha,
    sesiones: grupo.sesiones.map((s) => ({
      ...s,
      alumnos: asistenciasPorSesion[s.sesionId] || [],
    })),
  }))

  // Resumen global
  const todasAsistencias = asistencias || []
  const resumen = {
    totalSesiones: sesionIds.length,
    totalRegistros: todasAsistencias.length,
    totalPresentes: todasAsistencias.filter((a) => a.estado === ESTADOS.PRESENTE).length,
    totalAusentes: todasAsistencias.filter((a) => a.estado === ESTADOS.AUSENTE).length,
    totalJustificados: todasAsistencias.filter((a) => a.estado === ESTADOS.JUSTIFICADO).length,
  }

  return { grupos: gruposConDetalle, resumen }
}

function _resumenVacio() {
  return {
    totalSesiones: 0,
    totalRegistros: 0,
    totalPresentes: 0,
    totalAusentes: 0,
    totalJustificados: 0,
  }
}

