export async function crearAsistencia(asistencia) {
  const estadosValidos = Object.values(ESTADOS)
  if (!asistencia.clase_id) throwError('La clase es obligatoria')
  if (!asistencia.alumno_id) throwError('El alumno es obligatorio')
  if (!asistencia.fecha) throwError('La fecha es obligatoria')
  if (!asistencia.estado || !estadosValidos.includes(asistencia.estado)) {
    throwError(`Estado inválido. Debe ser: ${estadosValidos.join(', ')}`)
  }

  const { data, error } = await supabase
    .from('asistencias')
    .insert([
      {
        clase_id: asistencia.clase_id,
        alumno_id: asistencia.alumno_id,
        fecha: asistencia.fecha,
        estado: asistencia.estado,
        justificacion_texto: (asistencia.justificacion_texto || '').trim() || null,
        observaciones: (asistencia.observaciones || '').trim() || null,
        ...(asistencia.sesion_clase_id ? { sesion_clase_id: asistencia.sesion_clase_id } : {}),
        ...(asistencia.registrado_por ? { registrado_por: asistencia.registrado_por } : {}),
      },
    ])
    .select()
  if (error) throwError('No se pudo crear la asistencia', error)
  return data[0]
}

export async function registrarAsistenciaBulk(asistencias) {
  if (!asistencias?.length) throwError('No hay asistencias para registrar')

  // STEP 1: Validate that all alumno_ids exist
  const alumnoIds = [...new Set(asistencias.map((a) => a.alumno_id))]
  if (alumnoIds.some((id) => !id)) {
    throwError('Todas las asistencias deben tener alumno_id')
  }

  const { data: estudiantesExistentes, error: errorEstudiantes } = await supabase
    .from('alumnos')
    .select('id')
    .in('id', alumnoIds)

  if (errorEstudiantes) {
    throwError('No se pudo validar alumnos en la base de datos', errorEstudiantes)
  }

  const alumnosValidosSet = new Set(estudiantesExistentes?.map((e) => e.id) || [])
  const alumnosInvalidos = alumnoIds.filter((id) => !alumnosValidosSet.has(id))

  if (alumnosInvalidos.length > 0) {
    throwError(`Los siguientes alumnos no existen: ${alumnosInvalidos.join(', ')}`)
  }

  // STEP 2: Prepare records with validated data
  const records = asistencias
    .filter((a) => {
      // Skip records without sesion_clase_id (Bug #10: offline mode)
      if (!a.sesion_clase_id) {
        console.warn(
          `[asistenciasApi] Saltando alumno ${a.alumno_id} sin sesion_clase_id (se sincronizará vía offline queue)`,
        )
        return false
      }
      return true
    })
    .map((a) => {
      if (!a.clase_id) {
        throw new Error(`clase_id es requerido para alumno ${a.alumno_id}`)
      }
      if (!a.fecha) {
        throw new Error(`fecha es requerido para alumno ${a.alumno_id}`)
      }
      return {
        sesion_clase_id: a.sesion_clase_id,
        clase_id: a.clase_id,
        alumno_id: a.alumno_id,
        fecha: a.fecha,
        estado: mapEstado(a.estado),
        justificacion_texto: (a.justificacion_texto || '').trim() || null,
        observaciones: (a.observaciones || '').trim() || null,
        ...(a.registrado_por ? { registrado_por: a.registrado_por } : {}),
      }
    })

  if (records.length === 0) {
    console.warn('[asistenciasApi] No hay registros válidos con sesion_clase_id para insertar')
    return []
  }

  // STEP 3: Try UPSERT with composite key
  const { data, error } = await supabase
    .from('asistencias')
    .upsert(records, { onConflict: 'clase_id,alumno_id,fecha' })
    .select()

  // If unique constraint error, try INSERT as fallback
  if (error && isUniqueConstraintError(error)) {
    console.warn(
      '[registrarAsistenciaBulk] Constraint detected, trying plain INSERT:',
      error.message,
    )
    const { data: insertData, error: insertError } = await supabase
      .from('asistencias')
      .insert(records, { returning: 'representation' })
      .select()

    if (insertError) {
      // If INSERT also fails, throw original UPSERT error
      throwError('No se pudieron registrar las asistencias (UPSERT y INSERT fallidos)', error)
    }
    return insertData || []
  }

  if (error) throwError('No se pudieron registrar las asistencias', error)
  return data
}

// ─── REPORTE CONSOLIDADO POR CLASE ──────────────────────────────────────
// Agrupa por Clase + Horario (no por sesión individual)
// Consolida asistencias de múltiples sesiones del mismo día

export async function getReporteConsolidado({ periodoId, fecha, claseId } = {}) {
  try {
    // Obtener período si se provee (para filtrar por rango de fechas)
    let periodoFechaInicio, periodoFechaFin
    if (periodoId) {
      const { data: periodo, error: errPeriodo } = await supabase
        .from('periodos')
        .select('fecha_inicio, fecha_fin')
        .eq('id', periodoId)
        .single()
      if (errPeriodo) {
        console.warn('No se pudo cargar el período, mostrando todas las sesiones', errPeriodo)
      }
      if (periodo) {
        periodoFechaInicio = periodo.fecha_inicio
        periodoFechaFin = periodo.fecha_fin
      }
    }

    // PASO ÚNICO: Obtener todas las sesiones consolidadas desde la vista SQL
    let query = supabase.from('vw_asistencias_consolidada').select(`
        fecha,
        sesion_clase_id,
        clase_id,
        nombre_clase,
        hora_inicio,
        hora_fin,
        borrador,
        maestro_principal,
        maestro_auxiliar,
        observacion_clase,
        observacion_sesion,
        presentes,
        ausentes,
        justificados,
        total_registros,
        asistencias_detalle,
        justificaciones_detalle
      `)

    // Aplicar filtros
    if (periodoFechaInicio) query = query.gte('fecha', periodoFechaInicio)
    if (periodoFechaFin) query = query.lte('fecha', periodoFechaFin)
    if (fecha) query = query.eq('fecha', fecha)
    if (claseId) query = query.eq('clase_id', claseId)

    let { data: sesiones, error } = await query
      .order('fecha', { ascending: false })
      .order('hora_inicio', { ascending: true })
    if (error) throwError('No se pudieron cargar las sesiones consolidadas', error)

    if (!Array.isArray(sesiones)) {
      console.warn('sesiones no es un array, usando array vacío', sesiones)
      sesiones = []
    }

    // 🔥 FILTRO CRÍTICO: Excluir sesiones borradores (incompletas/abandonadas)
    // Solo mostrar sesiones guardadas (borrador = false)
    sesiones = sesiones.filter((s) => s.borrador === false)
    // PASO 2: Transformar datos de la vista en formato timeline (fecha → clases)
    // Los datos ya vienen consolidados, solo necesitamos agrupar por fecha
    const timelineByDate = {}

    if (sesiones && sesiones.length > 0) {
      sesiones.forEach((row) => {
        const clase = {
          clase_id: row.clase_id,
          clase_nombre: row.nombre_clase,
          fecha: row.fecha,
          hora_inicio: row.hora_inicio,
          hora_fin: row.hora_fin,
          maestro_nombre: row.maestro_principal || 'Sin asignar',
          maestro_auxiliar_nombre: row.maestro_auxiliar || null,
          observacion_clase: row.observacion_clase || null,
          observacion_sesion: row.observacion_sesion || null,
          presentes: row.presentes || 0,
          ausentes: row.ausentes || 0,
          justificados: row.justificados || 0,
          total_alumnos: row.total_registros || 0,
          asistencias: row.asistencias_detalle
            ? Array.isArray(row.asistencias_detalle)
              ? row.asistencias_detalle
              : JSON.parse(row.asistencias_detalle || '[]')
            : [],
          justificaciones: row.justificaciones_detalle
            ? Array.isArray(row.justificaciones_detalle)
              ? row.justificaciones_detalle
              : JSON.parse(row.justificaciones_detalle || '[]')
            : [],
        }

        // Agrupar por fecha
        if (!timelineByDate[row.fecha]) {
          timelineByDate[row.fecha] = []
        }
        timelineByDate[row.fecha].push(clase)
      })
    }

    // Convertir a array ordenado descendente por fecha
    const timeline = Object.entries(timelineByDate)
      .sort(([dateA], [dateB]) => dateB.localeCompare(dateA))
      .map(([fecha, clases]) => ({
        fecha,
        clases: clases.sort((a, b) => (a.hora_inicio || '').localeCompare(b.hora_inicio || '')),
      }))

    // Calcular resumen global
    const todasLasClases = timeline.flatMap((d) => d.clases)
    const resumenGlobal = {
      totalClases: todasLasClases.length,
      totalPresentes: todasLasClases.reduce((sum, c) => sum + c.presentes, 0),
      totalAusentes: todasLasClases.reduce((sum, c) => sum + c.ausentes, 0),
      totalJustificados: todasLasClases.reduce((sum, c) => sum + c.justificados, 0),
      totalRegistros: todasLasClases.reduce((sum, c) => sum + c.total_alumnos, 0),
      totalSesiones: sesiones.length,
    }

    return {
      timelineByDate: timeline,
      resumenGlobal,
    }
  } catch (err) {
    throwError('Error en getReporteConsolidado', err)
  }
}

import { AppModal } from '../../../shared/components/AppModal.js'
import { getReporteCompleto } from '../api/asistenciasApi.js'

export async function openAsistenciaExportModal(params = {}, onExport) {
  const formatos = [
    { id: 'xlsx', label: 'Excel (.xlsx)', icon: 'bi-file-earmark-spreadsheet', color: 'success' },
    { id: 'pdf', label: 'PDF (.pdf)', icon: 'bi-file-earmark-pdf', color: 'danger' },
    { id: 'md', label: 'Markdown (.md)', icon: 'bi-file-earmark-markdown', color: 'secondary' },
  ]

  AppModal.open({
    title: 'Exportar Reporte de Asistencia',
    size: 'md',
    hideSave: true,
    cancelText: 'Cancelar',
    body: `
      <div class="export-modal">
        <div class="mb-4">
          <label class="form-label fw-semibold">Seleccionar formato:</label>
          <div class="d-flex flex-column gap-2" id="formatOptions">
            ${formatos.map(f => `
              <button class="btn btn-outline-${f.color} d-flex align-items-center gap-3 p-3" data-fmt="${f.id}">
                <i class="bi ${f.icon} fs-4"></i>
                <span>${f.label}</span>
              </button>
            `).join('')}
          </div>
        </div>
        <div class="alert alert-info mb-0">
          <i class="bi bi-info-circle me-2"></i>
          El reporte incluirá: resumen por programa, estadísticas de asistencia y detalle por sesión.
        </div>
      </div>
    `,
  })

  document.querySelectorAll('#formatOptions button').forEach(btn => {
    btn.addEventListener('click', async () => {
      const fmt = btn.dataset.fmt
      AppModal.close()

      try {
        AppModal.showLoading('Generando reporte...')
        const { grupos, resumen } = await getReporteCompleto(params)

        if (fmt === 'xlsx') {
          await _exportXLSX(grupos, resumen, params)
        } else if (fmt === 'pdf') {
          await _exportPDF(grupos, resumen, params)
        } else if (fmt === 'md') {
          await _exportMD(grupos, resumen, params)
        }

        if (onExport) onExport(fmt)
      } catch (error) {
        AppModal.open({
          title: 'Error',
          body: `<div class="alert alert-danger">${error.message}</div>`,
          hideSave: true,
          cancelText: 'Cerrar',
        })
      }
    })
  })
}

async function _exportXLSX(grupos, resumen, params) {
  const rows = [['Fecha', 'Clase', 'Maestro', 'Tema', 'Presentes', 'Ausentes', 'Justificados', 'Total', '% Asistencia']]

  for (const grupo of grupos) {
    for (const sesion of grupo.sesiones) {
      const total = (sesion.totalPresentes || 0) + (sesion.totalAusentes || 0) + (sesion.totalJustificados || 0)
      const pct = total ? Math.round(((sesion.totalPresentes || 0) / total) * 100) : 0

      rows.push([
        grupo.fecha,
        sesion.claseNombre || '',
        sesion.maestroNombre || '',
        sesion.temaPrincipal || '',
        sesion.totalPresentes || 0,
        sesion.totalAusentes || 0,
        sesion.totalJustificados || 0,
        total,
        pct + '%',
      ])
    }
  }

  const csvContent = rows.map(r => r.join('\t')).join('\n')
  _downloadFile(csvContent, `reporte-asistencia-${_dateNow()}.xlsx`, 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')
}

async function _exportPDF(grupos, resumen, params) {
  const html = _generatePDFHTML(grupos, resumen)
  const printWindow = window.open('', '_blank')
  printWindow.document.write(html)
  printWindow.document.close()
  printWindow.print()
}

async function _exportMD(grupos, resumen, params) {
  let md = `# Reporte de Asistencia\n\n`
  md += `**Fecha de generación:** ${new Date().toLocaleDateString('es-AR')}\n\n`
  md += `## Resumen\n\n`
  md += `- Total Sesiones: ${resumen.totalSesiones}\n`
  md += `- Presentes: ${resumen.totalPresentes}\n`
  md += `- Ausentes: ${resumen.totalAusentes}\n`
  md += `- Justificados: ${resumen.totalJustificados}\n\n`
  md += `## Detalle por Fecha\n\n`

  for (const grupo of grupos) {
    md += `### ${grupo.fecha}\n\n`
    for (const sesion of grupo.sesiones) {
      const total = (sesion.totalPresentes || 0) + (sesion.totalAusentes || 0) + (sesion.totalJustificados || 0)
      const pct = total ? Math.round(((sesion.totalPresentes || 0) / total) * 100) : 0

      md += `- **${sesion.claseNombre}** (${sesion.maestroNombre})\n`
      md += `  - Tema: ${sesion.temaPrincipal || 'N/A'}\n`
      md += `  - Presentes: ${sesion.totalPresentes || 0} | Ausentes: ${sesion.totalAusentes || 0} | Justificados: ${sesion.totalJustificados || 0}\n`
      md += `  - **Asistencia: ${pct}%**\n\n`
    }
  }

  _downloadFile(md, `reporte-asistencia-${_dateNow()}.md`, 'text/markdown')
}

function _generatePDFHTML(grupos, resumen) {
  return `
    <!DOCTYPE html>
    <html>
    <head>
      <title>Reporte de Asistencia</title>
      <style>
        body { font-family: Arial, sans-serif; padding: 40px; }
        h1 { color: #333; }
        table { width: 100%; border-collapse: collapse; margin: 20px 0; }
        th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
        th { background: #f5f5f5; }
        .summary { background: #f9f9f9; padding: 15px; margin: 20px 0; }
      </style>
    </head>
    <body>
      <h1>Reporte de Asistencia</h1>
      <p>Generado: ${new Date().toLocaleDateString('es-AR')}</p>
      <div class="summary">
        <strong>Resumen:</strong> ${resumen.totalPresentes} presentes, ${resumen.totalAusentes} ausentes, ${resumen.totalJustificados} justificados
      </div>
      <table>
        <thead>
          <tr><th>Fecha</th><th>Clase</th><th>Maestro</th><th>Presentes</th><th>Ausentes</th><th>%</th></tr>
        </thead>
        <tbody>
          ${grupos.map(g => g.sesiones.map(s => {
            const total = (s.totalPresentes || 0) + (s.totalAusentes || 0) + (s.totalJustificados || 0)
            const pct = total ? Math.round(((s.totalPresentes || 0) / total) * 100) : 0
            return `<tr><td>${g.fecha}</td><td>${s.claseNombre || ''}</td><td>${s.maestroNombre || ''}</td><td>${s.totalPresentes || 0}</td><td>${s.totalAusentes || 0}</td><td>${pct}%</td></tr>`
          }).join('')).join('')}
        </tbody>
      </table>
    </body>
    </html>
  `
}

function _downloadFile(content, filename, mimeType) {
  const blob = new Blob([content], { type: mimeType })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = filename
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}

