export function openSeguimientoModal(observacion, _container, onSubmit) {
  const hoy = new Date().toISOString().split('T')[0]

  const body = `
    <div class="card border-0 bg-body-secondary p-3 mb-3 rounded">
      <div class="small d-flex flex-column gap-1">
        <div><strong>Título:</strong> ${escapeHTML(observacion.titulo)}</div>
        <div>
          <strong>Tipo:</strong>
          <span class="badge bg-${getPrioridadColor(observacion.tipo)} ms-1">
            <i class="bi ${getTipoIcon(observacion.tipo)}"></i> ${getTipoLabel(observacion.tipo)}
          </span>
        </div>
        <div>
          <strong>Prioridad:</strong>
          <span class="badge bg-${getPrioridadColor(observacion.prioridad)} ms-1">
            <i class="bi ${getPrioridadIcon(observacion.prioridad)}"></i>
            ${observacion.prioridad?.charAt(0).toUpperCase() + observacion.prioridad?.slice(1)}
          </span>
        </div>
        <div><strong>Descripción:</strong> ${escapeHTML(observacion.descripcion)}</div>
      </div>
    </div>

    <form novalidate>
      <div class="mb-3">
        <label class="form-label form-label-sm">Fecha de Seguimiento</label>
        <input type="date" class="form-control form-control-sm" id="seg-fecha" value="${hoy}">
      </div>
      <div class="mb-0">
        <label class="form-label form-label-sm">Observación de Seguimiento *</label>
        <textarea class="form-control form-control-sm" id="seg-observacion" rows="4" maxlength="500"
          placeholder="Describe el seguimiento realizado..."></textarea>
        <div class="form-text"><span id="seg-count">0</span>/500</div>
      </div>
    </form>
  `

  AppModal.open({
    title:    'Agregar Seguimiento',
    body,
    size:     'lg',
    saveText: 'Agregar Seguimiento',
    onSave:   async (bodyEl) => {
      const fecha      = bodyEl.querySelector('#seg-fecha')?.value
      const observacion= bodyEl.querySelector('#seg-observacion')?.value.trim()

      if (!observacion) { alert('La observación de seguimiento es obligatoria'); return false }

      if (onSubmit) await onSubmit(fecha, observacion)
    },
  })

  requestAnimationFrame(() => {
    const ta = document.getElementById('seg-observacion')
    const ct = document.getElementById('seg-count')
    if (ta && ct) {
      ta.addEventListener('input', () => {
        if (ta.value.length > 500) ta.value = ta.value.slice(0, 500)
        ct.textContent = ta.value.length
      })
    }
  })
}

import permisosMockData from '../../../assets/data/mocks/permisos.json'

// Simulación de delay
const delay = (ms = 300) => new Promise(resolve => setTimeout(resolve, ms))

// Persistencia en memoria local
let permisos = [...permisosMockData]

function normalizePermiso(p) {
  if (!p) return null
  return {
    id: p.id,
    maestro_id: p.maestro_id ?? '',
    maestro_nombre: p.maestro_nombre ?? '',
    maestro_email: p.maestro_email ?? '',
    puede_registrar_alumnos: p.puede_registrar_alumnos ?? false,
    puede_inscribir_clases: p.puede_inscribir_clases ?? false,
    permisos: Array.isArray(p.permisos) ? p.permisos : [],
    solicitudes: Array.isArray(p.solicitudes) ? p.solicitudes : [],
    concedido_por: p.concedido_por ?? null,
    concedido_por_nombre: p.concedido_por_nombre ?? null,
    creado_en: p.creado_en || null,
    actualizado_en: p.actualizado_en || null,
  }
}

export async function obtenerPermisos() {
  await delay()
  return permisos.map(normalizePermiso)
}

export async function obtenerPermisoPorMaestro(maestroId) {
  await delay()
  const permiso = permisos.find(p => p.maestro_id === maestroId)
  if (!permiso) {
    // Devolver permisos por defecto (fail-closed)
    return {
      id: null,
      maestro_id: maestroId,
      maestro_nombre: '',
      maestro_email: '',
      puede_registrar_alumnos: false,
      puede_inscribir_clases: false,
      permisos: [],
      solicitudes: [],
      concedido_por: null,
      concedido_por_nombre: null,
      creado_en: null,
      actualizado_en: null,
    }
  }
  return normalizePermiso(permiso)
}

export async function actualizarPermiso(maestroId, changes) {
  await delay()
  const index = permisos.findIndex(p => p.maestro_id === maestroId)
  const now = new Date().toISOString()

  if (index === -1) {
    // Upsert: insertar nuevo
    const nuevo = {
      id: Math.random().toString(36).substr(2, 9),
      maestro_id: maestroId,
      maestro_nombre: changes.maestro_nombre || '',
      maestro_email: changes.maestro_email || '',
      puede_registrar_alumnos: changes.puede_registrar_alumnos ?? false,
      puede_inscribir_clases: changes.puede_inscribir_clases ?? false,
      permisos: Array.isArray(changes.permisos) ? changes.permisos : [],
      solicitudes: Array.isArray(changes.solicitudes) ? changes.solicitudes : [],
      concedido_por: changes.concedido_por || null,
      concedido_por_nombre: changes.concedido_por_nombre || null,
      creado_en: now,
      actualizado_en: now,
    }
    permisos.push(nuevo)
    return normalizePermiso(nuevo)
  }

  // Upsert: actualizar existente
  permisos[index] = {
    ...permisos[index],
    puede_registrar_alumnos: changes.puede_registrar_alumnos ?? permisos[index].puede_registrar_alumnos,
    puede_inscribir_clases: changes.puede_inscribir_clases ?? permisos[index].puede_inscribir_clases,
    permisos: Array.isArray(changes.permisos) ? changes.permisos : permisos[index].permisos,
    solicitudes: Array.isArray(changes.solicitudes) ? changes.solicitudes : permisos[index].solicitudes,
    concedido_por: changes.concedido_por ?? permisos[index].concedido_por,
    concedido_por_nombre: changes.concedido_por_nombre ?? permisos[index].concedido_por_nombre,
    actualizado_en: now,
  }
  return normalizePermiso(permisos[index])
}

import { AppToast } from '../../../shared/components/AppToast.js'
import {
  obtenerPermisos,
  actualizarPermiso,
} from '../api/permisosApi.js'
import { config } from '../../../core/config/config.js'
import { useAuth } from '../../auth/hooks/useAuth.js'

const state = {
  permisos: [],
  cargando: false,
  togglingId: null,
  togglingField: null,
}

let currentContainer = null

function escapeHTML(str) {
  if (!str) return ''
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

export async function renderPermisosView(container) {
  currentContainer = container
  try {
    state.cargando = true
    renderLoading(container)

    const permisos = await obtenerPermisos()
    state.permisos = permisos
    state.cargando = false

    renderContent(container)
    attachEvents(container)
  } catch (error) {
    console.error(error)
    renderError(container, error.message)
  }
}

function renderLoading(container) {
  container.innerHTML = `
    <div class="d-flex justify-content-center align-items-center" style="min-height: 400px;">
      <div class="text-center">
        <div class="spinner-border text-primary mb-3" role="status">
          <span class="visually-hidden">Cargando...</span>
        </div>
        <p class="text-muted">Cargando permisos...</p>
      </div>
    </div>
  `
}

function renderError(container, mensaje) {
  container.innerHTML = `
    <div class="container mt-5">
      <div class="row justify-content-center">
        <div class="col-md-6">
          <div class="alert alert-danger" role="alert">
            <h4 class="alert-heading">
              <i class="bi bi-exclamation-triangle"></i> Error al cargar
            </h4>
            <p>${escapeHTML(mensaje)}</p>
            <hr>
            <button class="btn btn-primary" id="retryBtn">
              <i class="bi bi-arrow-clockwise"></i> Reintentar
            </button>
          </div>
        </div>
      </div>
    </div>
  `
  document.getElementById('retryBtn')?.addEventListener('click', () => renderPermisosView(container))
}

function renderContent(container) {
  const maestroActual = useAuth.getUser ? useAuth.getUser() : null
  const adminName = maestroActual?.nombre_completo || maestroActual?.email || 'Admin'

  container.innerHTML = `
    <div class="page-container">
      <!-- Page Header -->
      <div class="page-header">
        <div class="d-flex align-items-center gap-2">
          <span class="page-title"><i class="bi bi-shield-lock me-2 text-primary"></i>Permisos de Maestros</span>
          <span class="badge bg-secondary">${state.permisos.length}</span>
        </div>
      </div>

      ${!state.permisos.length ? renderEmpty() : `
      <!-- Table -->
      <div class="table-scroll-container">
        <table class="table table-compact table-hover mb-0" id="permisosTable">
          <thead>
            <tr>
              <th style="width: 20%;">Maestro</th>
              <th style="width: 20%;">Email</th>
              <th style="width: 18%;">Registrar Alumnos</th>
              <th style="width: 18%;">Inscribir Clases</th>
              <th style="width: 14%;">Concedido por</th>
              <th style="width: 10%;">Actualizado</th>
            </tr>
          </thead>
          <tbody id="permisosTBody">
            ${renderTableRows()}
          </tbody>
        </table>
      </div>
      `}

      <div class="mt-3 text-muted small">
        <i class="bi bi-info-circle"></i>
        Los cambios se guardan automáticamente al alternar un permiso.
        ${config.isDemoMode ? '<span class="badge bg-warning text-dark ms-1">Demo</span>' : ''}
      </div>
    </div>
  `
}

function renderTableRows() {
  return state.permisos.map(p => {
    const isToggling = state.togglingId === p.maestro_id
    const concedidoPor = p.concedido_por_nombre || p.concedido_por || '-'
    const actualizado = p.actualizado_en
      ? new Date(p.actualizado_en).toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })
      : '-'

    const solicitudes = p.solicitudes || []
    const reqAlumnos = !p.puede_registrar_alumnos && solicitudes.includes('alumnos:create')
    const reqClases = !p.puede_inscribir_clases && solicitudes.includes('clases:enroll')

    return `
      <tr data-maestro-id="${escapeHTML(p.maestro_id)}">
        <td>
          <div class="d-flex align-items-center gap-2">
            <div class="avatar-compact bg-primary text-white">${getInitials(p.maestro_nombre || p.maestro_id)}</div>
            <span class="text-truncate" style="max-width: 150px;" title="${escapeHTML(p.maestro_nombre)}">${escapeHTML(p.maestro_nombre || 'Sin nombre')}</span>
          </div>
        </td>
        <td class="text-truncate" style="max-width: 150px;" title="${escapeHTML(p.maestro_email)}">${escapeHTML(p.maestro_email || '-')}</td>
        <td>
          <div class="form-check form-switch mb-0 d-flex align-items-center gap-2">
            <input class="form-check-input permiso-toggle" type="checkbox"
              data-maestro-id="${escapeHTML(p.maestro_id)}"
              data-field="puede_registrar_alumnos"
              ${p.puede_registrar_alumnos ? 'checked' : ''}
              ${isToggling ? 'disabled' : ''}>
            <span class="small ${p.puede_registrar_alumnos ? 'text-success' : 'text-muted'}">
              ${p.puede_registrar_alumnos ? 'Sí' : 'No'}
            </span>
          </div>
          ${reqAlumnos ? `
            <div class="mt-1 d-flex align-items-center gap-1">
              <span class="badge bg-warning text-dark" style="font-size: 0.65rem; padding: 2px 4px;"><i class="bi bi-exclamation-triangle"></i> Solicitado</span>
              <button class="btn btn-sm btn-outline-primary aprobar-btn px-1 py-0" 
                data-maestro-id="${escapeHTML(p.maestro_id)}" 
                data-permiso="alumnos:create" 
                data-field="puede_registrar_alumnos" 
                style="font-size: 0.65rem; line-height: 1;">Aprobar</button>
            </div>
          ` : ''}
        </td>
        <td>
          <div class="form-check form-switch mb-0 d-flex align-items-center gap-2">
            <input class="form-check-input permiso-toggle" type="checkbox"
              data-maestro-id="${escapeHTML(p.maestro_id)}"
              data-field="puede_inscribir_clases"
              ${p.puede_inscribir_clases ? 'checked' : ''}
              ${isToggling ? 'disabled' : ''}>
            <span class="small ${p.puede_inscribir_clases ? 'text-success' : 'text-muted'}">
              ${p.puede_inscribir_clases ? 'Sí' : 'No'}
            </span>
          </div>
          ${reqClases ? `
            <div class="mt-1 d-flex align-items-center gap-1">
              <span class="badge bg-warning text-dark" style="font-size: 0.65rem; padding: 2px 4px;"><i class="bi bi-exclamation-triangle"></i> Solicitado</span>
              <button class="btn btn-sm btn-outline-primary aprobar-btn px-1 py-0" 
                data-maestro-id="${escapeHTML(p.maestro_id)}" 
                data-permiso="clases:enroll" 
                data-field="puede_inscribir_clases" 
                style="font-size: 0.65rem; line-height: 1;">Aprobar</button>
            </div>
          ` : ''}
        </td>
        <td class="small text-muted">${escapeHTML(concedidoPor)}</td>
        <td class="small text-muted">${actualizado}</td>
