 * Muestra el popup con opciones
 * @param {Array} options - Array de opciones
 * @param {Function} callback - Callback cuando se selecciona una opción
 * @param {Object} config - Configuración adicional { trigger, position }
 */
export function show(options, callback, config = {}) {
  initPopup();
  
  currentOptions = options || [];
  currentCallback = callback;
  triggerType = config.trigger || null;
  selectedIndex = -1;
  isVisible = true;
  
  render(options);
  
  // Posicionar con smart placement (evitar solapamiento con menús)
  if (config.position) {
    const pos = config.position;
    const viewportW = window.innerWidth;
    const viewportH = window.innerHeight;
    const popupW = 320;
    const popupH = 280;
    
    let left = pos.x;
    let top = pos.y + 20;
    
    // Si se sale por la derecha, mostrar a la izquierda del cursor
    if (left + popupW > viewportW - 20) {
      left = Math.max(10, pos.x - popupW - 10);
    }
    
    // Si se sale por abajo, mostrar arriba del cursor
    if (top + popupH > viewportH - 20) {
      top = Math.max(10, pos.y - popupH - 10);
    }
    
    popupEl.style.left = `${left}px`;
    popupEl.style.top = `${top}px`;
    initialPos = { x: left, y: top };
  }
  
  // Agregar listeners de drag
  popupEl.onmousedown = _startDrag;
  document.addEventListener('mousemove', _onDrag);
  document.addEventListener('mouseup', _endDrag);
  
  popupEl.style.display = 'block';
}

function _startDrag(e) {
  if (e.target.closest('.pm-ac-option')) return;
  isDragging = true;
  dragOffsetX = e.clientX - popupEl.offsetLeft;
  dragOffsetY = e.clientY - popupEl.offsetTop;
  popupEl.style.cursor = 'grabbing';
  popupEl.style.transition = 'none';
}

function _onDrag(e) {
  if (!isDragging) return;
  const x = e.clientX - dragOffsetX;
  const y = e.clientY - dragOffsetY;
  popupEl.style.left = `${Math.max(0, x)}px`;
  popupEl.style.top = `${Math.max(0, y)}px`;
}

function _endDrag() {
  if (!isDragging) return;
  isDragging = false;
  popupEl.style.cursor = '';
}

/**
 * Oculta el popup
 */
export function hide() {
  if (popupEl) {
    popupEl.style.display = 'none';
    isDragging = false;
    document.removeEventListener('mousemove', _onDrag);
    document.removeEventListener('mouseup', _endDrag);
  }
  currentOptions = [];
  currentCallback = null;
  selectedIndex = -1;
  isVisible = false;
  triggerType = null;
}

/**
 * Actualiza las opciones sin cerrar el popup
 * @param {Array} options 
 */
export function updateOptions(options) {
  currentOptions = options || [];
  selectedIndex = -1;
  render(options);
}

/**
 * Renderiza las opciones en el popup
 */
function render(options) {
  if (!popupEl) return;
  
  if (!options || options.length === 0) {
    popupEl.innerHTML = `
      <div class="pm-ac-empty">
        <span>No hay opciones disponibles</span>
      </div>
    `;
    return;
  }
  
  // Determinar el tipo de trigger para mostrar iconos apropiados
  const headerText = getHeaderText(triggerType);
  
  let html = `<div class="pm-ac-header">${headerText}</div>`;
  
  options.forEach((opt, idx) => {
    const label = opt.nombre || opt.name || opt.label || opt.description || '';
    const sublabel = opt.instrumento || opt.descripcion || opt.codigo || opt.type || '';
    const isSelected = idx === selectedIndex;
    const icon = getIcon(triggerType, opt);
    const badge = opt.is_historial ? '<span class="pm-ac-badge">Reciente</span>' : '';
    
    html += `
      <div class="pm-ac-option ${isSelected ? 'selected' : ''}" data-index="${idx}">
        <div class="pm-ac-icon">${icon}</div>
        <div class="pm-ac-text">
          <div class="pm-ac-label">${escapeHtml(label)}</div>
          ${sublabel ? `<div class="pm-ac-sublabel">${escapeHtml(sublabel)}</div>` : ''}
        </div>
        ${badge}
      </div>
    `;
  });
  
  popupEl.innerHTML = html;
  
  // Agregar event listeners
  popupEl.querySelectorAll('.pm-ac-option').forEach(el => {
    el.addEventListener('click', () => {
      const idx = parseInt(el.dataset.index, 10);
      selectOption(idx);
    });
  });
}

/**
 * Selecciona una opción por índice
 */
function selectOption(index) {
  if (index >= 0 && index < currentOptions.length) {
    const selected = currentOptions[index];
    
    if (currentCallback) {
      currentCallback(selected);
    }
    
    hide();
  }
}

/**
 * Maneja navegación con teclado
 * @param {KeyboardEvent} e
 */
export function handleKeyDown(e) {
  if (!isVisible || currentOptions.length === 0) return;
  
  switch (e.key) {
    case 'ArrowDown':
      e.preventDefault();
      selectedIndex = Math.min(selectedIndex + 1, currentOptions.length - 1);
      render(currentOptions);
      scrollToSelected();
      break;
      
    case 'ArrowUp':
      e.preventDefault();
      selectedIndex = Math.max(selectedIndex - 1, 0);
      render(currentOptions);
      scrollToSelected();
      break;
      
    case 'Enter':
      e.preventDefault();
      if (selectedIndex >= 0) {
        selectOption(selectedIndex);
      } else if (currentOptions.length > 0) {
        // Seleccionar primera si no hay selección
        selectOption(0);
      }
      break;
      
    case 'Escape':
      e.preventDefault();
      hide();
      break;
      
    case 'Tab':
      // Completar con primera opción
      if (currentOptions.length > 0 && selectedIndex === -1) {
        e.preventDefault();
        selectOption(0);
      }
      break;
  }
}

/**
 * Scroll hacia la opción seleccionada
 */
function scrollToSelected() {
  if (!popupEl || selectedIndex < 0) return;
  
  const selectedEl = popupEl.querySelector(`.pm-ac-option[data-index="${selectedIndex}"]`);
  if (selectedEl) {
    selectedEl.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  }
}

/**
 * Obtiene el texto del header según el trigger
 */
function getHeaderText(trigger) {
  switch (trigger) {
    case '#': return '👤 Alumnos';
    case '[': return '📚 Contenidos';
    case '(': return '💡 Sugerencias';
    case '{': return '📝 Tareas';
    case '$': return '🎯 Medidas';
    case '>': return '🎓 Objetivos';
    default: return 'Opciones';
  }
}

/**
 * Obtiene el icono según el tipo de opción
 */
function getIcon(trigger, opt) {
  // Para alumnos: "todos" usa emoji de grupo, el resto muestra inicial
  if (trigger === '#') {
    const nombre = opt.nombre || opt.name || '';
    if (opt.value === 'todos' || nombre.toLowerCase() === 'todos') return '👥';
    return nombre.charAt(0).toUpperCase();
  }
  
  // Para medidas técnicas
  if (trigger === '$') {
    return '🎯';
  }
  
  // Para niveles
  if (trigger === '>' && opt.level_number) {
    return opt.level_number;
  }
  
  // Para nodos
  if (trigger === '>' && opt.type) {
    return getNodeEmoji(opt.type);
  }
  
  // Default
  return '•';
}

/**
 * Obtiene emoji según tipo de nodo
 */
function getNodeEmoji(type) {
  const map = {
    'ESCALA': '🎼',
    'ARPEGIO': '🎹',
    'MANO_IZQ': '✋',
    'ARCO': '🎻',
    'SONIDO': '🔊',
    'AFINACION': '🎵',
    'TECNICA': '⚙️',
    'REPERTORIO': '📖'
  };
  return map[type] || '•';
}

/**
 * Escapa HTML para evitar XSS
 */
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

/**
 * Obtiene la posición del cursor en el documento
 */
export function getCursorPosition() {
  const sel = window.getSelection();
  if (!sel || sel.rangeCount === 0) return null;
  
  const range = sel.getRangeAt(0);
  const rect = range.getBoundingClientRect();
  
  return {
    x: rect.left,
    y: rect.top
  };
}

/**
 * Verifica si el popup está visible
 */
export function isOpen() {
  return isVisible;
}

/**
 * Obtiene el índice seleccionado
 */
export function getSelectedIndex() {
  return selectedIndex;
}

export default {
  show,
  hide,
  updateOptions,
  handleKeyDown,
  getCursorPosition,
  isOpen,
  getSelectedIndex
};

import { escHTML } from '../utils/portalUtils.js';
import { academicService } from '../../modules/academic-routes/services/academicService.js';

/**
 * Componente para evaluar un indicador individual dentro de un nodo.
 */
export function createNodeEvaluationCard(container, { indicator, sessionId, studentId, teacherId, onSave }) {
  const status = indicator.status || 'pending'; // 'approved', 'failed', 'in_process', 'pending'
  const token = academicService.getStatusToken(status);
  
  const card = document.createElement('div');
  card.className = `pm-node-eval-card pm-animate-fade-in status-${status}`;
  card.dataset.indicatorId = indicator.indicator_id;

  card.innerHTML = `
    <div class="pm-eval-card-header">
      <div class="pm-eval-node-info">
        <span class="pm-eval-node-name">${escHTML(indicator.node_name)}</span>
        <p class="pm-eval-indicator-desc">${escHTML(indicator.indicator_description || 'Evaluación de nodo')}</p>
      </div>
      ${indicator.is_critical ? '<span class="pm-badge-critical" title="Nodo Crítico"><i class="bi bi-exclamation-octagon"></i></span>' : ''}
    </div>

    <div class="pm-eval-status-selector">
      <button class="pm-eval-btn btn-approved ${status === 'approved' ? 'active' : ''}" data-status="approved">
        <i class="bi bi-check-lg"></i> Logrado
      </button>
      <button class="pm-eval-btn btn-in-process ${status === 'in_process' ? 'active' : ''}" data-status="in_process">
        <i class="bi bi-arrow-repeat"></i> En Proceso
      </button>
      <button class="pm-eval-btn btn-failed ${status === 'failed' ? 'active' : ''}" data-status="failed">
        <i class="bi bi-x-lg"></i> No Logrado
      </button>
    </div>

    <div class="pm-eval-feedback-area">
      <textarea placeholder="Feedback pedagógico (opcional)..." class="pm-eval-feedback-input">${escHTML(indicator.feedback || '')}</textarea>
    </div>

    <div class="pm-eval-card-footer">
      <span class="pm-eval-save-status"></span>
    </div>
  `;

  // Eventos
  const buttons = card.querySelectorAll('.pm-eval-btn');
  const feedbackInput = card.querySelector('.pm-eval-feedback-input');
  const statusMsg = card.querySelector('.pm-eval-save-status');

  let saveTimeout = null;

  const handleSave = async (newStatus = null) => {
    const currentStatus = newStatus || card.dataset.status || status;
    statusMsg.innerHTML = '<i class="pm-spinner-sm"></i> Guardando...';
    
    try {
      const payload = {
        student_id: studentId,
        indicator_id: indicator.indicator_id,
        session_id: sessionId,
        created_by: teacherId,
        status: currentStatus,
        feedback: feedbackInput.value,
        attempt_number: (indicator.attempt_number || 0) + 1
      };

      await academicService.saveIndicatorAttempt(payload);
      
      statusMsg.innerHTML = '<i class="bi bi-check-all"></i> Guardado localmente';
      card.className = `pm-node-eval-card status-${currentStatus}`;
      
      if (onSave) onSave(payload);
    } catch (err) {
      console.error('Error saving evaluation:', err);
      statusMsg.innerHTML = '<i class="bi bi-exclamation-circle"></i> Error al guardar';
    }
  };

  buttons.forEach(btn => {
    btn.onclick = () => {
      const newStatus = btn.dataset.status;
      buttons.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      card.dataset.status = newStatus;
      handleSave(newStatus);
    };
  });

  feedbackInput.oninput = () => {
    if (saveTimeout) clearTimeout(saveTimeout);
    saveTimeout = setTimeout(() => handleSave(), 1500);
  };

  container.appendChild(card);
}

/**
 * SessionSummaryPanel.js (v2 — grouped)
 *
 * Shows progress records for a saved session grouped by contenido_dsl.
 * Reads from `progresos` table, fetches alumno names from `alumnos`.
 *
 * Usage:
 *   const panel = createSessionSummaryPanel()
 *   panel.open({ sesionId, claseNombre, fecha, supabase })
 *   panel.close()
 *
 * Changes in v2:
 *   - Records grouped by normalized contenido_dsl (trim + lowercase)
 *   - Group shows combined alumnos, single observaciones/tarea
 *   - Estado 'mixto' when group has differing estados
 *   - Same public API as v1: open({ sesionId, claseNombre, fecha, supabase })
 */

// ── Estado badge display config ─────────────────────────────────────────────

const ESTADO_BADGES = {
  LOGRADO: { label: 'LOGRADO', cls: 'ssp-estado-logrado' },
  EN_PROGRESO: { label: 'EN_PROGRESO', cls: 'ssp-estado-en-progreso' },
  INICIADO: { label: 'INICIADO', cls: 'ssp-estado-iniciado' },
  MIXTO: { label: 'MIXTO', cls: 'ssp-estado-mixto' },
}

const ESTADO_CHIPS = {
  LOGRADO: 'ssp-chip-logrado',
  EN_PROGRESO: 'ssp-chip-en-progreso',
  INICIADO: 'ssp-chip-iniciado',
}

// For WhatsApp text display
const ESTADO_LABELS = {
  LOGRADO: 'LOGRADO',
  EN_PROGRESO: 'EN_PROGRESO',
  INICIADO: 'INICIADO',
  MIXTO: 'MIXTO',
}

// ── Helpers ─────────────────────────────────────────────────────────────────

/** Escapes HTML special chars to prevent XSS in innerHTML. */
function esc(str) {
  return String(str ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')
}

/**
 * Normalizes contenido_dsl for grouping: trim + lowercase.
 */
function normalizeKey(str) {
  return (str || '').trim().toLowerCase()
}

/**
 * Groups progress records by normalized contenido_dsl.
 *
 * @param {Array} records  — raw records from DB with alumno_nombre resolved
 * @returns {Array<{contenido, estado, alumnos, observaciones, tarea}>}
 */
function groupRecords(records) {
  const map = new Map()

  for (const rec of records) {
    const key = normalizeKey(rec.contenido_dsl)
    if (!key) continue // skip empty content

    if (!map.has(key)) {
      map.set(key, {
        contenido: rec.contenido_dsl,
        estado: rec.estado_cualitativo,
        alumnos: [
          {
            id: rec.alumno_id,
            nombre: rec.alumno_nombre || 'Alumno',
            estado: rec.estado_cualitativo,
          },
        ],
        observaciones: rec.observaciones || null,
        tarea: rec.tarea || null,
      })
    } else {
      const group = map.get(key)

      // Add alumno with individual estado
      group.alumnos.push({
        id: rec.alumno_id,
        nombre: rec.alumno_nombre || 'Alumno',
        estado: rec.estado_cualitativo,
      })

      // Detect mixto estado
      if (group.estado !== 'MIXTO' && group.estado !== rec.estado_cualitativo) {
        group.estado = 'MIXTO'
      }

      // Take first non-empty observaciones / tarea
      if (!group.observaciones && rec.observaciones) {
        group.observaciones = rec.observaciones
      }
      if (!group.tarea && rec.tarea) {
        group.tarea = rec.tarea
      }
    }
  }

  return Array.from(map.values())
}

// ── Factory ─────────────────────────────────────────────────────────────────

export function createSessionSummaryPanel() {
  let _panelEl = null
  let _groups = []
  let _supabase = null

  // ── WhatsApp text builder ───────────────────────────────────────────────

  function _buildWhatsAppText(claseNombre, fecha) {
    const fechaFmt = (() => {
      try {
        const [y, m, d] = fecha.split('-')
        return `${d}/${m}/${y}`
      } catch {
        return fecha
      }
    })()

    const lines = [`📚 Clase ${claseNombre} — ${fechaFmt}`]

    for (const group of _groups) {
      const estadoLabel = ESTADO_LABELS[group.estado] || group.estado
      const alumnoList =
        group.estado === 'MIXTO'
          ? group.alumnos
              .map((a) => {
                const indLabel = ESTADO_LABELS[a.estado] || a.estado
                return `${a.nombre} (${indLabel})`
              })
              .join(', ')
          : group.alumnos.map((a) => a.nombre).join(', ')

      lines.push('')
      lines.push(`🔹 ${group.contenido} — ${estadoLabel}`)
      lines.push(`   Alumnos: ${alumnoList}`)

      if (group.tarea) {
        lines.push(`   📝 Tarea: ${group.tarea}`)
      }
    }

    lines.push('', '🎯 El Sistema PC')
    return lines.join('\n')
  }

  // ── Render helpers ──────────────────────────────────────────────────────

  function _renderGroup(group, idx) {
    const badgeInfo = ESTADO_BADGES[group.estado] || ESTADO_BADGES.EN_PROGRESO
    const alumnosCount = group.alumnos.length
    const isMixed = group.estado === 'MIXTO'

    const alumnosHtml = group.alumnos
      .map((a) => {
        const chipCls = isMixed
          ? `ssp-alumno-chip ${ESTADO_CHIPS[a.estado] || ''}`
          : 'ssp-alumno-chip'
        return `<span class="${chipCls}">${esc(a.nombre)}</span>`
      })
      .join('')

    const obsHtml = group.observaciones
      ? `<div class="ssp-group-obs">${esc(group.observaciones)}</div>`
      : ''

    const tareaHtml = group.tarea
      ? `<div class="ssp-group-tarea">📝 Tarea: ${esc(group.tarea)}</div>`
      : ''

    return `
      <div class="ssp-group">
        <div class="ssp-group-header">
          <span class="ssp-group-contenido">${esc(group.contenido)}</span>
          <span class="ssp-group-count">${alumnosCount} alumno${alumnosCount !== 1 ? 's' : ''}</span>
          <span class="ssp-estado-badge ${badgeInfo.cls}">${badgeInfo.label}</span>
        </div>
        <div class="ssp-group-alumnos">${alumnosHtml}</div>
        ${obsHtml}
        ${tareaHtml}
      </div>
    `
  }

  function _render(claseNombre, fecha) {
    if (!_panelEl) return

    const hasGroups = _groups.length > 0

    _panelEl.innerHTML = `
      <div class="ssp-backdrop"></div>
      <div class="ssp-dialog" role="dialog" aria-modal="true" aria-label="Resumen pedagógico">
        <div class="ssp-header">
          <span class="ssp-icon">📊</span>
          <div>
            <strong>Resumen Pedagógico</strong>
            <div class="ssp-subtitle">${esc(claseNombre)} · ${esc(fecha)}</div>
          </div>
        </div>

        ${
          !hasGroups
            ? `
          <div class="ssp-empty">
            No hay registros de progreso para esta sesión.<br>
            Usá el botón 🎯 <strong>Analizar</strong> en el editor para generarlos.
          </div>
        `
            : `
          <div class="ssp-section-title">✅ Grupos de progreso (${_groups.length})</div>
          <div class="ssp-body">
            ${_groups.map((g) => _renderGroup(g)).join('')}
          </div>
        `
        }

        <div class="ssp-footer">
          <button class="pm-btn pm-btn-success ssp-btn-wa" id="ssp-whatsapp">
            <i class="bi bi-whatsapp"></i> Compartir WhatsApp
          </button>
          <button class="pm-btn pm-btn-outline ssp-btn-close" id="ssp-close">✕ Cerrar</button>
        </div>
      </div>
    `

    _injectStyles()

    // Wire WhatsApp
    _panelEl.querySelector('#ssp-whatsapp').onclick = () => {
      const text = _buildWhatsAppText(claseNombre, fecha)
      window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank')
    }

    // Wire close
    _panelEl.querySelector('#ssp-close').onclick = close
    _panelEl.querySelector('.ssp-backdrop').onclick = close
  }

  // ── Public API ──────────────────────────────────────────────────────────

  async function open({ sesionId, claseNombre, fecha, supabase }) {
    _supabase = supabase

    // Mount panel element
    if (!_panelEl) {
      _panelEl = document.createElement('div')
      _panelEl.className = 'ssp-wrapper'
      document.body.appendChild(_panelEl)
    }
    _panelEl.style.display = 'flex'

    // Show loading state
    _panelEl.innerHTML = `
      <div class="ssp-backdrop"></div>
      <div class="ssp-dialog">
        <div class="ssp-header">
          <span class="ssp-icon">📊</span>
          <div><strong>Resumen Pedagógico</strong><div class="ssp-subtitle">${esc(claseNombre)}</div></div>
        </div>
        <div class="ssp-loading">Cargando registros...</div>
      </div>
    `
    _injectStyles()
    _panelEl.querySelector('.ssp-backdrop').onclick = close

    // Fetch progresos
    const { data, error } = await supabase
      .from('progresos')
      .select('id, alumno_id, contenido_dsl, estado_cualitativo, observaciones, indicadores')
      .eq('sesion_clase_id', sesionId)
      .order('created_at', { ascending: true })

    if (error) {
      console.error('[SessionSummaryPanel] Error cargando progresos:', error)
      _groups = []
      _render(claseNombre, fecha)
      return
    }

    // Normalize records — extract tarea from indicadores jsonb
    const raw = data || []
    const records = raw.map((r) => ({
      id: r.id,
      alumno_id: r.alumno_id,
      contenido_dsl: r.contenido_dsl,
      estado_cualitativo: r.estado_cualitativo || 'EN_PROGRESO',
      observaciones: r.observaciones,
      tarea: r.indicadores?.tarea || null,
    }))

    // Fetch alumno names in batch
    const alumnoIds = [...new Set(records.map((r) => r.alumno_id).filter(Boolean))]
    if (alumnoIds.length > 0) {
      const { data: alumnos } = await supabase
        .from('alumnos')
        .select('id, nombre_completo')
        .in('id', alumnoIds)

      const nombreMap = new Map((alumnos || []).map((a) => [a.id, a.nombre_completo]))
      records.forEach((r) => {
        r.alumno_nombre = nombreMap.get(r.alumno_id) || 'Alumno'
      })
    }

    // Group records by normalized contenido_dsl
    _groups = groupRecords(records)
    _render(claseNombre, fecha)
  }

  function close() {
    if (_panelEl) {
      _panelEl.style.display = 'none'
      _panelEl.innerHTML = ''
    }
    _groups = []
    _supabase = null
  }

  return { open, close }
}

// ── Injected styles (grouped layout) ────────────────────────────────────────

function _injectStyles() {
  if (document.getElementById('ssp-styles')) return

  const style = document.createElement('style')
  style.id = 'ssp-styles'
  style.textContent = `
    /* ── Wrapper & backdrop ────────────────────────── */
    .ssp-wrapper {
      position: fixed;
      inset: 0;
      z-index: 9999;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 1rem;
    }
    .ssp-backdrop {
      position: absolute;
      inset: 0;
      background: rgba(0,0,0,0.55);
      backdrop-filter: blur(2px);
