      { id: 'e1', tipo: 'diagnostico', titulo: 'Nivel inicial', descripcion: 'Conoce posición 1', created_at: '2026-05-01T00:00:00Z' },
      { id: 'e2', tipo: 'logro',       titulo: 'Do mayor',      descripcion: null,                  created_at: '2026-05-10T00:00:00Z' },
