export function renderCalendarioMensual(container, opciones = {}) {
  const {
    sesiones = [],
    clases = [],
    maestroId = null,
    onFechaClick = null,
    esCoDocencia = false,
  } = opciones

  const today = new Date()
  let currentYear = today.getFullYear()
  let currentMonth = today.getMonth()

  function render() {
    container.innerHTML = _renderMonth(currentYear, currentMonth, sesiones, clases, onFechaClick)
    _attachMonthEvents(container, currentYear, currentMonth, render, renderPrev, onFechaClick)
  }

  function renderNext() {
    if (currentMonth === 11) {
      currentMonth = 0
      currentYear++
    } else {
      currentMonth++
    }
    render()
  }

  function renderPrev() {
    if (currentMonth === 0) {
      currentMonth = 11
      currentYear--
    } else {
      currentMonth--
    }
    render()
  }

  render()
}

function _renderMonth(year, month, sesiones, clases, onFechaClick) {
  const MESES = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre']
  const DIAS = ['Do', 'Lu', 'Ma', 'Mi', 'Ju', 'Vi', 'Sa']

  const primerDia = new Date(year, month, 1)
  const ultimoDia = new Date(year, month + 1, 0)
  const diasEnMes = ultimoDia.getDate()
  const primerDiaSemana = primerDia.getDay()

  const today = new Date()
  const todayStr = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`

  // Determine active date for roving tabindex: today if visible, else first day of month
  const firstDate = `${year}-${String(month + 1).padStart(2, '0')}-01`
  const lastDate = `${year}-${String(month + 1).padStart(2, '0')}-${String(diasEnMes).padStart(2, '0')}`
  const activeDate = (todayStr >= firstDate && todayStr <= lastDate) ? todayStr : null

  // Determine weekday number for each date (0=Do, 6=Sa) to group by week
  function getDayOfWeek(year, month, day) {
    return new Date(year, month, day).getDay()
  }

  let diasHTML = DIAS.map(d => `<div class="pm-cal-day-header">${d}</div>`).join('')

  for (let i = 0; i < primerDiaSemana; i++) {
    diasHTML += `<div class="pm-cal-day empty"></div>`
  }

  for (let d = 1; d <= diasEnMes; d++) {
    const fecha = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`
    const sesionesEnFecha = sesiones.filter(s => s.fecha === fecha)
    const sesionCount = sesionesEnFecha.length
    const esHoy = fecha === todayStr
    const tieneEmergente = sesionesEnFecha.some(s => s.tipo === 'emergente')
    const isActive = fecha === activeDate

    let dayClass = 'pm-cal-day'
    if (esHoy) dayClass += ' today'
    if (sesionCount > 0) dayClass += ' has-sessions'

    const dots = sesionCount > 0
      ? `<div class="pm-day-dots">
          ${sesionesEnFecha.map(s => `<span class="pm-dot ${s.tipo === 'emergente' ? 'emergente' : 'regular'}"></span>`).join('')}
        </div>`
      : ''

    const ariaLabel = `${d} de ${MESES[month]} ${year}`
    const ariaCurrent = esHoy ? ' aria-current="date"' : ''
    const tabIndex = isActive ? '0' : '-1'

    diasHTML += `
      <div class="${dayClass}" data-fecha="${fecha}" role="gridcell" tabindex="${tabIndex}" aria-label="${ariaLabel}" aria-selected="false"${ariaCurrent}>
        <span class="pm-day-number">${d}</span>
        ${dots}
      </div>
    `
  }

  return `
    <div class="pm-calendar-full">
      <div class="pm-cal-nav">
        <button class="pm-nav-btn" id="pm-cal-prev">‹</button>
        <h3 class="pm-cal-title">${MESES[month]} ${year}</h3>
        <button class="pm-nav-btn" id="pm-cal-next">›</button>
      </div>

      <div class="pm-cal-grid" role="grid" aria-label="Calendario ${MESES[month]} ${year}">
        ${diasHTML}
      </div>

      <div class="pm-cal-legend">
        <span><span class="pm-dot regular"></span> Regular</span>
        <span><span class="pm-dot emergente"></span> Emergente</span>
      </div>
    </div>
  `
}

function _attachMonthEvents(container, year, month, onNext, onPrev, onFechaClick) {
  container.querySelector('#pm-cal-prev')?.addEventListener('click', onPrev)
  container.querySelector('#pm-cal-next')?.addEventListener('click', onNext)

  container.querySelectorAll('.pm-cal-day:not(.empty)').forEach(day => {
    day.addEventListener('click', () => {
      // Update aria-selected on click
      container.querySelectorAll('.pm-cal-day[data-fecha]').forEach(c => c.setAttribute('aria-selected', 'false'))
      day.setAttribute('aria-selected', 'true')
      if (onFechaClick) {
        onFechaClick(day.dataset.fecha)
      }
    })
  })

  // Keyboard navigation: WAI-ARIA grid pattern with roving tabindex
  const grid = container.querySelector('.pm-cal-grid')
  if (!grid) return

  grid.addEventListener('keydown', function onGridKeydown(e) {
    const days = [...grid.querySelectorAll('.pm-cal-day[data-fecha]')]
    if (days.length === 0) return

    const currentFocused = grid.querySelector('[tabindex="0"]')
    const currentIndex = currentFocused ? days.indexOf(currentFocused) : -1

    const clampedIndex = (idx) => Math.max(0, Math.min(days.length - 1, idx))
    const moveFocus = (idx) => {
      if (idx < 0 || idx >= days.length) return
      days.forEach(d => d.setAttribute('tabindex', '-1'))
      days[idx].setAttribute('tabindex', '0')
      days[idx].focus()
    }

    switch (e.key) {
      case 'ArrowLeft':
        e.preventDefault()
        if (currentIndex > 0) moveFocus(currentIndex - 1)
        break
      case 'ArrowRight':
        e.preventDefault()
        if (currentIndex < days.length - 1) moveFocus(currentIndex + 1)
        break
      case 'ArrowUp':
        e.preventDefault()
        moveFocus(clampedIndex(currentIndex - 7))
        break
      case 'ArrowDown':
        e.preventDefault()
        moveFocus(clampedIndex(currentIndex + 7))
        break
      case 'Home':
        e.preventDefault()
        moveFocus(Math.floor(Math.max(currentIndex, 0) / 7) * 7)
        break
      case 'End':
        e.preventDefault()
        moveFocus(Math.min(days.length - 1, Math.floor(Math.max(currentIndex, 0) / 7) * 7 + 6))
        break
      case 'PageUp':
        e.preventDefault()
        if (typeof onPrev === 'function') {
          onPrev()
          requestAnimationFrame(() => {
            const newGrid = container.querySelector('.pm-cal-grid')
            if (newGrid) {
              const firstDay = newGrid.querySelector('.pm-cal-day[data-fecha]')
              if (firstDay) {
                newGrid.querySelectorAll('.pm-cal-day[data-fecha]').forEach(d => d.setAttribute('tabindex', '-1'))
                firstDay.setAttribute('tabindex', '0')
                firstDay.focus()
              }
            }
          })
        }
        break
      case 'PageDown':
        e.preventDefault()
        if (typeof onNext === 'function') {
          onNext()
          requestAnimationFrame(() => {
            const newGrid = container.querySelector('.pm-cal-grid')
            if (newGrid) {
              const firstDay = newGrid.querySelector('.pm-cal-day[data-fecha]')
              if (firstDay) {
                newGrid.querySelectorAll('.pm-cal-day[data-fecha]').forEach(d => d.setAttribute('tabindex', '-1'))
                firstDay.setAttribute('tabindex', '0')
                firstDay.focus()
              }
            }
          })
        }
        break
      case 'Enter':
      case ' ':
        e.preventDefault()
        if (currentFocused) {
          currentFocused.click()
        }
        break
    }
  })
}

function _escHTML(str) {
  return String(str ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
}

import { highlightDSL } from '../utils/dslParser.js';
import autocompletePopup, { getCursorPosition, isOpen, handleKeyDown as acHandleKeyDown } from './AutocompletePopup.js';
import * as catalogService from '../services/catalogService.js';

const DSL_PLACEHOLDER_HTML = `
  <div class="pm-dsl-placeholder-title">✨ Escribí lo que pasó en clase con tus propias palabras</div>
  <div class="pm-dsl-placeholder-example" style="font-style:italic;color:var(--pm-text-muted,#888);font-size:0.85rem;margin-bottom:6px">
    "Yereni y Santa avanzaron muy bien hoy con el cambio de posición. Santiago necesita practicar más el arco."
  </div>
  <div class="pm-dsl-placeholder-guide">
    Presioná <strong>✨ Analizar con IA</strong> y Groq va a extraer los avances automáticamente. · O usá los tokens del toolbar si preferís escribir directo: # alumno · [] contenido · {} tarea
  </div>
`;

/**
 * Componente: DslEditor
 * Editor con resaltado de sintaxis en tiempo real para el lenguaje DSL Pedagógico.
 * 
 * Soporta inserción inteligente: cuando el toolbar inserta un token ([], (), {}),
 * el cursor se posiciona DENTRO de los brackets y se auto-dispara el autocompletado
 * correspondiente (contenidos, sugerencias, tareas, etc.).
 * 
 * @param {HTMLElement} container 
 * @param {{ initialContent: string, onChange: Function, onAlumnosNeeded: Function }} options
 */
export function createDslEditor(container, { initialContent = '', onChange, onAlumnosNeeded }) {
  let _value = initialContent;
  let _isUpdating = false;
  let _context = {}; // Para pasar contexto (claseId, nivelId, etc.)

  container.innerHTML = `
    <div class="pm-dsl-editor-container">
      <div 
        id="pm-dsl-editable" 
        class="pm-dsl-editable" 
        contenteditable="true" 
        spellcheck="false"
      ></div>
      <div class="pm-dsl-placeholder" id="pm-dsl-placeholder">${DSL_PLACEHOLDER_HTML}</div>
    </div>
  `;

  const editor = container.querySelector('#pm-dsl-editable');
  const placeholder = container.querySelector('#pm-dsl-placeholder');

  // Tooltip element
  const tooltip = document.createElement('div');
  tooltip.className = 'dsl-tooltip';
  container.appendChild(tooltip);

  function _updateValue() {
    _value = editor.innerText;
    placeholder.style.display = _value.trim() === '' ? 'block' : 'none';
    if (onChange) onChange(_value);
  }

  // Tooltip hover
  editor.addEventListener('mouseover', (e) => {
    const token = e.target.closest('.dsl-objetivo');
    if (token) {
      const obj = token.dataset.objetivo;
      tooltip.textContent = `Objetivo: ${obj}`;
      tooltip.style.display = 'block';
      const rect = token.getBoundingClientRect();
      const containerRect = container.getBoundingClientRect();
      tooltip.style.left = `${rect.left - containerRect.left}px`;
      tooltip.style.top = `${rect.top - containerRect.top - 25}px`;
    }
  });

  editor.addEventListener('mouseout', () => {
    tooltip.style.display = 'none';
  });

  function _applyHighlight() {
    if (_isUpdating) return;
    _isUpdating = true;

    try {
      const selection = window.getSelection();
      if (!selection || selection.rangeCount === 0) {
        _isUpdating = false;
        return;
      }

      const range = selection.getRangeAt(0);
      const offset = _getCaretOffset(editor, range);

      _value = editor.innerText;
      editor.innerHTML = highlightDSL(_value);

      _setCaretOffset(editor, offset);
    } catch (err) {
      console.warn('[DSL] Error en highlight:', err);
      _value = editor.innerText;
    }
    _isUpdating = false;
  }

  // === AUTOCOMPLETADO INTELIGENTE ===
  
  /**
   * Detecta si hay un trigger de autocompletado en la posición del cursor
   * @returns {{ trigger: string, query: string }|null}
   */
  function _detectTrigger() {
    const sel = window.getSelection();
    if (!sel || sel.rangeCount === 0) return null;
    
    const range = sel.getRangeAt(0);
    const preCaretRange = document.createRange();
    preCaretRange.selectNodeContents(editor);
    preCaretRange.setEnd(range.endContainer, range.endOffset);
    const textBeforeCursor = preCaretRange.toString();
    
    // Detectar último trigger (#, [, (, {, $, >)
    const triggerMatch = textBeforeCursor.match(/([#\[\(\{\$>])\s*([^\[\(\{\$]*)$/);
    
    if (triggerMatch) {
      return {
        trigger: triggerMatch[1],
        query: triggerMatch[2] || ''
      };
    }
    
    return null;
  }

  // Guardamos el offset del caret ANTES de que el popup robe el foco.
  // Al hacer click en el popup el editor pierde el foco → getSelection() queda vacío.
  let _savedCaretOffset = null;

  editor.addEventListener('mousedown', () => {
    // Al interactuar con el editor actualizamos la posición guardada
    _savedCaretOffset = null;
  });

  /**
   * Guarda la posición actual del caret para recuperarla si el editor pierde el foco.
   */
  function _saveCaretOffset() {
    const sel = window.getSelection();
    if (!sel || sel.rangeCount === 0) return;
    const range = sel.getRangeAt(0);
    _savedCaretOffset = _getCaretOffset(editor, range);
  }

  /**
   * Restaura el foco y la posición del caret guardada.
   */
  function _restoreCaret() {
    editor.focus();
    if (_savedCaretOffset !== null) {
      _setCaretOffset(editor, _savedCaretOffset);
    }
  }

  /**
   * Muestra el popup de autocompletado.
   * @param {string|null} forceTrigger — Si se pasa, usa este trigger en vez de detectar
   */
  let _autocompleteDebounce = null;
  async function _showAutocomplete(forceTrigger = null) {
    let trigger, query;

    if (forceTrigger) {
      trigger = forceTrigger;
      query = '';
    } else {
      const triggerData = _detectTrigger();
      if (!triggerData) {
        autocompletePopup.hide();
        return;
      }
      trigger = triggerData.trigger;
      query = triggerData.query;
    }
    
    try {
      const options = await catalogService.getOptionsForTrigger(trigger, query, _context);
      
      if (options.length > 0) {
        const pos = getCursorPosition();
        if (pos) {
          // Guardar posición del caret ANTES de mostrar el popup
          _saveCaretOffset();
          autocompletePopup.show(options, (selected) => {
            _insertAutocomplete(selected, trigger, query);
          }, { trigger, position: pos });
        }
      } else {
        autocompletePopup.hide();
      }
    } catch (err) {
      console.warn('[DSL] Error en autocompletado:', err);
    }
  }

/**
   * Inserta la opción seleccionada del autocompletado
   */
  function _insertAutocomplete(selected, trigger, query) {
    // Extraer texto plano del label (puede contener HTML del popup)
    const labelHtml = selected.nombre || selected.name || selected.label || selected.descripcion || ''
    const label = _stripHtml(labelHtml)
    
    // Construir el texto según el trigger
    let finalText = '';
    
    switch (trigger) {
      case '#':
        finalText = label;
        break;
      case '[':
        finalText = label + ']';
        break;
      case '(':
        finalText = label + ')';
        break;
      case '{':
        finalText = label + '}';
        break;
      case '$':
        finalText = selected.codigo || label;
        break;
      case '>':
        if (selected.level_number) {
          finalText = `NIVEL-${selected.level_number}`;
        } else if (selected.type) {
          finalText = `NODO:${selected.type}`;
        } else {
          finalText = label;
        }
        break;
    }
    
    // El editor puede haber perdido el foco al hacer click en el popup.
    // Restauramos el caret guardado antes de insertar.
    _restoreCaret();

    const sel = window.getSelection();
    if (!sel || sel.rangeCount === 0) {
      console.warn('[DSL] Sin selección activa al insertar autocomplete');
      return;
    }

    // Si hay query parcial escrito después del trigger, borrarlo primero
    if (query.length > 0) {
      const range = sel.getRangeAt(0);
      const preCaretRange = document.createRange();
      preCaretRange.selectNodeContents(editor);
      preCaretRange.setEnd(range.endContainer, range.endOffset);
      const textBeforeCursor = preCaretRange.toString();
      const queryStart = textBeforeCursor.length - query.length;
      
      try {
        const deleteRange = document.createRange();
        _setRangeFromOffset(editor, deleteRange, queryStart, textBeforeCursor.length);
        deleteRange.deleteContents();
      } catch (e) {
        console.warn('[DSL] Error limpiando query parcial:', e);
      }
    }
      
    // Insertar el texto final
    _insertRawText(finalText + ' ');
    
    // Registrar la selección para fuzzy search
    catalogService.recordSelection(trigger, label);
  }

  /**
   * Helper: establece un Range basado en offsets de texto plano
   */
  function _setRangeFromOffset(element, range, startOffset, endOffset) {
    let charCount = 0;
    const nodeStack = [element];
    let startSet = false;

    while (nodeStack.length > 0) {
      const node = nodeStack.pop();
      if (node.nodeType === 3) {
        const nextCount = charCount + node.length;
        if (!startSet && startOffset <= nextCount) {
          range.setStart(node, startOffset - charCount);
          startSet = true;
        }
        if (startSet && endOffset <= nextCount) {
          range.setEnd(node, endOffset - charCount);
          return;
        }
        charCount = nextCount;
      } else {
        for (let i = node.childNodes.length - 1; i >= 0; i--) {
          nodeStack.push(node.childNodes[i]);
        }
      }
    }
  }

  function _stripHtml(str) {
    if (!str) return ''
    const d = document.createElement('div')
    d.innerHTML = str
    return d.textContent || d.innerText || ''
  }

  /**
   * Inserta texto plano en la posición actual del cursor (sin mover ni re-posicionar).
   */
  function _insertRawText(text) {
    const clean = _stripHtml(text)
    const sel = window.getSelection();
    if (!sel || sel.rangeCount === 0) return;
    const range = sel.getRangeAt(0);
    range.deleteContents();
    const textNode = document.createTextNode(clean);
    range.insertNode(textNode);
    range.setStartAfter(textNode);
    range.collapse(true);
    sel.removeAllRanges();
    sel.addRange(range);
    _updateValue();
    _applyHighlight();
  }

  // === FIN AUTOCOMPLETADO ===

  // Helpers para el cursor (Caret) en contenteditable
  function _getCaretOffset(element, range) {
    const preCaretRange = range.cloneRange();
    preCaretRange.selectNodeContents(element);
    preCaretRange.setEnd(range.endContainer, range.endOffset);
    return preCaretRange.toString().length;
  }

  function _setCaretOffset(element, offset) {
    const range = document.createRange();
    const sel = window.getSelection();
    if (!sel) return;
    
    let charCount = 0;
    let nodeStack = [element];
    let node, found = false;

    while (nodeStack.length > 0 && !found) {
      node = nodeStack.pop();
      if (node.nodeType === 3) {
        const nextCharCount = charCount + node.length;
        if (offset <= nextCharCount) {
          range.setStart(node, offset - charCount);
          range.collapse(true);
          found = true;
        }
        charCount = nextCharCount;
      } else {
        let i = node.childNodes.length;
        while (i--) {
          nodeStack.push(node.childNodes[i]);
        }
      }
    }

    sel.removeAllRanges();
    sel.addRange(range);
  }

  let _debounceTimer = null;
  editor.oninput = () => {
    _updateValue();
    
    // Highlight con debounce
    clearTimeout(_debounceTimer);
    _debounceTimer = setTimeout(_applyHighlight, 150);
    
    // Autocompletado con debounce
    clearTimeout(_autocompleteDebounce);
    _autocompleteDebounce = setTimeout(() => _showAutocomplete(), 300);
  };
  
  // Keyboard navigation para el popup de autocompletado
  editor.addEventListener('keydown', (e) => {
    if (isOpen()) {
      acHandleKeyDown(e);
    }
  });

  // BLOQUEAR PASTE DE IMÁGENES - evita error "this model does not support image input"
  editor.addEventListener('paste', (e) => {
    const items = e.clipboardData?.items;
    if (!items) return;
    
    const hasImage = Array.from(items).some(item => 
      item.type && item.type.startsWith('image/')
    );
    
    if (hasImage) {
      e.preventDefault();
      const msg = document.createElement('div');
      msg.className = 'pm-toast-image-blocked';
      msg.textContent = '🚫 No puedes pegar imágenes. Usa 🎤 para grabar audio o describe el contenido.';
      msg.style.cssText = 'position:fixed; bottom:20px; left:50%; transform:translateX(-50%); background:#dc3545; color:white; padding:12px 20px; border-radius:8px; z-index:10000; font-size:14px;';
      document.body.appendChild(msg);
      setTimeout(() => msg.remove(), 4000);
    }
  });

  /**
   * API Pública: Inserta texto en la posición actual del cursor.
   * 
   * @param {string} text — El texto a insertar (ej: "[]", "()", "{}", "#", "$", ">")
   * @param {number} cursorOffset — Dónde posicionar el cursor dentro del texto insertado.
   *   0 = después del texto, 1 = un caracter desde el inicio (dentro de brackets)
   * @param {string|null} triggerAC — Si se pasa, auto-dispara autocomplete para este trigger
   */
function insertText(text, cursorOffset = 0, triggerAC = null) {
    editor.focus();
    const sel = window.getSelection();
    if (!sel || sel.rangeCount === 0) return;

    const range = sel.getRangeAt(0);
    range.deleteContents();
    const cleanText = _stripHtml(text)
    const textNode = document.createTextNode(cleanText)
    range.insertNode(textNode)

    // Posicionar cursor: cursorOffset = 1 pone el cursor DENTRO de [] () {}
    if (cursorOffset > 0 && cursorOffset < text.length) {
      const newRange = document.createRange();
      newRange.setStart(textNode, cursorOffset);
      newRange.collapse(true);
      sel.removeAllRanges();
      sel.addRange(newRange);
    } else {
      range.setStartAfter(textNode);
      range.collapse(true);
      sel.removeAllRanges();
      sel.addRange(range);
    }

    _updateValue();
    _applyHighlight();

    // Auto-disparar autocomplete si el toolbar lo solicita
    if (triggerAC) {
      // Pequeño delay para que el cursor se estabilice después del highlight
      setTimeout(() => _showAutocomplete(triggerAC), 50);
    }
  }

  // Inicializar
  if (initialContent) {
    editor.innerText = initialContent;
    _updateValue();
    _applyHighlight();
  }

  return {
    insertText,
    getValue: () => _value,
    setValue: (newContent) => {
      editor.innerText = newContent
      _updateValue()
      _applyHighlight()
    },
    setContext: (context) => { _context = context; }
  };
}

import { enrichToDSL, transcribeAndStructure, structureTextToDSL } from '../services/groqService.js';
import { SNIPPETS, searchSnippets, expandSnippet } from '../services/snippetBank.js';
import { createStructureModal } from './structureModal.js';
import { createToolbarHelpModal } from './toolbarHelpModal.js';

/**
 * Componente: DslToolbar
 * Barra de herramientas inteligente para insertar tokens DSL en el editor.
 * 
 * Tokens:
 *   #  → Etiquetar alumno individual
 *   [] → Contenido de clase
 *   () → Sugerencia pedagógica
 *   {} → Tarea/Asignación
 *   $  → Medida técnica
 *   >  → Objetivo curricular
 * 
 * @param {HTMLElement} container
 * @param {{ onInsert: Function, onLoading: Function, onIaProposal: Function, getEditorContent: Function, aiService?: object, onImproveClick?: Function, onStructureClick?: Function }} options
 */
export function createDslToolbar(container, { onInsert, onLoading, onIaProposal, getEditorContent, aiService, onImproveClick, onStructureClick, onAnalyzeClick }) {

  // Contexto mutable: se actualiza desde fuera vía setContext()
  let _ctx = { presentes: [], indicadorActivo: null, indicadoresDisponibles: [] }

  // Definición centralizada de herramientas DSL
  const DSL_TOOLS = [
    { token: 'alumno',    label: '#',    title: 'Etiquetar alumno',     text: '#',   offset: 1, icon: '👤', triggerAC: '#' },
    { token: 'contenido', label: '[ ]',  title: 'Contenido de clase',   text: '[]',  offset: 1, icon: '📚', triggerAC: '[' },
    { token: 'sugerencia',label: '( )',  title: 'Sugerencia pedagógica',text: '()',  offset: 1, icon: '💡', triggerAC: '(' },
    { token: 'tarea',     label: '{ }',  title: 'Tarea / Asignación',   text: '{}',  offset: 1, icon: '📝', triggerAC: '{' },
    { token: 'medida',    label: '$',    title: 'Medida técnica',       text: '$',   offset: 1, icon: '🎯', triggerAC: '$' },
    { token: 'objetivo',  label: '>',    title: 'Objetivo curricular',  text: '>',   offset: 1, icon: '🎓', triggerAC: '>' },
  ];

  container.innerHTML = `
    <div class="pm-dsl-toolbar">
      ${DSL_TOOLS.map(t => `
        <button class="pm-dsl-tool-btn" data-token="${t.token}" title="${t.title}">
          <span class="pm-dsl-tool-symbol">${t.label}</span>
        </button>
      `).join('')}
      <div class="pm-dsl-divider"></div>
      <button class="pm-dsl-tool-btn snippet-btn" id="btn-snippets" title="Snippets / Banco">
        <span class="snippet-icon">/</span>
      </button>
      <div class="pm-dsl-divider"></div>
      <button class="pm-dsl-tool-btn ai" id="btn-generar-informe" title="Generar informe para padres/tutores">📋</button>
      <button class="pm-dsl-tool-btn ai" id="btn-ia-magic" title="Estructurar con IA">🚀</button>
      <button class="pm-dsl-tool-btn ai ai-primary" id="btn-analizar-progreso" title="La IA lee tu texto y extrae los avances de cada alumno automáticamente">✨ Analizar con IA</button>
      <div class="pm-dsl-divider"></div>
      <button class="pm-dsl-tool-btn" id="btn-help" title="Ayuda">❓</button>

    </div>
    <div id="pm-snippet-popup" class="pm-snippet-popup" style="display:none;"></div>
  `;

  // Estilos de la toolbar
  if (!document.getElementById('pm-dsl-toolbar-styles')) {
    const style = document.createElement('style');
    style.id = 'pm-dsl-toolbar-styles';
    style.textContent = `
      .pm-dsl-toolbar {
        display: flex;
        gap: 0.25rem;
        padding: 0.5rem;
        background: var(--pm-surface);
        border: 1px solid var(--pm-border);
        border-radius: var(--pm-radius-sm) var(--pm-radius-sm) 0 0;
        overflow-x: auto;
        white-space: nowrap;
        scrollbar-width: none;
        align-items: center;
      }
      .pm-dsl-toolbar::-webkit-scrollbar { display: none; }
      
      .pm-dsl-tool-btn {
        min-width: 32px;
        height: 32px;
        padding: 0 0.5rem;
        border: 1px solid var(--pm-border);
        background: var(--pm-surface);
        color: var(--pm-text);
        border-radius: 6px;
        font-weight: 700;
        cursor: pointer;
        font-size: 0.85rem;
        display: flex;
        align-items: center;
        justify-content: center;
        transition: all 0.15s ease;
        position: relative;
      }
      .pm-dsl-tool-btn:hover {
        background: var(--pm-surface-2);
        border-color: var(--pm-primary);
        color: var(--pm-primary);
        transform: translateY(-1px);
      }
      .pm-dsl-tool-btn:active { 
        background: var(--pm-border); 
        transform: translateY(1px); 
      }
      .pm-dsl-tool-btn.ai {
        border-color: var(--pm-primary);
        color: var(--pm-primary);
        background: rgba(99, 102, 241, 0.05);
      }
      .pm-dsl-tool-btn.ai-primary {
        padding: 0 0.85rem;
        font-weight: 700;
        font-size: 0.82rem;
        background: var(--pm-primary, #6366f1);
        color: #fff;
        border-color: var(--pm-primary, #6366f1);
        gap: 4px;
        min-width: unset;
        width: auto;
        letter-spacing: 0.01em;
      }
      .pm-dsl-tool-btn.ai-primary:hover {
        background: var(--pm-primary-dark, #4f46e5);
        border-color: var(--pm-primary-dark, #4f46e5);
        color: #fff;
        transform: translateY(-1px);
      }
      .pm-dsl-tool-btn.ai-primary:disabled {
        opacity: 0.7;
        cursor: not-allowed;
        transform: none;
      }

      
      .pm-dsl-tool-symbol {
        font-family: ui-monospace, SFMono-Regular, monospace;
        font-weight: 800;
        letter-spacing: -0.5px;
      }
      
      .pm-dsl-divider {
        width: 1px;
        background: var(--pm-border);
        margin: 4px 2px;
        height: 20px;
      }


    `;
    document.head.appendChild(style);
  }

  // --- Lógica de inserción inteligente ---
  // El mapa de herramientas nos permite buscar por token rápidamente
  const toolMap = new Map(DSL_TOOLS.map(t => [t.token, t]));

  container.querySelectorAll('.pm-dsl-tool-btn[data-token]').forEach(btn => {
    btn.onclick = () => {
      const tool = toolMap.get(btn.dataset.token);
      if (!tool) return;

      // Micro-animación de feedback al presionar
      btn.style.transform = 'scale(0.9)';
      setTimeout(() => { btn.style.transform = ''; }, 100);

      // Insertar el texto con cursorOffset para que el cursor quede DENTRO
      // de los brackets/paréntesis. El triggerAC indica qué autocomplete disparar.
      onInsert(tool.text, tool.offset, tool.triggerAC);
    };
  });



// --- Lógica de Generar Informe ---
  async function handleGenerateReport() {
    const rawText = getEditorContent ? getEditorContent() : ''
    if (!rawText.trim()) return
    if (onImproveClick) {
      try {
        onImproveClick(rawText)
      } catch (err) {
        alert('Error al generar informe: ' + err.message)
      }
    }
  }

  // --- Lógica de Estructurar con IA ---
  async function handleStructure() {
    const rawText = getEditorContent ? getEditorContent() : ''
    if (!rawText.trim()) return
    if (onStructureClick) {
      try {
        onStructureClick(rawText)
      } catch (err) {
        alert('Error al estructurar con IA: ' + err.message)
      }
    }
  }

  container.querySelector('#btn-generar-informe').onclick = handleGenerateReport;
  container.querySelector('#btn-ia-magic').onclick = handleStructure;

  const analyzeBtn = container.querySelector('#btn-analizar-progreso')
  if (analyzeBtn) {
    analyzeBtn.onclick = async () => {
      const rawText = getEditorContent ? getEditorContent() : ''
      if (!rawText.trim()) return
      if (onAnalyzeClick) {
        analyzeBtn.disabled = true
        analyzeBtn.textContent = '⏳ Analizando...'
        try {
          await onAnalyzeClick(rawText)
        } catch (err) {
          // error handled by caller
        } finally {
          analyzeBtn.disabled = false
          analyzeBtn.textContent = '✨ Analizar con IA'
        }
      }
    }
  }


  // === Snippets Popup ===
  const snippetPopup = container.querySelector('#pm-snippet-popup')
  let snippetSearch = ''

  function showSnippetPopup(search = '') {
    const results = searchSnippets(search)
    if (results.length === 0) {
      snippetPopup.style.display = 'none'
      return
    }
    
    snippetPopup.innerHTML = results.map(s => `
      <div class="pm-snippet-item" data-trigger="${s.trigger}">
        <span class="pm-snippet-icon">${s.icon}</span>
        <span class="pm-snippet-label">/${s.trigger}</span>
        <span class="pm-snippet-preview">${s.label}</span>
      </div>
    `).join('')
    
    // Auto-posicionamiento inteligente
    const rect = container.getBoundingClientRect()
    const spaceAbove = rect.top
    const threshold = 220
    
    snippetPopup.style.position = 'fixed'
    snippetPopup.style.left = `${rect.left}px`
    snippetPopup.style.width = `${rect.width}px`
    
    if (spaceAbove > threshold) {
      snippetPopup.style.top = 'auto'
      snippetPopup.style.bottom = `${window.innerHeight - rect.top + 8}px`
      snippetPopup.style.transformOrigin = 'bottom left'
    } else {
      snippetPopup.style.bottom = 'auto'
      snippetPopup.style.top = `${rect.bottom + 8}px`
      snippetPopup.style.transformOrigin = 'top left'
    }
    
    snippetPopup.style.display = 'block'
    
    snippetPopup.querySelectorAll('.pm-snippet-item').forEach(item => {
      item.onclick = () => {
        const expanded = expandSnippet(item.dataset.trigger)
        onInsert(expanded + ' ')
        hideSnippetPopup()
      }
    })
  }

  function hideSnippetPopup() {
    snippetPopup.style.display = 'none'
    snippetSearch = ''
  }

  // Agregar estilos de snippets
  if (!document.getElementById('pm-snippet-styles')) {
    const snippetStyle = document.createElement('style')
    snippetStyle.id = 'pm-snippet-styles'
    snippetStyle.textContent = `
      .snippet-btn { font-size: 1rem; font-weight: 800; }
      .snippet-icon { font-weight: 900; color: var(--pm-text-muted); }
      .pm-snippet-popup {
        position: fixed;
        left: 0;
        background: var(--pm-surface);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        border: 1px solid var(--pm-border);
        border-radius: var(--pm-radius-md);
        box-shadow: 0 8px 32px rgba(0,0,0,0.2);
        z-index: 2000;
        max-height: 250px;
        overflow-y: auto;
        min-width: 240px;
        animation: pm-pop-up 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      }
      @keyframes pm-pop-up {
        from { opacity: 0; transform: translateY(10px) scale(0.95); }
        to { opacity: 1; transform: translateY(0) scale(1); }
      }
      .pm-snippet-item {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        padding: 0.5rem 0.75rem;
        cursor: pointer;
        border-bottom: 1px solid var(--pm-border);
      }
      .pm-snippet-item:last-child { border-bottom: none; }
      .pm-snippet-item:hover { background: var(--pm-surface-2); }
      .pm-snippet-icon { font-size: 1rem; }
      .pm-snippet-label {
        font-family: monospace;
        font-weight: 600;
        color: var(--pm-primary);
      }
      .pm-snippet-preview {
        font-size: 0.8rem;
        color: var(--pm-text-muted);
      }
    `
    document.head.appendChild(snippetStyle)
  }

  // Botón de snippets
  container.querySelector('#btn-snippets').onclick = () => {
    if (snippetPopup.style.display === 'block') {
      hideSnippetPopup()
    } else {
      showSnippetPopup()
    }
  }

  // === Help Modal ===
  const helpModal = createToolbarHelpModal(container)

  container.querySelector('#btn-help').onclick = () => {
    helpModal.open()
  }

  /**
   * Actualiza el contexto que usa el botón ✨ al llamar structureDSL.
   * @param {{ presentes?: string[], indicadorActivo?: string|null, indicadoresDisponibles?: string[] }} ctx
   */
  return {
    setContext(ctx = {}) {
      if (ctx.presentes !== undefined)           _ctx.presentes = ctx.presentes
      if (ctx.indicadorActivo !== undefined)     _ctx.indicadorActivo = ctx.indicadorActivo
      if (ctx.indicadoresDisponibles !== undefined) _ctx.indicadoresDisponibles = ctx.indicadoresDisponibles
    }
  }
}

/**
 * Modal para que maestros creen y gestionen clases
 * Requiere permiso: puede_inscribir_clases
 */

import { supabase } from '../../lib/supabaseClient.js'
import * as bootstrap from 'bootstrap'

export function gestionarClasesModal() {
  let isOpen = false
  let maestroId = null
  let clasesList = []

  const modal = document.createElement('div')
  modal.id = 'gestionar-clases-modal'
  modal.className = 'modal modal-fade'
  modal.setAttribute('role', 'dialog')
  modal.setAttribute('aria-labelledby', 'gestionar-clases-title')
  modal.innerHTML = `
    <div class="modal-dialog modal-dialog-centered modal-lg">
      <div class="modal-content border-0 shadow-lg">
        <div class="modal-header bg-apple-primary text-white border-0">
          <h5 class="modal-title" id="gestionar-clases-title">
            <i class="bi bi-mortarboard-fill"></i> Gestionar Clases
          </h5>
          <button type="button" class="btn-close btn-close-white" data-bs-dismiss="modal" aria-label="Close"></button>
        </div>

        <div class="modal-body">
          <!-- Tabs para listar y crear -->
          <ul class="nav nav-tabs mb-3" role="tablist">
            <li class="nav-item" role="presentation">
              <button class="nav-link active" id="clases-list-tab" type="button" role="tab" aria-controls="clases-list" aria-selected="true">
                <i class="bi bi-list-check"></i> Mis Clases
              </button>
            </li>
            <li class="nav-item" role="presentation">
              <button class="nav-link" id="clases-create-tab" type="button" role="tab" aria-controls="clases-create" aria-selected="false">
                <i class="bi bi-plus-circle"></i> Crear Clase
              </button>
            </li>
          </ul>

          <!-- Tab: Listar clases -->
          <div class="tab-pane fade show active" id="clases-list" role="tabpanel" aria-labelledby="clases-list-tab">
            <div id="clases-loading" class="text-center">
              <div class="spinner-border spinner-border-sm text-primary" role="status">
                <span class="visually-hidden">Cargando...</span>
              </div>
              <p class="mt-2">Cargando clases...</p>
            </div>
            <div id="clases-container" style="display: none;"></div>
            <div id="clases-empty" style="display: none;" class="text-center py-4">
              <i class="bi bi-inbox" style="font-size: 2rem; color: #ccc;"></i>
              <p class="text-muted mt-2">No hay clases registradas</p>
            </div>
            <div id="clases-error" style="display: none;" class="alert alert-danger" role="alert">
              <i class="bi bi-exclamation-circle"></i>
              <span id="clases-error-message"></span>
            </div>
          </div>

          <!-- Tab: Crear clase -->
          <div class="tab-pane fade" id="clases-create" role="tabpanel" aria-labelledby="clases-create-tab">
            <form id="crear-clase-form">
              <div class="mb-3">
                <label for="clase-nombre" class="form-label">Nombre de la Clase *</label>
                <input
                  type="text"
                  class="form-control"
                  id="clase-nombre"
                  placeholder="Ej: Matemáticas Básicas"
                  required
                />
                <div class="form-text text-danger d-none" id="clase-nombre-error"></div>
              </div>

              <div class="mb-3">
                <label for="clase-codigo" class="form-label">Código de Clase *</label>
                <input
                  type="text"
                  class="form-control"
                  id="clase-codigo"
                  placeholder="Ej: MAT-101"
                  required
                />
                <div class="form-text text-muted small">Identificador único para la clase</div>
              </div>

              <div class="mb-3">
                <label for="clase-descripcion" class="form-label">Descripción</label>
                <textarea
                  class="form-control"
                  id="clase-descripcion"
                  rows="3"
                  placeholder="Describe el contenido y objetivos de la clase..."
                ></textarea>
              </div>

              <div class="mb-3">
                <label for="clase-horario" class="form-label">Horario</label>
                <input
                  type="text"
                  class="form-control"
                  id="clase-horario"
                  placeholder="Ej: Lunes 10:00 - 12:00"
                />
              </div>

              <div class="mb-3">
                <label for="clase-ubicacion" class="form-label">Ubicación / Aula</label>
                <input
                  type="text"
                  class="form-control"
                  id="clase-ubicacion"
                  placeholder="Ej: Aula 101"
                />
              </div>

              <div id="crear-clase-error" class="alert alert-danger d-none mt-3" role="alert">
                <i class="bi bi-exclamation-circle"></i>
                <span id="crear-clase-error-message"></span>
              </div>
            </form>
          </div>
        </div>

        <div class="modal-footer border-0">
          <button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Cerrar</button>
          <button type="button" class="btn btn-apple-primary" id="btn-crear-clase" style="display: none;">
            <i class="bi bi-check-circle"></i> Crear Clase
          </button>
        </div>
      </div>
    </div>
  `

  document.body.appendChild(modal)

  const tabButtons = modal.querySelectorAll('[role="tab"]')
  const createButton = modal.querySelector('#btn-crear-clase')
  const createForm = modal.querySelector('#crear-clase-form')
  const createError = modal.querySelector('#crear-clase-error')
  const createErrorMsg = modal.querySelector('#crear-clase-error-message')

  // Handle tab switching
  tabButtons.forEach(btn => {
    btn.addEventListener('click', () => {
      const tabContent = btn.getAttribute('aria-controls')
      if (tabContent === 'clases-create') {
        createButton.style.display = 'inline-block'
      } else {
        createButton.style.display = 'none'
      }
    })
  })

  createButton.addEventListener('click', handleCrearClase)

  async function loadClases() {
    try {
      const listContainer = modal.querySelector('#clases-container')
      const loadingDiv = modal.querySelector('#clases-loading')
      const emptyDiv = modal.querySelector('#clases-empty')
      const errorDiv = modal.querySelector('#clases-error')

      loadingDiv.style.display = 'block'
      listContainer.style.display = 'none'
      emptyDiv.style.display = 'none'
      errorDiv.style.display = 'none'

      const { data, error } = await supabase
        .from('clases')
        .select('*')
        .eq('maestro_id', maestroId)
        .order('creado_en', { ascending: false })

      if (error) throw error

      clasesList = data || []
      loadingDiv.style.display = 'none'

      if (clasesList.length === 0) {
        emptyDiv.style.display = 'block'
      } else {
        listContainer.innerHTML = renderClasesList(clasesList)
        listContainer.style.display = 'block'
        attachClasesListeners(listContainer)
      }
    } catch (err) {
      console.error('[gestionarClasesModal] Error loading clases:', err)
      const errorDiv = modal.querySelector('#clases-error')
      const errorMsg = modal.querySelector('#clases-error-message')
      errorMsg.textContent = err.message || 'Error al cargar las clases'
      errorDiv.style.display = 'block'
      modal.querySelector('#clases-loading').style.display = 'none'
    }
  }

  function renderClasesList(clases) {
    return `
      <div class="list-group">
        ${clases.map(clase => `
          <div class="list-group-item" data-clase-id="${clase.id}">
            <div class="d-flex justify-content-between align-items-start">
              <div>
                <h6 class="mb-1 fw-bold">${clase.nombre}</h6>
                <p class="mb-1 text-muted small">
                  <i class="bi bi-code"></i> ${clase.codigo}
                </p>
                ${clase.descripcion ? `<p class="mb-1 small">${clase.descripcion}</p>` : ''}
                ${clase.horario ? `<p class="mb-1 small"><i class="bi bi-clock"></i> ${clase.horario}</p>` : ''}
                ${clase.ubicacion ? `<p class="mb-0 small"><i class="bi bi-geo-alt"></i> ${clase.ubicacion}</p>` : ''}
              </div>
              <div class="btn-group-sm" role="group">
                <button type="button" class="btn btn-sm btn-outline-primary btn-editar" data-clase-id="${clase.id}">
                  <i class="bi bi-pencil"></i>
                </button>
                <button type="button" class="btn btn-sm btn-outline-danger btn-eliminar" data-clase-id="${clase.id}">
                  <i class="bi bi-trash"></i>
                </button>
              </div>
            </div>
          </div>
        `).join('')}
      </div>
    `
  }

  function attachClasesListeners(container) {
    container.querySelectorAll('.btn-eliminar').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        const claseId = btn.getAttribute('data-clase-id')
        if (confirm('¿Estás seguro de que quieres eliminar esta clase?')) {
          await deleteClase(claseId)
        }
      })
    })

    container.querySelectorAll('.btn-editar').forEach(btn => {
      btn.addEventListener('click', (e) => {
        const claseId = btn.getAttribute('data-clase-id')
        // TODO: Implement edit functionality
        alert('Funcionalidad de edición próximamente')
      })
    })
  }

  async function deleteClase(claseId) {
    try {
      const { error } = await supabase
        .from('clases')
        .delete()
        .eq('id', claseId)
        .eq('maestro_id', maestroId)

      if (error) throw error

      window.dispatchEvent(new CustomEvent('showToast', {
        detail: { message: 'Clase eliminada exitosamente', type: 'success' }
      }))

      await loadClases()
    } catch (err) {
      console.error('[gestionarClasesModal] Error deleting clase:', err)
      window.dispatchEvent(new CustomEvent('showToast', {
        detail: { message: 'Error al eliminar la clase', type: 'danger' }
      }))
    }
  }

  async function handleCrearClase() {
    let originalText = ''
    try {
      if (!createForm.checkValidity()) {
        createForm.reportValidity()
        return
      }

      createButton.disabled = true
      originalText = createButton.innerHTML
      createButton.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Creando...'

      const formData = {
        maestro_id: maestroId,
        nombre: modal.querySelector('#clase-nombre').value.trim(),
        codigo: modal.querySelector('#clase-codigo').value.trim(),
        descripcion: modal.querySelector('#clase-descripcion').value.trim() || null,
        horario: modal.querySelector('#clase-horario').value.trim() || null,
        ubicacion: modal.querySelector('#clase-ubicacion').value.trim() || null,
        creado_en: new Date().toISOString()
      }

      const { data, error } = await supabase
        .from('clases')
        .insert([formData])
        .select()
        .single()

      if (error) throw error

      // Reset form
      createForm.reset()
      createError.classList.add('d-none')

      // Dispatch event
      window.dispatchEvent(new CustomEvent('clase-creada', {
        detail: { clase: data }
      }))

      window.dispatchEvent(new CustomEvent('showToast', {
        detail: {
          message: `Clase "${formData.nombre}" creada exitosamente`,
          type: 'success'
        }
      }))

      // Switch to list tab
      const listTab = modal.querySelector('#clases-list-tab')
      const tab = new bootstrap.Tab(listTab)
      tab.show()

      await loadClases()

    } catch (err) {
      console.error('[gestionarClasesModal] Error:', err)
      createErrorMsg.textContent = err.message || 'Error al crear la clase'
      createError.classList.remove('d-none')
    } finally {
      createButton.disabled = false
      if (originalText) {
        createButton.innerHTML = originalText
      }
    }
  }

  return {
    show(maestro_id) {
      maestroId = maestro_id
      const bsModal = new bootstrap.Modal(modal)
      bsModal.show()
      isOpen = true
      loadClases()
    },

    hide() {
      const bsModal = bootstrap.Modal.getInstance(modal)
      bsModal?.hide()
      isOpen = false
    },

    destroy() {
      modal.remove()
    },

    isOpen() {
      return isOpen
    }
  }
}

