// ── Helpers ────────────────────────────────────────────────────────────────

function mockFetchSuccess(content) {
  fetchMock.mockResolvedValue({
    ok: true,
    status: 200,
    json: vi.fn().mockResolvedValue({
      choices: [{ message: { content } }],
    }),
