    [
      ['Maestro:', maestro?.nombre_completo || maestro?.email || '—'],
      ['Horario:', horario ? `${fmtHora(horario.hora_inicio)} – ${fmtHora(horario.hora_fin)}` : '—'],
    ],
    [
      ['Instrumento:', clase?.instrumento || clase?.nivel || '—'],
      ['Salón:', salonNombre || '—'],
    ],
  ]

  rows.forEach((row, i) => {
