/**
 * Extrae texto de un archivo PDF
 */
async function extractTextFromPDF(file) {
  // Cargamos PDF.js dinámicamente si no está
  if (!window.pdfjsLib) {
    await loadScript('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.4.120/pdf.min.js');
    window.pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.4.120/pdf.worker.min.js';
  }

  const arrayBuffer = await file.arrayBuffer();
  const pdf = await window.pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  let fullText = '';

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    fullText += content.items.map(item => item.str).join(' ') + '\n';
  }

  return fullText;
}

/**
 * Extrae texto de un archivo DOCX
 */
async function extractTextFromDocx(file) {
  if (!window.mammoth) {
    await loadScript('https://cdnjs.cloudflare.com/ajax/libs/mammoth/1.4.0/mammoth.browser.min.js');
  }

  const arrayBuffer = await file.arrayBuffer();
  const result = await window.mammoth.extractRawText({ arrayBuffer });
  return result.value;
}

/**
 * Lee un archivo Markdown o Texto
 */
async function extractTextFromMarkdown(file) {
  return await file.text();
}

/**
 * Realiza OCR en una imagen
 */
async function extractTextFromImage(file, onProgress) {
  if (!window.Tesseract) {
    await loadScript('https://cdn.jsdelivr.net/npm/tesseract.js@4/dist/tesseract.min.js');
  }
  
  const worker = await Tesseract.createWorker({
    logger: m => {
      if (m.status === 'recognizing' && onProgress) {
        onProgress(Math.round(m.progress * 100));
      }
      console.log(`[OCR Progress] ${m.status}: ${(m.progress * 100).toFixed(1)}%`);
    }
  });
  
  await worker.loadLanguage('spa');
  await worker.initialize('spa');
  const { data: { text } } = await worker.recognize(file);
  await worker.terminate();
  return text;
}

function loadScript(src) {
  return new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.src = src;
    script.onload = resolve;
    script.onerror = reject;
    document.head.appendChild(script);
  });
}

/**
 * Función principal: Procesa el archivo y devuelve la estructura JSON
 */
export async function parsePlanningFile(file, onProgress) {
  let text = '';
  const ext = file.name.split('.').pop().toLowerCase();

  try {
    if (ext === 'pdf') {
      text = await extractTextFromPDF(file);
    } else if (ext === 'docx') {
      text = await extractTextFromDocx(file);
    } else if (ext === 'md' || ext === 'txt') {
      text = await extractTextFromMarkdown(file);
    } else if (['jpg', 'jpeg', 'png'].includes(ext)) {
      text = await extractTextFromImage(file, onProgress);
    } else {
      throw new Error('Formato no soportado. Usa PDF, DOCX, MD o Imágenes.');
    }

    if (!text.trim()) throw new Error('El archivo parece estar vacío o no contiene texto legible.');

    // Llamada a Groq
    const messages = [
      { role: 'system', content: EXTRACT_PLANNING_PROMPT },
      { role: 'user', content: `Analiza esta planificación y devuelve SOLO el JSON:\n\n${text.substring(0, 8000)}` }
    ];

    const jsonResponse = await callGroq(messages);
    
    // ROBUSTEZ: Extraer solo el bloque JSON (por si la IA añade texto extra)
    const jsonMatch = jsonResponse.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      throw new Error('La IA no devolvió un formato de datos válido.');
    }

    const cleanJson = jsonMatch[0].trim();
    return JSON.parse(cleanJson);

  } catch (err) {
    console.error('[PlanningParser] Error:', err);
    throw err;
  }
}

/**
 * reportService.js
 *
 * Three institutional PDF generator functions.
 * Each function queries Supabase, builds HTML via reportTemplates, opens a new window, prints.
 *
 * Exports:
 *   generateDailyReport(sesionId)
 *   generateMonthlyAttendance(claseId, year, month)
 *   generateMonthlyPedagogical(claseId, year, month)
 *
 * Also exports stat helpers for testing:
 *   calcAttendanceStats(asistenciaArray) → { P, A, J, total }
 *   buildAlumnoAttMap(sesiones) → { [alumnoId]: { [sesionId]: estado } }
 */

import { supabase } from '../../lib/supabaseClient.js'
import { AppToast } from '../../shared/components/AppToast.js'
import { generateMonthlyPatterns } from './groqService.js'
import {
  header,
  footer,
  metricChips,
  attendanceCell,
  progressBar,
  obsBlock,
  contentChips,
  compBar,
  openReport,
  wrapDocument,
  esc,
} from './reportTemplates.js'

// ---------------------------------------------------------------------------
// Stat helpers (exported for tests)
// ---------------------------------------------------------------------------

export function calcAttendanceStats(asistenciaArr) {
  const arr = asistenciaArr || []
  const P = arr.filter((a) => a.estado === 'P').length
  const A = arr.filter((a) => a.estado === 'A').length
  const J = arr.filter((a) => a.estado === 'J').length
  return { P, A, J, total: arr.length }
}

export function buildAlumnoAttMap(sesiones) {
  const map = {}
  for (const ses of sesiones) {
    for (const att of ses.asistencia || []) {
      if (!map[att.alumno_id]) map[att.alumno_id] = {}
      map[att.alumno_id][ses.id] = att.estado
    }
  }
  return map
}

// ---------------------------------------------------------------------------
// Date helpers
// ---------------------------------------------------------------------------

function formatDate(dateStr) {
  if (!dateStr) return ''
  const d = new Date(dateStr + 'T00:00:00')
  return d.toLocaleDateString('es-DO', { day: '2-digit', month: '2-digit', year: 'numeric' })
}

function monthName(month) {
  const names = [
    'Enero',
    'Febrero',
    'Marzo',
    'Abril',
    'Mayo',
    'Junio',
    'Julio',
    'Agosto',
    'Septiembre',
    'Octubre',
    'Noviembre',
    'Diciembre',
  ]
  return names[month - 1] ?? ''
}

function lastDayOfMonth(year, month) {
  return new Date(year, month, 0).getDate()
}

function padMM(n) {
  return String(n).padStart(2, '0')
}

