/**
 * Abre el HTML del reporte en una ventana visible y dispara el diálogo de impresión.
 * Si el navegador bloquea la ventana emergente, descarga el reporte como archivo HTML
 * que el usuario puede abrir y guardar como PDF.
 *
 * @param {string} html     — documento HTML completo
 * @param {string} filename — nombre base del archivo (sin extensión)
 * @returns {boolean}       — true si se pudo abrir la ventana, false si se descargó como archivo
 */
export function openReport(html, filename = 'reporte') {
  const reportWindow = window.open('', '_blank')

  if (reportWindow) {
    // Ventana abierta correctamente: escribir el HTML y disparar impresión
    reportWindow.document.open()
    reportWindow.document.write(html)
    reportWindow.document.close()
    reportWindow.focus()
    // Esperar a que carguen fuentes y estilos antes de imprimir
    reportWindow.onload = () => {
      setTimeout(() => reportWindow.print(), 500)
    }
    // Fallback: si onload ya disparó antes de asignarlo
    setTimeout(() => {
      try {
        if (reportWindow && !reportWindow.closed) reportWindow.print()
      } catch (_) {}
    }, 1500)
    return true
  }

  // Popup bloqueado → descargar como archivo HTML
  downloadReport(html, filename)
  return false
}

/**
 * Descarga el HTML del reporte como archivo .html.
 * El usuario puede abrirlo en el navegador y guardar como PDF (Ctrl+P → Guardar como PDF).
 *
 * @param {string} html     — documento HTML completo
 * @param {string} filename — nombre base del archivo (sin extensión)
 */
export function downloadReport(html, filename = 'reporte') {
  const date = new Date().toISOString().split('T')[0]
  const blob = new Blob([html], { type: 'text/html;charset=utf-8' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = `${filename}-${date}.html`
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  setTimeout(() => URL.revokeObjectURL(url), 1000)
}

/**
 * Wrap page content in a complete HTML document.
 * @param {string} pagesHtml — one or more <div class="page"> blocks
 * @param {boolean} landscape — whether to use @page landscape
 */
export function wrapDocument(pagesHtml, landscape = false) {
  const pageRule = landscape
    ? '@page { size: letter landscape; margin: 0; }'
    : '@page { size: letter portrait; margin: 0; }'

  return `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <title>Informe El Sistema Punta Cana</title>
  <style>
    ${pageRule}
    ${REPORT_CSS}
  </style>
</head>
<body>
  ${pagesHtml}
</body>
</html>`
}

import { supabase } from '../../lib/supabaseClient.js'
import { getSemaphoreForNode } from './evaluationService.js'
import { getMisClases } from './maestroDataService.js'
import { SemaphoreCache } from '../../lib/semaphoreCache.js'
import { fuzzyMatch, fuzzyMatchBest } from '../../lib/fuzzyMatch.js'

// Global cache instance for semaphore states
let _semaphoreCache = null

/**
 * Get or initialize the global semaphore cache.
 * @returns {SemaphoreCache}
 */
function getSemaphoreCache() {
  if (!_semaphoreCache) {
    _semaphoreCache = new SemaphoreCache({ ttl: 60000 }) // 60 second TTL
  }
  return _semaphoreCache
}

/**
 * Create a cache key from nodeId and claseId.
 * @param {string} nodeId
 * @param {string} claseId
 * @returns {string}
 */
export function getSemaphoreCacheKey(nodeId, claseId) {
  return `${nodeId}:${claseId}`
}

/**
 * Load semaphores for multiple nodes in batch, with caching.
 * Uses the global cache to avoid redundant queries for the same node+clase pair.
 *
 * @param {string[]} nodeIds
 * @param {string} claseId
 * @param {SemaphoreCache} [cache] - optional cache instance for testing
 * @returns {Promise<Map<string, string>>} Map of nodeId -> semaphore state
 */
export async function loadSemaphoresInBatch(nodeIds, claseId, cache = null) {
  const actualCache = cache || getSemaphoreCache()

  // Separate cached and uncached nodes
  const nodesToFetch = []
  const result = new Map()

  for (const nodeId of nodeIds) {
    const cacheKey = getSemaphoreCacheKey(nodeId, claseId)
    const cached = actualCache.get(cacheKey)

    if (cached !== null) {
      result.set(nodeId, cached)
    } else {
      nodesToFetch.push(nodeId)
    }
  }

  // Fetch uncached nodes in parallel
  if (nodesToFetch.length > 0) {
    const fetchResults = await Promise.all(
      nodesToFetch.map(nodeId =>
        getSemaphoreForNode(nodeId, claseId)
          .then(r => {
            const semaphore = r.semaphore
            const cacheKey = getSemaphoreCacheKey(nodeId, claseId)
            actualCache.set(cacheKey, semaphore)
            return { nodeId, semaphore }
          })
          .catch(() => {
            const semaphore = 'gray'
            const cacheKey = getSemaphoreCacheKey(nodeId, claseId)
            actualCache.set(cacheKey, semaphore)
            return { nodeId, semaphore }
          })
      )
    )

    for (const { nodeId, semaphore } of fetchResults) {
      result.set(nodeId, semaphore)
    }
  }

  return result
}

/**
 * Invalidate all cached semaphores for a specific clase.
 * @param {string} claseId
 */
export function invalidateSemaphoresForClase(claseId) {
  const cache = getSemaphoreCache()
  cache.invalidatePrefix(`:${claseId}`)
}

/**
 * Resolve the published route_version_id for a given clase, with fuzzy matching fallback.
 * First tries exact match via ilike on the first instrument.
 * If no match found, uses fuzzy matching against available routes.
 *
 * @param {string} claseId
 * @returns {Promise<string|null>}
 */
export async function resolveRutaIdForClaseWithFuzzy(claseId) {
  const misClases = await getMisClases()
  const claseRow  = misClases?.find(c => c.id === claseId)
  const instrumento = claseRow?.instrumento
  if (!instrumento) return null

  const primerInstrumento = instrumento.split(',')[0].trim().toLowerCase()

  // ── 1. Try exact match first ────────────────────────────────────────────────
  const { data: exactMatch, error: exactErr } = await supabase
    .from('routes')
    .select('id, instrument, route_versions!inner(id)')
    .ilike('instrument', `%${primerInstrumento}%`)
    .eq('route_versions.status', 'published')
    .limit(1)
    .maybeSingle()

  if (!exactErr && exactMatch) {
    return exactMatch.route_versions?.[0]?.id || exactMatch.route_versions?.id || null
  }

  // ── 2. Fallback to fuzzy matching ──────────────────────────────────────────
  const { data: allRoutes, error: allErr } = await supabase
    .from('routes')
    .select('id, instrument, route_versions!inner(id)')
    .eq('route_versions.status', 'published')

  if (allErr) {
    console.warn('[rutaService] resolveRutaIdForClaseWithFuzzy fuzzy match error:', allErr.message)
    return null
  }

  if (!allRoutes || allRoutes.length === 0) return null

  // Extract route instruments and find best fuzzy match
  const routeInstruments = allRoutes.map(r => ({
    instrument: r.instrument?.toLowerCase() || '',
    routeVersionId: r.route_versions?.[0]?.id || r.route_versions?.id,
  }))

  const bestMatch = fuzzyMatchBest(primerInstrumento, routeInstruments.map(r => r.instrument), 0.6)

  if (bestMatch) {
    const matched = routeInstruments.find(r => r.instrument === bestMatch.candidate)
    return matched?.routeVersionId || null
  }

  return null
}

/**
 * Load nodes for a specific level (lazy-load on expand).
 * Used by the UI to load child nodes when a level is expanded.
 *
 * @param {string} levelId
 * @returns {Promise<Object[]>} Array of node objects
 */
export async function loadNodesForLevel(levelId) {
  const { data, error } = await supabase
    .from('nodes')
    .select('id, level_id, nombre, order_index')
    .in('level_id', [levelId])
    .eq('route_version_id', null) // Only if not filtering by route_version_id

  if (error) {
    console.warn('[rutaService] loadNodesForLevel error:', error.message)
    return []
  }

  return data || []
}

/**
 * Load indicators for a specific node (lazy-load on expand).
 * Used by the UI to load child indicators when a node is expanded.
 *
 * @param {string} nodeId
 * @returns {Promise<Object[]>} Array of indicator objects
 */
export async function loadIndicatorsForNode(nodeId) {
  const { data, error } = await supabase
    .from('indicators')
    .select('id, node_id, description as nombre, order_index')
    .in('node_id', [nodeId])
    .eq('activo', true)
    .order('order_index', { ascending: true })

  if (error) {
    console.warn('[rutaService] loadIndicatorsForNode error:', error.message)
    return []
  }

  return data || []
}

/**
 * Resolve the published route_version_id for a given clase.
 * Matches the class instrumento against routes.instrument (case-insensitive).
 * Returns null if not found.
 *
 * @param {string} claseId
 * @returns {Promise<string|null>}
 */
export async function resolveRutaIdForClase(claseId) {
  const misClases = await getMisClases()
  const claseRow  = misClases?.find(c => c.id === claseId)
  const instrumento = claseRow?.instrumento
  if (!instrumento) return null

  const primerInstrumento = instrumento.split(',')[0].trim().toLowerCase()

  const { data, error } = await supabase
    .from('routes')
    .select('id, route_versions!inner(id)')
    .ilike('instrument', `%${primerInstrumento}%`)
    .eq('route_versions.status', 'published')
    .limit(1)
    .maybeSingle()

  if (error) {
    console.warn('[rutaService] resolveRutaIdForClase error:', error.message)
    return null
  }

  return data?.route_versions?.[0]?.id || data?.route_versions?.id || null
}

/**
 * Load the full route tree for a route version + class, with semaphore per node.
 *
 * Returns:
 * Block[] where:
 *   block.levels[].nodes[].semaphore = 'green'|'yellow'|'gray'
 *   block.levels[].semaphore         = aggregated from nodes
 *   block.levels[].locked            = true if previous level < 80% green indicators
 *
 * @param {string} routeVersionId
 * @param {string} claseId
 * @returns {Promise<Block[]>}
 */
export async function loadRouteTree(routeVersionId, claseId) {
  // ── 1. Blocks ──────────────────────────────────────────────────────────────
  const { data: blocks, error: bErr } = await supabase
    .from('blocks')
    .select('id, nombre:name, order_index')
    .eq('route_version_id', routeVersionId)
    .order('order_index', { ascending: true })

  if (bErr) throw new Error('[rutaService] blocks: ' + bErr.message)
  if (!blocks || blocks.length === 0) return []

  // ── 2. Levels ──────────────────────────────────────────────────────────────
  const blockIds = blocks.map(b => b.id)
  const { data: levels, error: lErr } = await supabase
    .from('levels')
    .select('id, block_id, nombre:name, order_index')
    .in('block_id', blockIds)
    .eq('route_version_id', routeVersionId)
    .order('order_index', { ascending: true })

  if (lErr) throw new Error('[rutaService] levels: ' + lErr.message)

  // ── 3. Nodes ───────────────────────────────────────────────────────────────
  const levelIds = (levels ?? []).map(l => l.id)
  if (levelIds.length === 0) return blocks.map(b => ({ ...b, levels: [] }))

  const { data: nodes, error: nErr } = await supabase
    .from('nodes')
    .select('id, level_id, nombre:name, order_index')
    .in('level_id', levelIds)
    .eq('route_version_id', routeVersionId)
    .order('order_index', { ascending: true })

  if (nErr) throw new Error('[rutaService] nodes: ' + nErr.message)

  // ── 4. Indicators ──────────────────────────────────────────────────────────
  const nodeIds = (nodes ?? []).map(n => n.id)
  const { data: indicators, error: iErr } = nodeIds.length > 0
    ? await supabase
        .from('indicators')
        .select('id, node_id, nombre:description, order_index')
        .in('node_id', nodeIds)
        .eq('activo', true)
        .order('order_index', { ascending: true })
    : { data: [], error: null }

  if (iErr) throw new Error('[rutaService] indicators: ' + iErr.message)

  // ── 5. Semaphore per node (parallel) ───────────────────────────────────────
  const semaphoreResults = await Promise.all(
    (nodes ?? []).map(n =>
      getSemaphoreForNode(n.id, claseId)
        .then(r => ({ nodeId: n.id, semaphore: r.semaphore }))
        .catch(() => ({ nodeId: n.id, semaphore: 'gray' }))
    )
  )
  const semMap = new Map(semaphoreResults.map(s => [s.nodeId, s.semaphore]))

  // ── 6. Group indicators by node ────────────────────────────────────────────
  const indByNode = new Map()
  for (const ind of indicators ?? []) {
    if (!indByNode.has(ind.node_id)) indByNode.set(ind.node_id, [])
    indByNode.get(ind.node_id).push({ ...ind, semaphore: semMap.get(ind.node_id) ?? 'gray' })
  }

  // ── 7. Group nodes by level ────────────────────────────────────────────────
  const nodesByLevel = new Map()
  for (const node of nodes ?? []) {
    if (!nodesByLevel.has(node.level_id)) nodesByLevel.set(node.level_id, [])
    nodesByLevel.get(node.level_id).push({
      ...node,
      semaphore: semMap.get(node.id) ?? 'gray',
      indicators: indByNode.get(node.id) ?? [],
    })
  }

  // ── 8. Group levels by block + compute level semaphore + lock state ────────
  const levelsByBlock = new Map()
  for (const [blockId] of blockIds.map(id => [id])) {
    levelsByBlock.set(blockId, [])
  }

  const levelsSortedByBlock = new Map()
  for (const level of levels ?? []) {
    if (!levelsSortedByBlock.has(level.block_id)) levelsSortedByBlock.set(level.block_id, [])
    levelsSortedByBlock.get(level.block_id).push(level)
  }

  for (const [blockId, blockLevels] of levelsSortedByBlock) {
    const enriched = blockLevels.map((level, idx, arr) => {
      const levelNodes = nodesByLevel.get(level.id) ?? []
      const allLevelInds = levelNodes.flatMap(n => indByNode.get(n.id) ?? [])
      const greenIndCount = allLevelInds.filter(i => (semMap.get(i.node_id) ?? 'gray') === 'green').length
      const percentage = allLevelInds.length > 0 ? Math.round((greenIndCount / allLevelInds.length) * 100) : 0

      const nodeSems   = levelNodes.map(n => n.semaphore)
      const levelSem   = nodeSems.every(s => s === 'green') && nodeSems.length > 0
        ? 'green'
        : nodeSems.every(s => s === 'gray') || nodeSems.length === 0
        ? 'gray'
        : 'yellow'

      // Lock: previous level must have ≥80% of its indicators green
      let locked = false
      if (idx > 0) {
        const prev = arr[idx - 1]
        const prevNodes = nodesByLevel.get(prev.id) ?? []
        const allInds = prevNodes.flatMap(n => indByNode.get(n.id) ?? [])
        const greenCount = allInds.filter(i => (semMap.get(i.node_id) ?? 'gray') === 'green').length
        locked = allInds.length > 0 && greenCount / allInds.length < 0.8
      }

      return { ...level, semaphore: levelSem, locked, percentage, nodes: levelNodes }
    })
    levelsByBlock.set(blockId, enriched)
  }

  return blocks.map(b => ({ ...b, levels: levelsByBlock.get(b.id) ?? [] }))
}

/**
 * syncManager — Sincronización automática de la cola offline
 *
 * Escucha el evento `online` del navegador y procesa la cola FIFO
 * de operaciones pendientes contra Supabase.
 *
 * Uso:
 *   import { initSyncManager } from './services/syncManager.js'
 *   initSyncManager()
 */

import { supabase } from '../../lib/supabaseClient.js'
import { processQueue, getQueueCount, getQueue } from './offlineQueue.js'

/** @type {Set<function>} */
const _listeners = new Set()

/**
 * Registra un callback que se dispara cuando cambia el estado de la cola.
 * @param {(count: number, status: 'idle'|'syncing'|'error') => void} fn
 */
export function onSyncStatusChange(fn) {
  _listeners.add(fn)
  return () => _listeners.delete(fn)
}

function _notify(count, status) {
  for (const fn of _listeners) {
    try {
      fn(count, status)
    } catch (_) {}
  }
}

// ─────────────────────────────────────────────────────────────
// Sync handlers por tabla
// ─────────────────────────────────────────────────────────────

/** Mapa: nombre de tabla → función de sync */
const _syncHandlers = {
  sesiones_clase: async (item) => {
    const { operacion, payload } = item
    if (operacion === 'insert') {
      const { error } = await supabase.from('sesiones_clase').insert(payload)
      if (error) throw error
    } else if (operacion === 'update') {
      const { id, ...data } = payload
      const { error } = await supabase
        .from('sesiones_clase')
        .update({ ...data, updated_at: new Date().toISOString() })
        .eq('id', id || payload.id)
      if (error) throw error
    } else {
      throw new Error(`Operación no soportada para sesiones_clase: ${operacion}`)
    }
  },

  asistencias: async (item) => {
    const { payload } = item
    const { error } = await supabase
      .from('asistencias')
      .upsert(payload, { onConflict: 'clase_id,alumno_id,fecha' })
    if (error) throw error
  },

  observaciones_sesion: async (item) => {
    const { operacion, payload } = item
    if (operacion === 'insert' || operacion === 'upsert') {
      const { error } = await supabase
        .from('observaciones_sesion')
        .upsert(payload, { onConflict: 'sesion_id,maestro_id' })
      if (error) throw error
    } else {
      throw new Error(`Operación no soportada para observaciones_sesion: ${operacion}`)
    }
  },

  observaciones_alumnos: async (item) => {
    const { operacion, payload } = item
    if (operacion === 'upsert') {
      const { error } = await supabase
        .from('observaciones_alumnos')
        .upsert(payload, { onConflict: 'sesion_clase_id,alumno_id' })
      if (error) throw error
    } else {
      throw new Error(`Operación no soportada para observaciones_alumnos: ${operacion}`)
    }
  },

  indicator_attempts: async (item) => {
    const { operacion, payload } = item
    if (operacion === 'upsert') {
      const { error } = await supabase
        .from('indicator_attempts')
        .upsert(payload, { onConflict: 'session_id,indicator_id,student_id' })
      if (error) throw error
    } else {
      throw new Error(`Operación no soportada para indicator_attempts: ${operacion}`)
    }
  },
}

/**
 * Procesa un item de la cola: lo rutea al handler según su tabla.
 * @param {object} item
 */
async function _syncItem(item) {
  const handler = _syncHandlers[item.tabla]
  if (!handler) {
    console.warn(`[syncManager] No hay handler para tabla: ${item.tabla} — se descarta`)
    return // descarta items de tablas desconocidas
  }
  await handler(item)
}

/**
 * Dispara la sincronización de toda la cola pendiente.
 * Se puede llamar manualmente o se dispara automáticamente al reconectar.
 */
export async function attemptSync() {
  const count = await getQueueCount()
  if (count === 0) return { synced: 0, failed: 0 }

  console.log(`[syncManager] Iniciando sync de ${count} item(s)...`)
  _notify(count, 'syncing')

  let synced = 0
  let failed = 0

  await processQueue(async (item) => {
    try {
      await _syncItem(item)
      synced++
    } catch (err) {
      failed++
      console.error(`[syncManager] Error sync ${item.tabla}#${item.id}:`, err.message)
      throw err // processQueue maneja reintentos
    }
  })

  const remaining = await getQueueCount()
  console.log(`[syncManager] Sync completo: ${synced} ok, ${failed} fail, ${remaining} pendientes`)
  _notify(remaining, remaining > 0 ? 'error' : 'idle')

  return { synced, failed, remaining }
}

/** @type {boolean} */
let _initialized = false

/**
 * Inicializa el sync manager.
 * Escucha el evento `online` y dispara la sincronización automática.
 * También escucha cambios de visibilidad para sync al volver a la pestaña.
 */
export function initSyncManager() {
  if (_initialized) return
  _initialized = true

  // Sync al recuperar conexión
  window.addEventListener('online', () => {
    console.log('[syncManager] Conexión recuperada — sincronizando...')
    attemptSync().catch((err) => console.error('[syncManager] Error en sync automático:', err))
  })

  // Sync al volver a la pestaña (por si recuperó conexión mientras estaba en segundo plano)
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible' && navigator.onLine) {
      attemptSync().catch((err) =>
        console.error('[syncManager] Error en sync por visibility:', err),
      )
    }
  })

  // Notificar estado inicial
  getQueueCount().then((count) => _notify(count, count > 0 ? 'idle' : 'idle'))
  console.log('[syncManager] Inicializado — esperando conexión...')
}

/**
 * ViewCache - Cache en memoria para datos de vistas del Portal Maestros
 * Evita consultas redundantes a Supabase al navegar entre vistas
 */

const CACHE_TTL = {
  misClases: 600000,       // 10 minutos — cambian rara vez
  horarios: 600000,        // 10 minutos — cambian rara vez
  sesiones: 120000,        // 2 minutos — se invalida manualmente al guardar
  inscripciones: 600000,   // 10 minutos — cambian rara vez
  salones: 3600000,        // 1 hora
  ausencias: 120000,       // 2 minutos
  metricasSesiones: 120000 // 2 minutos
}

let cache = new Map()
let cacheMeta = new Map()

function _isValid(key) {
  const meta = cacheMeta.get(key)
  if (!meta) return false
  return Date.now() - meta.timestamp < meta.ttl
}

function _set(key, data, ttl) {
  cache.set(key, data)
  cacheMeta.set(key, { timestamp: Date.now(), ttl: ttl || 60000 })
}

export function get(key) {
  if (!_isValid(key)) {
    cache.delete(key)
    cacheMeta.delete(key)
    return null
  }
  return cache.get(key)
}

export function set(key, data, ttlKey) {
  const ttl = CACHE_TTL[ttlKey] || 60000
  _set(key, data, ttl)
}

export function invalidate(pattern) {
  for (const key of cache.keys()) {
    if (key.includes(pattern)) {
      cache.delete(key)
      cacheMeta.delete(key)
    }
  }
}

export function invalidateAll() {
  cache.clear()
  cacheMeta.clear()
}

export function getCached(key) {
  return get(key)
}

export function keys() {
  return [...cache.keys()]
}

export default { get, set, invalidate, invalidateAll, getCached, _keys: keys }

/**
 * ViewRegistry - Gestor de vistas persistentes para SPA del Portal Maestros
 * Mantiene las vistas en el DOM y solo cambia cual se muestra con display:none/block
 * Esto evita recargas completas y mantiene el estado de cada vista
 */

import { getMaestroLocal } from '../auth/maestroAuth.js'
import viewCache from './viewCache.js'

const _views = new Map()
let _currentRoute = null
let _router = null

export function initViewRegistry(router) {
  _router = router
  
  window.addEventListener('popstate', (e) => {
    if (e.state?.route) {
      _navigateTo(e.state.route, false)
    }
  })
}

function _navigateTo(route, pushState = true) {
  if (pushState && _router) {
    history.pushState({ route }, '', `#/${route}`)
  }
  
  if (_currentRoute === route) return
  
  _showView(route)
  _currentRoute = route
}

function _showView(route) {
  const container = document.getElementById('pm-view-container')
  if (!container) return

  _views.forEach((viewData, viewName) => {
    if (viewName === route) {
      viewData.container.style.display = 'block'
      viewData.container.classList.add('pm-view-active')
      
      if (viewData.onShow) {
        viewData.onShow(viewData.container)
      }
    } else {
      viewData.container.style.display = 'none'
      viewData.container.classList.remove('pm-view-active')
    }
  })

  _updateActiveTab(route)
}

function _updateActiveTab(route) {
  const baseRoute = route.split('?')[0]
  
  // Footer nav tabs
  document.querySelectorAll('.pm-nav-tab').forEach(tab => {
    tab.classList.toggle('active', tab.dataset.route === baseRoute)
  })
  
  // Header tabs (tablet+)
  document.querySelectorAll('.pm-header-tab').forEach(tab => {
    tab.classList.toggle('active', tab.dataset.route === baseRoute)
  })
  
  // Legacy bottom tabs (for compatibility)
  document.querySelectorAll('.pm-bottom-tab').forEach(tab => {
    tab.classList.toggle('active', tab.dataset.route === baseRoute)
  })
}

export function registerView(name, renderFn, onShow = null) {
  const container = document.getElementById('pm-view-container')
  if (!container) {
    console.warn('[ViewRegistry] Container no encontrado')
    return
  }

  const viewContainer = document.createElement('div')
  viewContainer.id = `pm-view-${name}`
  viewContainer.className = 'pm-view-container'
  viewContainer.style.display = 'none'
  container.appendChild(viewContainer)

  _views.set(name, {
    container: viewContainer,
    render: renderFn,
    onShow: onShow,
    rendered: false
  })

  return viewContainer
}

export async function showView(name, params = {}) {
  const viewData = _views.get(name)
  if (!viewData) {
    console.warn(`[ViewRegistry] Vista no registrada: ${name}`)
    return
  }

  if (!viewData.rendered) {
    await viewData.render(viewData.container, params)
    viewData.rendered = true
  }

  _navigateTo(name)
}

export function getView(name) {
  return _views.get(name)
}

export function invalidateView(name) {
  const viewData = _views.get(name)
  if (viewData) {
    viewData.rendered = false
  }
}

export function invalidateAllViews() {
  _views.forEach((viewData) => {
    viewData.rendered = false
  })
}

export function navigate(route) {
  _navigateTo(route, true)
}

export default {
  initViewRegistry,
  registerView,
  showView,
  getView,
  invalidateView,
  invalidateAllViews,
  navigate
}

/**
 * portalEvents.js
 * Responsabilidad: Listeners globales del portal que se registran UNA sola vez:
 * notificaciones, permisos realtime, keyboard shortcuts, resize.
 */

import { supabase } from '../../lib/supabaseClient.js'
import {
  onNotificacionesChange,
  getUnreadCount,
  fetchNotificaciones,
  startRealtime,
  stopRealtime,
} from '../services/notificationService.js'
import { getPermisos } from '../services/permisoService.js'
import { AppToast } from '../../shared/components/AppToast.js'
import { getBreakpoint } from './portalShell.js'

let _globalEventsInitialized = false
let _permisosChannel = null

export function setupGlobalAppEvents({
  isAdmin,
  getMaestro,
  getPermisosCached,
  onPermisosUpdate,
  onNavigate,
  onResize,
}) {
  if (_globalEventsInitialized) return
  _globalEventsInitialized = true

  // ── Notificaciones badge ───────────────────────────────────
  onNotificacionesChange(() => {
    const badge = document.getElementById('pm-notif-badge')
    if (!badge) return
    const count = getUnreadCount()
    if (count > 0) {
      badge.textContent = count > 9 ? '9+' : count
      badge.style.display = 'flex'
    } else {
      badge.style.display = 'none'
    }
  })

  fetchNotificaciones()
  startRealtime()

  // ── Permisos Realtime (solo maestros, no admins) ───────────
  if (!isAdmin) {
    _subscribeToPermisos({ getMaestro, getPermisosCached, onPermisosUpdate, onNavigate })
  }

  // ── Keyboard shortcuts (desktop) ──────────────────────────
  document.addEventListener('keydown', (e) => {
    if (getBreakpoint() !== 'desktop') return
    if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return

    if (!window._globalAppKeys) window._globalAppKeys = []
    const _keys = window._globalAppKeys
    _keys.push(e.key.toLowerCase())

    if (_keys[_keys.length - 2] === 'g') {
      const shortcuts = { h: 'hoy', c: 'calendario', r: 'ruta', m: 'metricas', p: 'perfil' }
      const dest = shortcuts[e.key.toLowerCase()]
      if (dest) { onNavigate(dest); _keys.length = 0 }
    }
    if (_keys.length > 3) _keys.splice(0, _keys.length - 2)
  })

  // ── Resize → re-render shell en cambio de breakpoint ──────
  let _resizeTimer = null
  window.addEventListener(
    'resize',
    () => {
      clearTimeout(_resizeTimer)
      _resizeTimer = setTimeout(() => onResize(), 250)
    },
    { passive: true },
  )
}

function _subscribeToPermisos({ getMaestro, getPermisosCached, onPermisosUpdate, onNavigate }) {
  const maestro = getMaestro()
  if (!maestro?.id) return

  if (_permisosChannel) {
    supabase.removeChannel(_permisosChannel)
    _permisosChannel = null
  }

  _permisosChannel = supabase
    .channel(`permisos-maestro:${maestro.id}`)
    .on(
      'postgres_changes',
      { event: '*', schema: 'public', table: 'permisos_maestros', filter: `maestro_id=eq.${maestro.id}` },
      async (payload) => {
        console.log('[Realtime] Permisos actualizados:', payload.new)
        try {
          const nuevosPermisos = await getPermisos(maestro.id)
          const permisosPrevios = getPermisosCached()

          const ganados = []
          const perdidos = []
          if (nuevosPermisos.puede_inscribir_clases && !permisosPrevios?.puede_inscribir_clases)
            ganados.push('Gestionar e Inscribir Clases')
          if (permisosPrevios?.puede_inscribir_clases && !nuevosPermisos.puede_inscribir_clases)
            perdidos.push('Gestionar e Inscribir Clases')

          await onPermisosUpdate(nuevosPermisos, { ganados, perdidos })

          if (ganados.length > 0) {
            AppToast.success(`¡Nuevos permisos activados: ${ganados.join(', ')}! Ahora podés acceder desde el Perfil o la barra de navegación.`)
          } else if (perdidos.length > 0) {
            AppToast.show(`El administrador removió tu acceso a: ${perdidos.join(', ')}.`, 'warning')
          } else {
            AppToast.show('Tus permisos fueron actualizados por el administrador.', 'info')
          }
        } catch (err) {
          console.warn('[Realtime] Error actualizando permisos:', err.message)
        }
      },
    )
    .subscribe((status) => console.log('[Realtime] Canal permisos_maestros:', status))

  window.addEventListener('beforeunload', () => supabase.removeChannel(_permisosChannel), { once: true })
}

export function teardownGlobalEvents() {
  _globalEventsInitialized = false
  stopRealtime()
  if (_permisosChannel) {
    supabase.removeChannel(_permisosChannel)
    _permisosChannel = null
  }
}

/**
 * Tests for focusTrap utility
 *
 * Tests Tab/Shift+Tab cycling, auto-focus, Escape close,
 * and focus restoration on dispose.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { enableTrap } from '../focusTrap.js'

describe('enableTrap', () => {
  let container

  beforeEach(() => {
    container = document.createElement('div')
    container.innerHTML = `
      <button id="btn-1">First</button>
      <input id="input-1" type="text" />
      <select id="select-1"><option>1</option></select>
      <textarea id="textarea-1"></textarea>
      <button id="btn-2">Last</button>
      <div tabindex="0" id="div-focusable">Focusable div</div>
    `
    document.body.appendChild(container)
  })

  afterEach(() => {
    if (container.parentNode) container.parentNode.removeChild(container)
  })

  it('should return an object with a dispose function', () => {
    const trap = enableTrap(container, { onClose: vi.fn() })
    expect(trap).toBeTruthy()
    expect(typeof trap.dispose).toBe('function')
  })

  it('should auto-focus the first focusable element inside the container', () => {
    enableTrap(container, { onClose: vi.fn() })
    expect(document.activeElement).toBe(document.getElementById('btn-1'))
  })

  it('should trap Tab and cycle forward through focusable elements', () => {
    enableTrap(container, { onClose: vi.fn() })
    // btn-1 is already focused (auto-focus)

    // Tab to input-1
    document.getElementById('btn-1').focus()
    document.getElementById('btn-1').dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('input-1'))

    // Tab to select-1
    document.getElementById('input-1').dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('select-1'))

    // Tab to textarea-1
    document.getElementById('select-1').dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('textarea-1'))

    // Tab to btn-2
    document.getElementById('textarea-1').dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('btn-2'))

    // Tab to div-focusable
    document.getElementById('btn-2').dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('div-focusable'))
  })

  it('should wrap from the last to the first element on Tab', () => {
    enableTrap(container, { onClose: vi.fn() })
    const last = document.getElementById('div-focusable')
    last.focus()

    last.dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('btn-1'))
  })

  it('should reverse cycle on Shift+Tab', () => {
    enableTrap(container, { onClose: vi.fn() })
    // Focus the last element
    const last = document.getElementById('div-focusable')
    last.focus()

    last.dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', shiftKey: true, bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('btn-2'))
  })

  it('should wrap from the first to the last element on Shift+Tab', () => {
    enableTrap(container, { onClose: vi.fn() })
    const first = document.getElementById('btn-1')
    first.focus()

    first.dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', shiftKey: true, bubbles: true }))
    expect(document.activeElement).toBe(document.getElementById('div-focusable'))
  })

  it('should call onClose when Escape key is pressed', () => {
    const onClose = vi.fn()
    enableTrap(container, { onClose })

    container.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape', bubbles: true }))
    expect(onClose).toHaveBeenCalledTimes(1)
  })

  it('should restore focus to previously active element on dispose', () => {
    // Set up a trigger element that is outside the container
    const trigger = document.createElement('button')
    trigger.id = 'trigger-btn'
    document.body.appendChild(trigger)
    trigger.focus()
    expect(document.activeElement).toBe(trigger)

    const trap = enableTrap(container, { onClose: vi.fn() })
    // After trap, focus moved inside
    expect(document.activeElement).not.toBe(trigger)

    trap.dispose()
    expect(document.activeElement).toBe(trigger)

    document.body.removeChild(trigger)
  })

  it('should stop trapping Tab after dispose', () => {
    const trap = enableTrap(container, { onClose: vi.fn() })
    trap.dispose()

    const first = document.getElementById('btn-1')
    const second = document.getElementById('input-1')
    first.focus()

    // Tab should move freely (not trapped)
    first.dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', bubbles: true }))
    // Without trap, the event isn't prevented so focus shouldn't wrap
    expect(document.activeElement).toBe(first) // Default Tab behavior won't auto-move in jsdom
  })

  it('should not call onClose for Escape after dispose', () => {
    const onClose = vi.fn()
    const trap = enableTrap(container, { onClose })
    trap.dispose()

    container.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape', bubbles: true }))
    expect(onClose).not.toHaveBeenCalled()
  })
})

const TOKEN_PATTERNS = {
  // Prioriza 'todos' (cierre exacto). Si no, permite palabras (nombres) pero es estricto con los límites.
  alumnos: /#(todos\b|[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+(?:\s+(?:de|la|las|los|del|y|el)\b)?(?:\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)*|[A-Za-zÁÉÍÓÚáéíóúÑñ]+)/g,
  contenido: /\[([^\]]+)\]/g,
  sugerencias: /\(([^)]+)\)/g,
  tareas: /\{([^}]+)\}/g,
  medidas: /\$([^\s$]+)/g,
  objetivos: />([A-Z]{1,3}(?:-[A-Za-z]+)?-[0-9]+(?:\.[0-9]+)?)/g,
  niveles: />NIVEL-(\d{1,2})/g,
  nodos: />NODO:([A-Z_]+)/g,
  capas: /:::CAPA:\s*([A-Z_]+)/g,
  calificacion: /(\d)\/(\d)/g,
  estados: /!(LOGRADO|EN_PROGRESO|INICIADO)\b/gi,
}

/**
 * Detecta si el texto está en modo DSL o lenguaje natural.
 * @param {string} text
 * @returns {'dsl' | 'natural'}
 */
export function detectInputMode(text) {
  if (!text || typeof text !== 'string' || !text.trim()) return 'dsl'
  const hasTokens = /[#\[\(\{\$>!]/.test(text)
  return hasTokens ? 'dsl' : 'natural'
}

export const TOKEN_COLORS = {
  alumnos: '#0d6efd',
  contenido: '#198754',
  sugerencias: '#fd7e14',
  tareas: '#9333ea',
  medidas: '#6dd5ed',
  calificacion: '#dc3545',
  objetivos: '#6c757d',
  niveles: '#5856d6',
  nodos: '#af52de',
  capas: '#ff9500',
  estados: { LOGRADO: '#198754', EN_PROGRESO: '#0d6efd', INICIADO: '#6c757d' },
}

export const CAPA_MAP = {
  TECNICA: ['Escalas', 'Arpegios y patrones', 'Mano izquierda', 'Arco'],
  CORE: ['Sonido', 'Afinación'],
  REPERTORIO: ['Estudios técnicos', 'Repertorio / Obra-hito'],
}

function extractTokens(text, pattern) {
  if (!text) return []
  const results = []
  let match
  const regex = new RegExp(pattern.source, pattern.flags)
  while ((match = regex.exec(text)) !== null) {
    if (match[1]) {
      // Limpieza proactiva: si es un nombre (#alumno), cortamos en el primer caracter especial o token
      let cleaned = match[1].trim();
      if (pattern.source.includes('#')) {
        const parts = cleaned.split(/(?=\s[#\[\(\{\$>])/);
        cleaned = parts[0].trim();
      }
      results.push(cleaned)
    }
  }
  return results
}

function extractCalificacion(text) {
  if (!text) return null
  const match = text.match(/(\d)\/(\d)/)
  if (!match) return null

  const valor = parseInt(match[1], 10)
  const sobre = parseInt(match[2], 10)

  if (valor < 0 || valor > 5) return null
  if (sobre !== 5) return null

  return { valor, sobre }
}

function parseDSLSection(text) {
  return {
    alumnos: extractTokens(text, TOKEN_PATTERNS.alumnos),
    contenido: extractTokens(text, TOKEN_PATTERNS.contenido),
    sugerencias: extractTokens(text, TOKEN_PATTERNS.sugerencias),
    tareas: extractTokens(text, TOKEN_PATTERNS.tareas),
    medidas: extractTokens(text, TOKEN_PATTERNS.medidas),
    calificacion: extractCalificacion(text),
    objetivos: extractTokens(text, TOKEN_PATTERNS.objetivos),
    niveles: extractTokens(text, TOKEN_PATTERNS.niveles),
    nodos: extractTokens(text, TOKEN_PATTERNS.nodos),
    capas: extractTokens(text, TOKEN_PATTERNS.capas),
    estados: extractTokens(text, TOKEN_PATTERNS.estados).map(e => e.toUpperCase()),
  }
}

/**
 * Parsea el DSL organizándolo por capas si se detectan bloques :::CAPA
 */
export function parseDSL(text) {
  if (!text || typeof text !== 'string') {
    return {
      alumnos: [],
      contenido: [],
      sugerencias: [],
      tareas: [],
      medidas: [],
      calificacion: null,
      objetivos: [],
      niveles: [],
      nodos: [],
      capas: [],
      estados: [],
      por_capas: {}
    }
  }

  // 1. Extraer bloques por capas
  const capasRaw = text.split(/:::CAPA:/);
  const por_capas = {};
  
  if (capasRaw.length > 1) {
    capasRaw.forEach(bloque => {
      if (!bloque.trim()) return;
      const lines = bloque.split('\n');
      const capaName = lines[0].trim().toUpperCase();
      const content = lines.slice(1).join('\n');
      if (capaName) {
        por_capas[capaName] = parseDSLSection(content);
      }
    });
  }

  return {
    ...parseDSLSection(text),
    por_capas
  }
}

// Alias for legacy support
export const parseDsl = parseDSL;

export function highlightDSL(text) {
  if (!text) return ''

  // 1. Escapar HTML base
  let result = escapeHtml(text)
  
  // 2. Mapa de placeholders para evitar colisiones
  const placeholders = []
  function pushPlaceholder(html) {
    const id = `__DSL_TOKEN_${placeholders.length}__`
    placeholders.push({ id, html })
    return id
  }

  // 3. Aplicar transformaciones usando placeholders
  
  // Capas
  result = result.replace(TOKEN_PATTERNS.capas, (_, capa) => {
    return pushPlaceholder(`<span class="dsl-token dsl-capa" style="background:${TOKEN_COLORS.capas}22; color:${TOKEN_COLORS.capas}; font-weight:800; padding:2px 6px; border-radius:4px">:::CAPA: ${capa}</span>`)
  })

  // Niveles
  result = result.replace(/&gt;NIVEL-(\d{1,2})/g, (_, nivel) => {
    return pushPlaceholder(`<span class="dsl-token dsl-nivel" style="color:${TOKEN_COLORS.niveles}; font-weight:700">&gt;NIVEL-${nivel}</span>`)
  })

  // Nodos
  result = result.replace(/&gt;NODO:([A-Z_]+)/g, (_, nodo) => {
    return pushPlaceholder(`<span class="dsl-token dsl-nodo" style="color:${TOKEN_COLORS.nodos}; font-weight:600">&gt;NODO:${nodo}</span>`)
  })

  // Objetivos
  result = result.replace(/&gt;([A-Z]{1,3}(?:-[A-Za-z]+)?-[0-9]+(?:\.[0-9]+)?)/g, (_, objetivo) => {
    return pushPlaceholder(`<span class="dsl-token dsl-objetivo" data-objetivo="${objetivo}">&gt;${objetivo}</span>`)
  })

  // Alumnos
  result = result.replace(TOKEN_PATTERNS.alumnos, (_, nombre) => {
    return pushPlaceholder(`<span class="dsl-token dsl-alumno" data-nombre="${nombre}">#${nombre}</span>`)
  })

  // Contenido
  result = result.replace(TOKEN_PATTERNS.contenido, (_, contenido) => {
    return pushPlaceholder(`<span class="dsl-token dsl-contenido" data-contenido="${contenido}">[${contenido}]</span>`)
  })

  // Sugerencias
  result = result.replace(TOKEN_PATTERNS.sugerencias, (_, sugerencia) => {
    return pushPlaceholder(`<span class="dsl-token dsl-sugerencia" data-sugerencia="${sugerencia}">(${sugerencia})</span>`)
  })

  // Tareas
  result = result.replace(TOKEN_PATTERNS.tareas, (_, tarea) => {
    return pushPlaceholder(`<span class="dsl-token dsl-tarea" data-tarea="${tarea}">{${tarea}}</span>`)
  })

  // Medidas
  result = result.replace(TOKEN_PATTERNS.medidas, (_, medida) => {
    return pushPlaceholder(`<span class="dsl-token dsl-medida" data-medida="${medida}">$${medida}</span>`)
  })

  // Estados de progreso
  result = result.replace(/!(LOGRADO|EN_PROGRESO|INICIADO)/gi, (_, estado) => {
    const estadoUp = estado.toUpperCase()
    const colorMap = { LOGRADO: '#198754', EN_PROGRESO: '#0d6efd', INICIADO: '#6c757d' }
    const color = colorMap[estadoUp] ?? '#6c757d'
    return pushPlaceholder(
      `<span class="dsl-token dsl-estado" style="color:${color};font-weight:700;background:${color}18;padding:1px 4px;border-radius:3px">!${estadoUp}</span>`
    )
  })

  // Calificación
  result = result.replace(TOKEN_PATTERNS.calificacion, (_, v, s) => {
    return pushPlaceholder(`<span class="dsl-token dsl-calificacion" data-valor="${v}" data-sobre="${s}">${v}/${s}</span>`)
  })

  // 4. Restaurar placeholders (en orden inverso para manejar posibles anidamientos si existieran)
  for (let i = placeholders.length - 1; i >= 0; i--) {
    result = result.replace(placeholders[i].id, placeholders[i].html)
  }

  return result
}

function escapeHtml(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;')
}

export function getTokenSummary(parsed) {
  const summary = []

  if (parsed.alumnos.length > 0) summary.push(`${parsed.alumnos.length} alumno(s)`)
  if (parsed.contenido.length > 0) summary.push(`${parsed.contenido.length} contenido(s)`)
  if (parsed.sugerencias.length > 0) summary.push(`${parsed.sugerencias.length} sugerencia(s)`)
  if (parsed.tareas.length > 0) summary.push(`${parsed.tareas.length} tarea(s)`)
  if (parsed.medidas.length > 0) summary.push(`${parsed.medidas.length} medida(s)`)
  if (parsed.calificacion) summary.push(`calificación: ${parsed.calificacion.valor}/${parsed.calificacion.sobre}`)
  if (parsed.estados && parsed.estados.length > 0) summary.push(`${parsed.estados.length} estado(s)`)
  if (parsed.objetivos.length > 0) summary.push(`${parsed.objetivos.length} objetivo(s)`)
  if (parsed.niveles.length > 0) summary.push(`${parsed.niveles.length} nivel(es)`)
  if (parsed.nodos.length > 0) summary.push(`${parsed.nodos.length} nodo(s)`)
  if (Object.keys(parsed.por_capas).length > 0) summary.push(`${Object.keys(parsed.por_capas).length} capa(s)`)

  return summary.length > 0 ? summary.join(', ') : 'Sin tokens'
}

export function validateDsl(text) {
  const errors = []
  const parsed = parseDSL(text)

  if (parsed.calificacion) {
    if (parsed.calificacion.valor < 0 || parsed.calificacion.valor > 5) {
      errors.push('La calificación debe estar entre 0 y 5')
    }
    if (parsed.calificacion.sobre !== 5) {
      errors.push('El denominador de la calificación debe ser 5')
    }
  } else if (text && /\d\/\d/.test(text)) {
    const match = text.match(/(\d)\/(\d)/)
    if (match) {
      const valor = parseInt(match[1], 10)
      if (valor < 0 || valor > 5) {
        errors.push('La calificación debe estar entre 0 y 5')
      } else {
        errors.push('El denominador de la calificación debe ser 5')
      }
    }
  }

  if (text && text.length > 10000) {
    errors.push('El texto excede el límite de 10KB')
  }

  return { valid: errors.length === 0, errors }
}

/**
 * observationParser.js
 *
 * Pure-JS pre-processor for teacher observation text.
 * Extracts structure (who, state, note, task) WITHOUT calling any AI.
 * Groq is only called afterward to enrich content descriptions and observations.
 */

// ─── Normalizer ──────────────────────────────────────────────────────────────

/**
 * Normalizes text: lowercase, removes accents/diacritics, cleans spacing.
 * @param {string} text
 * @returns {string}
 */
export function normalizeText(text = '') {
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\p{L}\p{N}\s#]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

// ─── State keyword rules ─────────────────────────────────────────────────────

const STATE_RULES = [
  {
    estado: 'DIFICULTAD',
    peso: 4,
    keywords: [
      'no logro', 'no logra', 'no pudo', 'no puede', 'dificultad',
      'le cuesta', 'les cuesta', 'se le dificulta', 'se les dificulta',
      'confunde', 'confunden', 'sigue mostrando dificultad',
      'siguen mostrando dificultad', 'necesita reforzar', 'necesitan reforzar',
      'falta practica', 'falta mejorar', 'todavia no'
    ]
  },
  {
    estado: 'LOGRADO',
    peso: 3,
    keywords: [
      'logro', 'logra correctamente', 'domina', 'domino', 'dominan',
      'excelente', 'muy bien', 'supero', 'superaron', 'perfecto',
      'completo correctamente', 'completaron correctamente', 'ya sabe', 'ya saben'
    ]
  },
  {
    estado: 'INICIADO',
    peso: 2,
    keywords: [
      'inicio', 'comenzo', 'comenzaron', 'primera vez', 'se introdujo',
      'se introdujeron', 'nuevo contenido', 'empez', 'conocier', 'presentamos'
    ]
  },
  {
    estado: 'EN_PROGRESO',
    peso: 1,
    keywords: [
      'trabajo', 'trabajaron', 'practico', 'practicaron', 'repaso', 'repasaron',
      'continua', 'continuan', 'sigue', 'siguen', 'mejorando', 'avanzando',
      'progresando', 'van bien', 'casi'
    ]
  }
]

/**
 * Detects the most likely state from a text fragment using a weighted rule system.
 * Returns 'EN_PROGRESO' as conservative default.
 * @param {string} text
 * @returns {{value: 'LOGRADO'|'EN_PROGRESO'|'INICIADO'|'DIFICULTAD', confidence: number, evidence: string[]}}
 */
export function detectState(text) {
  const normalized = normalizeText(text)
  const matches = []

  for (const rule of STATE_RULES) {
    for (const kw of rule.keywords) {
      const normalizedKw = normalizeText(kw)
      if (normalized.includes(normalizedKw)) {
        matches.push({
          estado: rule.estado,
          peso: rule.peso,
          evidence: kw
        })
      }
    }
  }

  if (!matches.length) {
    return {
      value: 'EN_PROGRESO',
      confidence: 0.4,
      evidence: []
    }
  }

  // Sort by weight descending (highest weight wins)
  matches.sort((a, b) => b.peso - a.peso)

  return {
    value: matches[0].estado,
    confidence: Math.min(0.95, 0.55 + matches.length * 0.15),
    evidence: matches.map(m => m.evidence)
  }
}

// ─── Note detection ──────────────────────────────────────────────────────────

/**
 * Extracts a numeric note from text (format: "4/5", "3.5/5", "nota: 4").
 * @param {string} text
 * @returns {number|null}
 */
export function detectNote(text) {
  const m = text.match(/(\d(?:[.,]\d)?)\s*\/\s*5/)
  if (m) return parseFloat(m[1].replace(',', '.'))
  const m2 = text.match(/nota[:\s]+(\d(?:[.,]\d)?)/i)
  if (m2) return parseFloat(m2[1].replace(',', '.'))
  return null
}

// ─── Task detection ──────────────────────────────────────────────────────────

/**
 * Extracts explicit task from DSL {tarea} syntax or implicit "para la próxima" phrasing.
 * @param {string} text
 * @returns {string|null}
 */
export function detectTask(text) {
  const dsl = text.match(/\{([^}]+)\}/)
  if (dsl) return dsl[1].trim()
  const natural = text.match(/(?:tarea[:\s]+|para la pr[oó]xima[,:\s]+|practicar en casa[,:\s]+)([^.!?\n]{5,80})/i)
  if (natural) return natural[1].trim()
  return null
}

// ─── Alert detection (Fine categorisation) ───────────────────────────────────

export const ALERT_TYPES = {
  CONDUCTA: [
    'mal comportamiento', 'mala conducta', 'conducta disruptiva', 'comportamiento negativo',
    'falta de respeto', 'irrespetuoso', 'irrespetuosa', 'agresivo', 'agresiva',
    'pelea', 'peleo', 'golpeo', 'insulto', 'insulto', 'indisciplina', 'indisciplinado',
    'indisciplinada', 'actitud negativa', 'actitud problema', 'mala actitud',
    'no quiso', 'se nego', 'berrinche'
  ],
  ATENCION: [
    'dificultad en la atencion', 'atencion y concentracion', 'concentracion',
    'se distrae', 'no logra concentrarse', 'no atiende', 'no presta atencion',
    'distrae', 'falta de atencion', 'falta de concentracion'
  ],
  RIESGO_PEDAGOGICO: [
    'frustracion', 'atraso', 'acumulando fallas', 'riesgo', 'cuesta mas', 'le cuesta',
    'les cuesta', 'se le dificulta', 'se les dificulta', 'dificultad tecnica'
  ]
}

/**
 * Detects if a text fragment contains pedagogical or behavioral alerts.
 * Returns an object with type and message.
 * @param {string} text
 * @param {string} tipo - Inferred class category
 * @returns {{active: boolean, type: 'CONDUCTA'|'ATENCION'|'RIESGO_PEDAGOGICO'|null, mensaje: string|null}}
 */
export function detectPedagogicalAlert(text, tipo) {
  const normalized = normalizeText(text)
  
  if (tipo === 'comportamiento' || tipo === 'conducta') {
    return { active: true, type: 'CONDUCTA', mensaje: 'Alerta de comportamiento detectada.' }
  }
  
  for (const [alertType, keywords] of Object.entries(ALERT_TYPES)) {
    if (keywords.some(kw => normalized.includes(normalizeText(kw)))) {
      const label = alertType === 'RIESGO_PEDAGOGICO' ? 'Riesgo Pedagógico' : alertType === 'ATENCION' ? 'Atención y Concentración' : 'Conducta'
      return {
        active: true,
        type: alertType,
        mensaje: `Alerta de ${label.toLowerCase()} detectada.`
      }
    }
  }
  
  return { active: false, type: null, mensaje: null }
}

/** Legacy support - returns a boolean if any alert is active */
export function detectAlert(text, tipo) {
  return detectPedagogicalAlert(text, tipo).active
}

// ─── Tipo inference ──────────────────────────────────────────────────────────

const TIPO_KEYWORDS = {
  tecnica:        ['escala', 'posición', 'posicion', 'arco', 'digitación', 'digitacion',
                   'embocadura', 'afinación', 'afinacion', 'técnica', 'tecnica', 'vibrato',
                   'pizzicato', 'staccato', 'legato', 'golpe de arco', 'detaché'],
  repertorio:     ['obra', 'pieza', 'danzón', 'danzon', 'minueto', 'sonata', 'concierto',
                   'sinfonía', 'sinfonia', 'compases', 'c\\.\\d', 'repertorio', 'canción',
                   'cancion', 'melodía', 'melodia'],
  teoria:         ['ritmo', 'compás', 'compas', 'armonía', 'armonia', 'lectura', 'solfeo',
                   'teoría', 'teoria', 'nota', 'clave', 'intervalo', 'acorde'],
  interpretacion: ['expresión', 'expresion', 'fraseo', 'dinámica', 'dinamica', 'tempo',
                   'articulación', 'articulacion', 'musicalidad', 'carácter', 'caracter'],
}

/**
 * Infers the tipo from content text.
 * @param {string} text
 * @param {'instrumento'|'ensayo_general'|'teoria'} tipoClase
 * @returns {string}
 */
export function inferTipo(text, tipoClase = 'instrumento') {
  if (tipoClase === 'teoria') return 'teoria'
  const lower = text.toLowerCase()
  for (const [tipo, keywords] of Object.entries(TIPO_KEYWORDS)) {
    if (keywords.some(kw => new RegExp(kw).test(lower))) return tipo
  }
  return tipoClase === 'ensayo_general' ? 'repertorio' : 'tecnica'
}

// ─── Student name matching ────────────────────────────────────────────────────

/**
 * Builds a lookup map: name variant → Array of candidate student objects.
 * Accrue duplicates for ambiguity resolution.
 * @param {Array<{id, nombre, nombreCorto}>} roster
 * @returns {Map<string, object[]>}
 */
export function buildRosterLookup(roster) {
  const map = new Map()

  function addToIndex(key, alumno) {
    if (!key) return
    const normalized = normalizeText(key)
    const list = map.get(normalized) || []
    if (!list.some(a => a.id === alumno.id)) {
      list.push(alumno)
    }
    map.set(normalized, list)
  }

  for (const a of roster) {
    const full = (a.nombre || a.nombre_completo || '').toLowerCase().trim()
    const short = (a.nombreCorto || a.nombre_corto || a.nombre || a.nombre_completo || '').toLowerCase().trim()
    if (full) addToIndex(full, a)
    if (short && short !== full) addToIndex(short, a)
  }

  // Index first name
  const firstNames = roster.map(a => (a.nombre || a.nombre_completo || '').toLowerCase().trim().split(' ')[0])
  for (const a of roster) {
    const first = (a.nombre || a.nombre_completo || '').toLowerCase().trim().split(' ')[0]
    if (!first) continue
    addToIndex(first, a)
  }

  return map
}

/**
 * Finds all students mentioned in a text fragment, tracking ambiguity.
 * @param {string} text
 * @param {Map} lookup
 * @param {Array} presentes
 * @param {Array} alumnos
 * @returns {{students: Array, ambiguous: boolean, requires_confirmation: boolean}}
 */
export function findMentionedStudents(text, lookup, presentes, alumnos) {
  const lower = text.toLowerCase()
  const roster = presentes?.length ? presentes : alumnos

  if (/\btodos(?!\s+los\s+(?:compases|dedos|ejercicios|dias|metodos|aspectos|materiales|detalles|objetivos|retos|elementos|puntos|errores|fallas))\b|\btodo el grupo\b|\btoda la clase\b|\bel grupo\b/.test(lower)) {
    return {
      students: roster,
      ambiguous: false,
      requires_confirmation: false
    }
  }

  const foundMap = new Map()
  let ambiguous = false

  for (const [key, candidates] of lookup.entries()) {
    const escaped = key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
    if (new RegExp(`(?<![a-záéíóúñ])${escaped}(?![a-záéíóúñ])`, 'i').test(text)) {
      if (candidates.length > 1) {
        ambiguous = true
      }
      candidates.forEach(alumno => {
        foundMap.set(alumno.id || alumno.nombre || alumno.nombre_completo, alumno)
      })
    }
  }

  const found = Array.from(foundMap.values())

  return {
    students: found,
    ambiguous,
    requires_confirmation: ambiguous
  }
}

// ─── Sentence Segmentation ───────────────────────────────────────────────────

/**
 * Splits text into sentences protecting musical and decimal abbreviations.
 * @param {string} text
 * @returns {string[]}
 */
export function segmentSentences(text) {
  const protectedText = text
    .replace(/Lec\./gi, 'Lec§')
    .replace(/c\./gi, 'c§')
    .replace(/n\.º/gi, 'n§º')
    .replace(/(\d)[.](\d)/g, '$1§$2')

  return protectedText
    .replace(/([.!?;])\s+/g, '$1\n')
    .split('\n')
    .map(s => s
      .replace(/Lec§/gi, 'Lec.')
      .replace(/c§/gi, 'c.')
      .replace(/n§º/gi, 'n.º')
      .replace(/(\d)§(\d)/g, '$1.$2')
      .trim()
    )
    .filter(Boolean)
}

// ─── Group segmentation ───────────────────────────────────────────────────────

/**
 * Segments a teacher observation into named groups with advanced pedagogical scopes.
 *
 * Strategy: paragraph-first segmentation.
 * Teachers naturally write one paragraph per subject (Evans, the group, some students).
 * Splitting by sentence loses that context and creates too many redundant cards.
 *
 * Algorithm:
 *   1. Split by paragraph (double newline or clear topic shift)
 *   2. Within each paragraph, detect the primary subject (individual / grupo / exclusion / algunos)
 *   3. Merge sentences within the same paragraph into one fragment
 *   4. Track individual students with difficulties for "los demás" exclusion
 *
 * @param {string} text
 * @param {object} context
 * @returns {ParsedGroup[]}
 */
const IMPLICIT_RE = /\b(?:el alumno|la alumna|este alumno|esta alumna|dicho alumno|dicha alumna)\b/i

export function segmentObservation(text, context = {}) {
  const { alumnos = [], tipoClase = 'instrumento' } = context
  const presentes = context.presentes?.length ? context.presentes : alumnos
  const lookup = buildRosterLookup(presentes)

  // ── Step 1: split into paragraphs ────────────────────────────────────────
  const rawParagraphs = text
    .split(/\n{2,}/)                     // explicit blank lines
    .map(p => p.replace(/\n/g, ' ').trim())
    .filter(p => p.length > 10)

  const paragraphs = rawParagraphs.flatMap(paragraph => {
    const sentences = segmentSentences(paragraph).filter(s => !_isMetaCommentary(s))
    if (sentences.length === 0) return []
    if (sentences.length === 1) return [sentences[0]]

    const scopedSentences = sentences.filter(sentence => {
      const lower = sentence.toLowerCase()
      const hasStudents = findMentionedStudents(sentence, lookup, presentes, alumnos).students.length > 0
      const hasGroupScope = /\btodos(?!\s+los\s+(?:compases|dedos|ejercicios|dias|metodos|aspectos|materiales|detalles|objetivos|retos|elementos|puntos|errores|fallas))\b|\btodo el grupo\b|\btoda la clase\b|\balgunos\b/i.test(lower)
      const hasExclusionScope = /(?:los dem[a\u00e1]s|el resto del grupo|los otros alumnos)/i.test(sentence)
      const hasImplicitSubject = IMPLICIT_RE.test(sentence)
      return hasStudents || hasGroupScope || hasExclusionScope || hasImplicitSubject
    })

    return scopedSentences.length > 1 ? sentences : [sentences.join(' ')]
  })

  if (!paragraphs.length) return []

  const initialGroups = []
  // Track individuals explicitly named with a difficulty (for "los demás" exclusion)
  const individualDifficulties = new Set()

  // ── Step 2: process each paragraph as one semantic unit ──────────────────
  for (const paragraph of paragraphs) {
    const lower = paragraph.toLowerCase()

    const hasExclusionCue = /(?:los dem[a\u00e1]s|el resto del grupo|los otros alumnos)/i.test(paragraph)
    const isIndeterminado = /\balgunos\b/i.test(lower) &&
                            !findMentionedStudents(paragraph, lookup, presentes, alumnos).students.length

    const { students: mentioned, ambiguous, requires_confirmation } = findMentionedStudents(paragraph, lookup, presentes, alumnos)
    const startsWithExclusionCue = /^\s*(?:los dem[a\u00e1]s|el resto del grupo|los otros alumnos)\b/i.test(paragraph)
    const isExclusion = hasExclusionCue && (!mentioned.length || startsWithExclusionCue)
    // If no specific student mentioned and not a targeted exclusion/subgroup,
    // treat the paragraph as a collective observation for the whole group.
    const isImplicitColectivo = !mentioned.length && !isExclusion && !isIndeterminado
    const isColectivo = mentioned.length > 1 ||
                        /\btodos(?!\s+los\s+(?:compases|dedos|ejercicios|dias|metodos|aspectos|materiales|detalles|objetivos|retos|elementos|puntos|errores|fallas))\b|\btodo el grupo\b|\btoda la clase\b/.test(lower) ||
                        isExclusion ||
                        isImplicitColectivo

    const tipo     = inferTipo(paragraph, tipoClase)
    const stateObj = detectState(paragraph)
    const alertObj = detectPedagogicalAlert(paragraph, tipo)
    const effectiveAlertObj = alertObj.active
      ? alertObj
      : stateObj.value === 'DIFICULTAD'
        ? { active: true, type: 'RIESGO_PEDAGOGICO', mensaje: 'Riesgo pedagógico detectado.' }
        : alertObj

    // Track individual students flagged with difficulty for exclusion later
    if (!isColectivo && !isExclusion && mentioned.length === 1 &&
        (stateObj.value === 'DIFICULTAD' || effectiveAlertObj.active)) {
      individualDifficulties.add(mentioned[0].id || mentioned[0].nombre || mentioned[0].nombre_completo)
    }

    initialGroups.push({
      alumnos:              mentioned,
      alumnoTags:           [],
      fragment:             paragraph,
      estado:               stateObj,
      nota:                 detectNote(paragraph),
      tarea:                detectTask(paragraph),
      esColectivo:          isColectivo,
      isExclusion,
      isIndeterminado,
      alerta:               effectiveAlertObj.active || stateObj.value === 'DIFICULTAD',
      alertDetails:         effectiveAlertObj,
      tipoClase,
      ambiguous,
      requires_confirmation,
      scope:                'individual',
    })
  }

  // ── Step 2.5: inherit implicit subject ("el alumno", "la alumna", "su") ──
  _attachImplicitSubject(initialGroups)

  // ── Step 3: resolve scopes using accumulated difficulty context ───────────
  for (const group of initialGroups) {
    if (group.isExclusion) {
      const excludedIds = Array.from(individualDifficulties)
      group.alumnos = presentes.filter(a => {
        const id = a.id || a.nombre || a.nombre_completo
        return !excludedIds.includes(id)
      })
      group.esColectivo         = true
      group.scope               = 'grupo_excluyendo'
      group.excludeIds          = excludedIds
      group.alumnoTags          = ['Todos (excluyendo)']
    } else if (group.isIndeterminado) {
      group.alumnos             = []
      group.esColectivo         = false
      group.scope               = 'subgrupo_indeterminado'
      group.requires_confirmation = true
      group.alumnoTags          = ['Algunos']
    } else {
      group.scope = group.esColectivo ? 'grupo' : 'individual'
      if (group.esColectivo && !group.alumnos.length) {
        // Implicit collective — fill with all present students
        group.alumnos    = presentes
        group.alumnoTags = ['Todos']
      } else {
        group.alumnoTags = group.esColectivo
          ? ['Todos']
          : group.alumnos.map(a => a.nombreCorto || a.nombre_corto || a.nombre || a.nombre_completo)
      }
    }
  }

  // ── Step 4: split DIFICULTAD paragraphs by alert type ────────────────────
  // If one paragraph has both RIESGO_PEDAGOGICO and ATENCION cues, split into 2 cards
  return _splitDualAlerts(initialGroups, presentes, lookup)
}

/**
 * Returns true if a sentence is meta-commentary (institutional reflection, pedagogical
 * goals, continuity statements) rather than a direct observation record.
 * These sentences should NOT generate progress cards.
 *
 * Examples that should be filtered:
 *   "Es fundamental que continuemos trabajando en la práctica..."
 *   "Es importante señalar que debemos asegurarnos de que todos progresen."
 *   "Lo que es un gran desafío para el grupo."
 */
function _isMetaCommentary(text) {
  const n = normalizeText(text)
  return (
    /^es fundamental\b/.test(n)      ||
    /^es importante (que|senalar|notar|destacar)\b/.test(n) ||
    /\bdebemos continuar\b/.test(n)  ||
    /\bpara asegurarnos\b/.test(n)   ||
    /\bde manera equilibrada\b/.test(n) ||
    /\bcontinuemos trabajando\b/.test(n) ||
    /\bseguir trabajando\b/.test(n)  ||
    /\bcontinuar practicando\b/.test(n)
  )
}

/**
 * Resolves implicit subject references ("el alumno", "la alumna", "su") by
 * inheriting the last explicitly named individual student when no students are
 * found in a paragraph. This handles the common pattern:
 *
 *   "Evans tiene dificultad con el arco."  ← names Evans explicitly
 *   "El alumno además se distrae mucho."   ← implicit — still Evans
 *
 * Mutates groups in place.
 * @param {Array} groups
 */
function _attachImplicitSubject(groups) {
  let lastStudents = []
  let lastIsIndividual = false

  for (const group of groups) {
    const hasExplicit = group.alumnos?.length > 0

    if (hasExplicit) {
      if (!group.esColectivo && !group.isExclusion && !group.isIndeterminado) {
        lastStudents    = group.alumnos
        lastIsIndividual = true
      } else {
        // Reset on collective/group paragraphs so we don't over-inherit
        lastIsIndividual = false
      }
      continue
    }

    // No explicit students — check if text uses a back-reference pronoun
    if (lastIsIndividual && lastStudents.length && IMPLICIT_RE.test(group.fragment)) {
      group.alumnos           = [...lastStudents]
      group.esColectivo       = lastStudents.length > 1
      group.inherited_subject = true
    }
  }
}

/**
 * If a paragraph has both a technical risk AND an attention alert,
 * split it into two separate records so the teacher sees them distinctly.
 */
function _splitDualAlerts(groups, presentes, lookup) {
  const result = []
  for (const g of groups) {
    if (!g.alerta || g.esColectivo || g.isIndeterminado) {
      result.push(g)
      continue
    }

    const sentences = segmentSentences(g.fragment)
    const hasTechRisk = sentences.some(s => {
      const n = normalizeText(s)
      return ALERT_TYPES.RIESGO_PEDAGOGICO.some(kw => n.includes(normalizeText(kw)))
    })
    const hasAttention = sentences.some(s => {
      const n = normalizeText(s)
      return ALERT_TYPES.ATENCION.some(kw => n.includes(normalizeText(kw)))
    })

    if (hasTechRisk && hasAttention) {
      // Sentence 1..N-1 = technical risk, last attention sentence = attention card
      const attentionSentences = sentences.filter(s => {
        const n = normalizeText(s)
        return ALERT_TYPES.ATENCION.some(kw => n.includes(normalizeText(kw)))
      })
      const techSentences = sentences.filter(s => !attentionSentences.includes(s))

      if (techSentences.length) {
        result.push({
          ...g,
          fragment:     techSentences.join(' '),
          alertDetails: { active: true, type: 'RIESGO_PEDAGOGICO', mensaje: 'Riesgo pedagógico detectado.' },
        })
      }
      if (attentionSentences.length) {
        result.push({
          ...g,
          fragment:     attentionSentences.join(' '),
          alertDetails: { active: true, type: 'ATENCION', mensaje: 'Alerta de atención y concentración detectada.' },
        })
      }
    } else {
      result.push(g)
    }
  }
  return result
}

function _mergeAdjacentGroups(groups) {
  if (groups.length <= 1) return groups
  const merged = [groups[0]]
  for (let i = 1; i < groups.length; i++) {
    const prev = merged[merged.length - 1]
    const curr = groups[i]
    const sameStudents = _sameSet(
      prev.alumnos.map(a => a.id || a.nombre || a.nombre_completo),
      curr.alumnos.map(a => a.id || a.nombre || a.nombre_completo)
    )
    const sameStateValue = prev.estado.value === curr.estado.value
    const isBothDificultad = prev.estado.value === 'DIFICULTAD' && curr.estado.value === 'DIFICULTAD'

    if (sameStudents && (sameStateValue || isBothDificultad)) {
      prev.fragment += ' ' + curr.fragment
      prev.nota  = prev.nota  ?? curr.nota
      prev.tarea = prev.tarea ?? curr.tarea
      if (curr.alerta) {
        prev.alerta = true
        if (curr.alertDetails && curr.alertDetails.active) {
          prev.alertDetails = curr.alertDetails
        }
      }
      if (curr.estado.confidence > prev.estado.confidence) {
        prev.estado = curr.estado
      }
    } else {
      merged.push(curr)
    }
  }
  return merged
}

function _sameSet(a, b) {
  if (a.length !== b.length) return false
  const setA = new Set(a)
  return b.every(x => setA.has(x))
}

// ─── Contradiction detection ──────────────────────────────────────────────────

/**
 * Detects contradictory records.
 * @param {Array} progreso
 * @returns {Array<{idxA: number, idxB: number, reason: string}>}
 */
export function detectContradictions(progreso) {
  const conflicts = []

  for (let i = 0; i < progreso.length; i++) {
    for (let j = i + 1; j < progreso.length; j++) {
      const a = progreso[i]
      const b = progreso[j]

      if (!_sameAlumnoSet(a.alumnos, b.alumnos)) continue
      if (!_similarContent(a.contenido, b.contenido)) continue

      const notaConflict = a.nota != null && b.nota != null && Math.abs(a.nota - b.nota) > 1.5

      const stateConflict = a.estado !== b.estado &&
        ((a.estado === 'LOGRADO' && b.estado === 'INICIADO') ||
         (a.estado === 'INICIADO' && b.estado === 'LOGRADO'))

      if (notaConflict || stateConflict) {
        const reason = notaConflict
          ? `Notas contradictorias: ${a.nota}/5 vs ${b.nota}/5 para "${a.contenido}"`
          : `Estados contradictorios: ${a.estado} vs ${b.estado} para "${a.contenido}"`
        conflicts.push({ idxA: i, idxB: j, reason })
      }
    }
  }

  return conflicts
}

function _sameAlumnoSet(a, b) {
  if (!a?.length || !b?.length) return false
  if (a.length !== b.length) return false
  const setA = new Set(a.map(n => n.toLowerCase()))
  return b.every(n => setA.has(n.toLowerCase()))
}

function _similarContent(a, b) {
  if (!a || !b) return false
  const normalize = s => s.toLowerCase().replace(/[^a-záéíóúñ0-9]/g, ' ').trim()
  const na = normalize(a)
  const nb = normalize(b)
  if (na === nb) return true
  return na.includes(nb) || nb.includes(na)
}

// src/portal-maestros/views/__tests__/asistenciaView.race-condition.test.js
import { describe, it, expect, vi } from 'vitest'
import { createAsyncMutex } from '../../../shared/utils/asyncMutex.js'

describe('asistenciaView - Race Condition Prevention (deadlock fix)', () => {
  it('should prevent deadlock when button handler acquires mutex and calls _autoSave(true, skipMutex=true)', async () => {
    /**
     * This test validates the race condition fix pattern used in asistenciaView:
     *
     * Button handler pattern:
     *   await _saveMutex.run(async () => {
     *     // button save logic
     *     await _autoSave(true, true)  // skipMutex=true because we already hold the lock
     *   })
     *
     * _autoSave pattern (with skipMutex parameter):
     *   async function _autoSave(immediate = false, skipMutex = false) {
     *     const saveFn = async () => { ... }
     *     if (immediate) {
     *       if (skipMutex) {
     *         await saveFn()  // Caller already holds mutex
     *       } else {
     *         await _saveMutex.run(saveFn)  // Acquire mutex ourselves
     *       }
     *     }
     *   }
     *
     * If skipMutex=true is NOT respected, both would try to acquire the mutex,
     * causing deadlock (outer awaits inner, inner waits for outer lock release).
     */

    const mutex = createAsyncMutex()
    const executionLog = []
    const timeout = new Promise((_, reject) =>
      setTimeout(() => reject(new Error('DEADLOCK: Operation timed out')), 500)
    )

    // Simulate the button handler that holds the mutex
    const buttonHandler = async () => {
      executionLog.push('button-handler-start')

      return Promise.race([
        mutex.run(async () => {
          // Inside button handler, we hold the mutex
          executionLog.push('button-save-start')

          // Simulate _autoSave(true, true) being called with skipMutex=true
          // It should NOT try to acquire the mutex again
          const autoSaveFn = async () => {
            executionLog.push('autosave-fn-start')
            await new Promise(resolve => setTimeout(resolve, 20))
            executionLog.push('autosave-fn-end')
          }

          // With skipMutex=true, autoSave runs directly WITHOUT calling mutex.run()
          await autoSaveFn()

          executionLog.push('button-save-end')
        }),
        timeout
      ])
    }

    // Execute the button handler - should NOT timeout/deadlock
    await buttonHandler()

    // Verify execution order shows no deadlock
    expect(executionLog).toEqual([
      'button-handler-start',
      'button-save-start',
      'autosave-fn-start',
      'autosave-fn-end',
      'button-save-end'
    ])
  })

  it('should serialize autosave and button handler when they run concurrently', async () => {
    /**
     * Verify that autosave (deferred, holds mutex) and button click (immediate, holds mutex)
     * serialize correctly through the shared _saveMutex, with autosave completing first.
     */
    const mutex = createAsyncMutex()
    const events = []

    const autoSave = async () => {
      return mutex.run(async () => {
        events.push('autosave-start')
        await new Promise(resolve => setTimeout(resolve, 100))
        events.push('autosave-end')
      })
    }

    const buttonClick = async () => {
      return mutex.run(async () => {
        events.push('button-start')
        await new Promise(resolve => setTimeout(resolve, 50))
        events.push('button-end')
      })
    }

    // Fire both concurrently (simulating user clicking save while autosave in-flight)
    await Promise.all([autoSave(), buttonClick()])

    // Verify serialization: one completes, then the other
    expect(events).toEqual([
      'autosave-start',
      'autosave-end',
      'button-start',
      'button-end'
    ])
  })
})

