/**
 * Error reporting to Sentry
 * Tracks unhandled errors, exceptions, and performance issues
 */

let sentryInitialized = false
let userId = null

/**
 * Initialize Sentry error reporting
 * @param {Object} options
 * @param {string} options.dsn - Sentry DSN
 * @param {string} [options.environment] - Environment (dev/staging/prod)
 * @param {number} [options.tracesSampleRate] - Performance sampling rate
 */
export function initErrorReporter(options = {}) {
  const { dsn, environment = 'development', tracesSampleRate = 0.1 } = options

  if (!dsn) {
    // console.warn('[ErrorReporter] Disabled: no DSN provided') // Silenced for cleaner local dev console
    return
  }

  if (typeof window !== 'undefined' && window.Sentry) {
    const integrations = []
    if (window.Sentry.Replay) {
      integrations.push(new window.Sentry.Replay({ maskAllText: true, blockAllMedia: true }))
    }
    
    window.Sentry.init({
      dsn,
      environment,
      tracesSampleRate,
      integrations,
      replaysSessionSampleRate: 0.1,
      replaysOnErrorSampleRate: 1.0,
    })
    sentryInitialized = true
    console.log('[ErrorReporter] Initialized:', environment)
  }
}

/**
 * Report an error to Sentry
 * @param {Error|string} error - Error object or message
 * @param {Object} context - Additional context
 * @param {string} [context.userId] - User ID
 * @param {string} [context.context] - Error context
 * @param {string} [context.level] - Severity level
 */
export function reportError(error, context = {}) {
  if (!sentryInitialized && !window.Sentry) return

  const { userId: uid, context: ctx, level = 'error', ...extra } = context

  if (uid) {
    userId = uid
    window.Sentry?.setUser({ id: uid })
  }

  if (ctx) {
    window.Sentry?.setTag('context', ctx)
  }

  if (Object.keys(extra).length > 0) {
    window.Sentry?.setContext('details', extra)
  }

  if (error instanceof Error) {
    window.Sentry?.captureException(error, { level })
    console.error(`[Error] ${error.message}`, error)
  } else {
    window.Sentry?.captureMessage(String(error), level)
    console.warn(`[${level}] ${error}`)
  }
}

/**
 * Set current user for error tracking
 * @param {string} id - User ID
 * @param {Object} [info] - Additional user info
 */
export function setErrorUser(id, info = {}) {
  userId = id
  window.Sentry?.setUser({ id, ...info })
}

/**
 * Add breadcrumb (user action) for debugging
 * @param {string} message - Action description
 * @param {Object} [data] - Additional data
 */
export function addBreadcrumb(message, data = {}) {
  window.Sentry?.addBreadcrumb({
    message,
    data,
    level: 'info',
  })
  console.log(`[Breadcrumb] ${message}`, data)
}

/**
 * Start performance monitoring
 * @param {string} operation - Operation name
 * @returns {Object} Transaction object with finish() method
 */
export function startTransaction(operation) {
  if (!window.Sentry) {
    return { finish: () => {} }
  }

  const startTime = performance.now()
  return {
    finish: () => {
      const duration = performance.now() - startTime
      if (duration > 1000) {
        addBreadcrumb(`Slow operation: ${operation}`, { duration: duration.toFixed(2) })
      }
    },
  }
}

export default {
  initErrorReporter,
  reportError,
  setErrorUser,
  addBreadcrumb,
  startTransaction,
}

/**
 * Service Worker Caching Strategy
 * Implements offline-first caching for PWA
 */

const CACHE_VERSION = 'v1'
const STATIC_ASSETS = [
  '/',
  '/index.html',
  '/manifest.json',
  '/sw.js',
]

const CACHE_STRATEGIES = {
  STATIC: 'cache-first',
  API: 'network-first',
  DYNAMIC: 'stale-while-revalidate',
}

const NO_CACHE_PATHS = [
  '/auth/',
  '/login',
  '/logout',
]

/**
 * Get caching strategy for a request
 * @param {string} url - Request URL
 * @returns {string} Strategy name
 */
export function getCacheStrategy(url) {
  if (url.includes('/static/') || url.includes('.js') || url.includes('.css') || url.includes('.woff')) {
    return CACHE_STRATEGIES.STATIC
  }
  
  if (url.includes('/api/')) {
    if (url.includes('/notifications') || url.includes('/messages')) {
      return CACHE_STRATEGIES.DYNAMIC
    }
    return CACHE_STRATEGIES.API
  }
  
  return CACHE_STRATEGIES.STATIC
}

/**
 * Determine if request should be cached
 * @param {string} url - Request URL
 * @returns {boolean}
 */
export function shouldCache(url) {
  for (const noCache of NO_CACHE_PATHS) {
    if (url.includes(noCache)) {
      return false
    }
  }
  
  if (url.includes('/api/')) {
    return true
  }
  
  if (url.includes('/static/') || url.includes('.js') || url.includes('.css')) {
    return true
  }
  
  return false
}

/**
 * Get current cache version
 * @returns {string}
 */
export function getCacheVersion() {
  return CACHE_VERSION
}

/**
 * Get list of static assets to cache
 * @returns {string[]}
 */
export function getStaticAssets() {
  return [...STATIC_ASSETS]
}

/**
 * Clear app cache
 * @returns {Promise<Object>}
 */
export async function clearAppCache() {
  if (typeof caches === 'undefined') {
    return { success: false, error: 'Caches API not available' }
  }
  
  try {
    const cacheNames = await caches.keys()
    const deletePromises = cacheNames.map(name => caches.delete(name))
    await Promise.all(deletePromises)
    
    console.log('[SW] All caches cleared')
    return { success: true, deleted: cacheNames.length }
  } catch (error) {
    console.error('[SW] Failed to clear cache:', error)
    return { success: false, error: error.message }
  }
}

/**
 * Cache a specific response
 * @param {string} cacheName - Cache name
 * @param {Request} request - Request
 * @param {Response} response - Response
 */
export async function cacheResponse(cacheName, request, response) {
  if (typeof caches === 'undefined') return
  
  try {
    const cache = await caches.open(cacheName)
    await cache.put(request, response.clone())
  } catch (error) {
    console.warn('[SW] Failed to cache response:', error)
  }
}

/**
 * Get cached response if available
 * @param {string} url - Request URL
 * @returns {Promise<Response|null>}
 */
export async function getCachedResponse(url) {
  if (typeof caches === 'undefined') return null
  
  try {
    const cache = await caches.open(CACHE_VERSION)
    return await cache.match(url)
  } catch (error) {
    return null
  }
}

/**
 * Register service worker
 * @returns {Promise<Registration|null>}
 */
export async function registerServiceWorker() {
  if (typeof window === 'undefined' || !('serviceWorker' in navigator)) {
    console.warn('[SW] Service Worker not supported')
    return null
  }
  
  try {
    const registration = await navigator.serviceWorker.register('/sw.js', {
      scope: '/',
    })
    
    console.log('[SW] Registered:', registration.scope)
    return registration
  } catch (error) {
    console.error('[SW] Registration failed:', error)
    return null
  }
}

export default {
  getCacheStrategy,
  shouldCache,
  getCacheVersion,
  getStaticAssets,
  clearAppCache,
  cacheResponse,
  getCachedResponse,
  registerServiceWorker,
}

/**
 * Web Vitals monitoring
 * Tracks Core Web Vitals (LCP, FID, CLS) using Web Vitals API
 */

let metrics = {
  LCP: null,
  FID: null,
  CLS: null,
  FCP: null,
  TTFB: null,
}
let observerSupported = false

/**
 * Check if Web Vitals API is supported
 */
export function isSupported() {
  if (typeof window === 'undefined') return false
  return typeof PerformanceObserver !== 'undefined'
}

/**
 * Initialize Web Vitals monitoring
 * @param {Object} options
 * @param {boolean} options.debug - Log metrics to console
 * @param {Function} options.onReport - Callback when metrics are reported
 */
export function initWebVitals(options = {}) {
  const { debug = false, onReport = null } = options

  if (!isSupported()) {
    console.warn('[WebVitals] Not supported in this environment')
    return
  }

  observerSupported = true
  console.log('[WebVitals] Initialized')

  observeLCP(debug, onReport)
  observeFID(debug, onReport)
  observeCLS(debug, onReport)
  observeFCP(debug, onReport)
  observeTTFB(debug, onReport)
}

function observeLCP(debug, onReport) {
  try {
    const observer = new PerformanceObserver((list) => {
      const entries = list.getEntries()
      const lastEntry = entries[entries.length - 1]
      metrics.LCP = lastEntry.value
      if (debug) console.log('[LCP]', lastEntry.value)
      if (onReport) onReport('LCP', lastEntry.value)
    })
    observer.observe({ entryTypes: ['largest-contentful-paint'] })
  } catch (e) {
    if (debug) console.log('[LCP] Not available')
  }
}

function observeFID(debug, onReport) {
  try {
    const observer = new PerformanceObserver((list) => {
      const entries = list.getEntries()
      const firstEntry = entries[0]
      metrics.FID = firstEntry.value
      if (debug) console.log('[FID]', firstEntry.value)
      if (onReport) onReport('FID', firstEntry.value)
    })
    observer.observe({ entryTypes: ['first-input'] })
  } catch (e) {
    if (debug) console.log('[FID] Not available')
  }
}

function observeCLS(debug, onReport) {
  try {
    let clsValue = 0
    const observer = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        if (!entry.hadRecentInput) {
          clsValue += entry.value
        }
      }
      metrics.CLS = clsValue
      if (debug) console.log('[CLS]', clsValue)
      if (onReport) onReport('CLS', clsValue)
    })
    observer.observe({ entryTypes: ['layout-shift'] })
  } catch (e) {
    if (debug) console.log('[CLS] Not available')
  }
}

function observeFCP(debug, onReport) {
  try {
    const observer = new PerformanceObserver((list) => {
      const entries = list.getEntries()
      const firstEntry = entries[0]
      metrics.FCP = firstEntry.value
      if (debug) console.log('[FCP]', firstEntry.value)
      if (onReport) onReport('FCP', firstEntry.value)
    })
    observer.observe({ entryTypes: ['paint'] })
  } catch (e) {
    if (debug) console.log('[FCP] Not available')
  }
}

function observeTTFB(debug, onReport) {
  try {
    const observer = new PerformanceObserver((list) => {
      const entries = list.getEntries()
      const navEntry = entries[0]
      metrics.TTFB = navEntry.responseStart
      if (debug) console.log('[TTFB]', navEntry.responseStart)
      if (onReport) onReport('TTFB', navEntry.responseStart)
    })
    observer.observe({ entryTypes: ['navigation'] })
  } catch (e) {
    if (debug) console.log('[TTFB] Not available')
  }
}

/**
 * Get collected Web Vitals metrics
 */
export function getWebVitals() {
  return { ...metrics }
}

/**
 * Get performance rating for a metric
 * @param {string} metric - Metric name
 * @param {number} value - Metric value
 */
export function getRating(metric, value) {
  const thresholds = {
    LCP: { good: 2500, poor: 4000 },
    FID: { good: 100, poor: 300 },
    CLS: { good: 0.1, poor: 0.25 },
    FCP: { good: 1800, poor: 3000 },
    TTFB: { good: 800, poor: 1800 },
  }

  const threshold = thresholds[metric]
  if (!threshold) return 'unknown'

  if (value <= threshold.good) return 'good'
  if (value >= threshold.poor) return 'poor'
  return 'needs-improvement'
}

export default {
  initWebVitals,
  getWebVitals,
  isSupported,
  getRating,
}

// Global modal singleton — lives in <body>, never touched by the router.
// Usage:
//   AppModal.open({ title, body, onSave, onCancel, saveText, size })
//   AppModal.close()

const MODAL_ID = 'app-global-modal'
const BACKDROP_ID = 'app-global-backdrop'

function ensureDOM() {
  if (document.getElementById(MODAL_ID)) return

  // Backdrop
  const backdrop = document.createElement('div')
  backdrop.id = BACKDROP_ID
  backdrop.style.cssText = `
    display:none;position:fixed;inset:0;
    background:var(--pm-backdrop, rgba(0,0,0,0.55));
    backdrop-filter:blur(4px);
    z-index:11000;
    transition:opacity .2s ease;
    opacity:0;
  `
  document.body.appendChild(backdrop)

  // Modal shell
  const modal = document.createElement('div')
  modal.id = MODAL_ID
  modal.setAttribute('role', 'dialog')
  modal.setAttribute('aria-modal', 'true')
  modal.style.cssText = `
    display:none;position:fixed;inset:0;
    z-index:11001;
    overflow-y:auto;
    padding:1.5rem;
    align-items:center;
    justify-content:center;
  `
  modal.innerHTML = `
    <div class="app-modal-dialog" style="
      background:var(--pm-surface, var(--bs-body-bg, #ffffff));
      color:var(--pm-text, var(--bs-body-color, #212529));
      border:1px solid var(--pm-border, var(--bs-border-color, #dee2e6));
      border-radius:16px;
      box-shadow:0 20px 60px rgba(0,0,0,0.2);
      width:100%;
      max-width:480px;
      margin:auto;
      transform:translateY(20px) scale(0.97);
      transition:transform .25s cubic-bezier(.34,1.56,.64,1), opacity .2s ease;
      opacity:0;
      overflow:hidden;
    ">
      <!-- Header -->
      <div class="app-modal-header" style="
        padding:1rem 1.25rem;
        border-bottom:1px solid var(--pm-border, var(--bs-border-color, #dee2e6));
        display:flex;align-items:center;gap:.5rem;
        background: linear-gradient(135deg, var(--pm-primary, var(--bs-primary, #0d6efd)) 0%, #5856d6 100%);
      ">
        <h5 class="app-modal-title mb-0 fw-bold" style="flex:1;font-size:1.0625rem;color:white;font-weight:600;letter-spacing:-0.01em;"></h5>
        <button class="app-modal-close-x" type="button" aria-label="Cerrar" style="
          background:rgba(255,255,255,0.15);border:none;cursor:pointer;
          width:28px;height:28px;border-radius:50%;
          display:flex;align-items:center;justify-content:center;
          color:white;
          transition:all .15s;
          flex-shrink:0;
        ">
          <i class="bi bi-x-lg" style="font-size:0.875rem;"></i>
        </button>
      </div>

      <!-- Body -->
      <div class="app-modal-body" style="padding:1.25rem; background:var(--pm-surface, var(--bs-body-bg, #ffffff));"></div>

      <!-- Footer -->
      <div class="app-modal-footer" style="
        padding:1rem 1.25rem;
        border-top:1px solid var(--pm-border, var(--bs-border-color, #dee2e6));
        display:flex;align-items:center;justify-content:flex-end;gap:.5rem;
        background:var(--pm-surface-2, var(--bs-tertiary-bg, #f8f9fa));
      ">
        <button class="app-modal-btn-delete pm-btn" type="button" style="background:none; border:none; color:var(--pm-danger, var(--bs-danger, #dc3545)); font-size:0.85rem; font-weight:600; padding:0.5rem 1rem; cursor:pointer; margin-right:auto; display:none;">Eliminar</button>
        <button class="app-modal-btn-cancel pm-btn pm-btn-outline" type="button">Cancelar</button>
        <button class="app-modal-btn-save pm-btn pm-btn-primary" type="button">
          <span class="app-modal-save-text">Guardar</span>
        </button>
      </div>
    </div>
  `
  document.body.appendChild(modal)
}

function escapeHTML(text) {
  if (!text) return ''
  return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
}

function getEls() {
  return {
    backdrop: document.getElementById(BACKDROP_ID),
    modal:    document.getElementById(MODAL_ID),
    dialog:   document.querySelector(`#${MODAL_ID} .app-modal-dialog`),
    title:    document.querySelector(`#${MODAL_ID} .app-modal-title`),
    body:     document.querySelector(`#${MODAL_ID} .app-modal-body`),
    closeX:   document.querySelector(`#${MODAL_ID} .app-modal-close-x`),
    btnCancel:document.querySelector(`#${MODAL_ID} .app-modal-btn-cancel`),
    btnSave:  document.querySelector(`#${MODAL_ID} .app-modal-btn-save`),
    btnDelete:document.querySelector(`#${MODAL_ID} .app-modal-btn-delete`),
    saveText: document.querySelector(`#${MODAL_ID} .app-modal-save-text`),
  }
}

// Sizes
const SIZES = { sm: '400px', md: '520px', lg: '720px', xl: '960px' }

export const AppModal = {
  _saveHandler: null,
  _cancelHandler: null,
  _keydownHandler: null,

  open({ title = '', body = '', saveText = 'Guardar', cancelText = 'Cancelar', deleteText = 'Eliminar', onSave = null, onCancel = null, onDelete = null, onShow = null, onOpen = null, size = 'md', hideSave = false } = {}) {
    ensureDOM()
    const els = getEls()

    // Reset footer visibility so a previous call with `!important` inline
    // style cannot bleed into this new modal (e.g. profile modal hiding footer).
    const footer = els.dialog.querySelector('.app-modal-footer')
    if (footer) footer.style.removeProperty('display')

    // Size
    els.dialog.style.maxWidth = SIZES[size] || SIZES.md

    // Content
    els.title.textContent = title
    if (typeof body === 'string') {
      els.body.innerHTML = body
    } else if (body instanceof HTMLElement) {
      els.body.innerHTML = ''
      els.body.appendChild(body)
    }

    if (onShow) onShow(els.body)

    // onOpen fires async after the animation completes (useful for async data loads)
    if (onOpen) setTimeout(() => onOpen(els.body), 280)

    // Buttons
    this.resetSaveBtn(saveText)
    els.btnCancel.textContent = cancelText
    els.btnSave.style.display = hideSave ? 'none' : ''
    
    // Delete btn logic
    if (onDelete) {
      els.btnDelete.textContent = deleteText
      els.btnDelete.style.display = 'block'
    } else {
      els.btnDelete.style.display = 'none'
    }

    // Trap focus on first input when open
    setTimeout(() => {
      const first = els.body.querySelector('input,select,textarea')
      if (first) first.focus()
    }, 280)

    // Wire handlers — remove old ones first
    this._detachHandlers()

    this._keydownHandler = (e) => {
      if (e.key === 'Escape') {
        this._cancelHandler ? this._cancelHandler() : this.close()
      }
    }
    document.addEventListener('keydown', this._keydownHandler)

    this._saveHandler = async () => {
      if (onSave) {
        const btn = els.btnSave
        const original = btn.innerHTML
        btn.disabled = true
        btn.innerHTML = '<span class="spinner-border spinner-border-sm me-1" role="status"></span>'
      try {
        const result = await onSave(els.body)
        if (result !== false) {
          this.close()
        } else {
          btn.disabled = false
          btn.innerHTML = original
        }
      } catch (err) {
        btn.disabled = false
        btn.innerHTML = original
      }
      } else {
        this.close()
      }
    }

    this._cancelHandler = () => {
      if (onCancel) onCancel()
      this.close()
    }

    this._deleteHandler = async () => {
      if (!onDelete) return
      if (!confirm('¿Estás seguro de que querés eliminar este elemento? Esta acción no se puede deshacer.')) return
      
      const original = els.btnDelete.innerHTML
      els.btnDelete.disabled = true
      els.btnDelete.innerHTML = '<span class="spinner-border spinner-border-sm" role="status"></span>'
      
      try {
        const result = await onDelete()
        if (result !== false) this.close()
        else {
          els.btnDelete.disabled = false
          els.btnDelete.innerHTML = original
        }
      } catch (err) {
        els.btnDelete.disabled = false
        els.btnDelete.innerHTML = original
      }
    }

    els.btnSave.addEventListener('click', this._saveHandler)
    els.btnCancel.addEventListener('click', this._cancelHandler)
    els.closeX.addEventListener('click', this._cancelHandler)
    els.btnDelete.addEventListener('click', this._deleteHandler)

    // Close-X hover style
    els.closeX.onmouseenter = () => { els.closeX.style.background = 'var(--bs-secondary-bg)'; els.closeX.style.color = 'var(--bs-body-color)' }
    els.closeX.onmouseleave = () => { els.closeX.style.background = 'none'; els.closeX.style.color = 'var(--bs-secondary-color)' }

    // Show
    els.backdrop.style.display = 'block'
    els.modal.style.display = 'flex'
    document.body.style.overflow = 'hidden'

    requestAnimationFrame(() => {
      els.backdrop.style.opacity = '1'
      els.dialog.style.opacity = '1'
      els.dialog.style.transform = 'translateY(0) scale(1)'
    })
  },

  close() {
    if (!document.getElementById(MODAL_ID)) return
    const els = getEls()

    els.backdrop.style.opacity = '0'
    els.dialog.style.opacity = '0'
    els.dialog.style.transform = 'translateY(20px) scale(0.97)'

    this._detachHandlers()

    setTimeout(() => {
      els.backdrop.style.display = 'none'
      els.modal.style.display = 'none'
      els.body.innerHTML = ''
      document.body.style.overflow = ''
    }, 220)
  },

  _detachHandlers() {
    const els = getEls()
    if (!els.btnSave) return
    if (this._saveHandler) els.btnSave.removeEventListener('click', this._saveHandler)
    if (this._cancelHandler) {
      els.btnCancel.removeEventListener('click', this._cancelHandler)
      els.closeX.removeEventListener('click', this._cancelHandler)
    }
    if (this._deleteHandler) {
      els.btnDelete.removeEventListener('click', this._deleteHandler)
    }
    if (this._keydownHandler) {
      document.removeEventListener('keydown', this._keydownHandler)
    }
    this._saveHandler = null
    this._cancelHandler = null
    this._deleteHandler = null
    this._keydownHandler = null
  },

  // Reset save button after error (call from onSave catch if you handle errors yourself)
  resetSaveBtn(text = 'Guardar') {
    const btn = document.querySelector(`#${MODAL_ID} .app-modal-btn-save`)
    if (btn) { btn.disabled = false; btn.innerHTML = `<span class="app-modal-save-text">${text}</span>` }
  },

  setSaveHandler(newOnSave, newText = null) {
    const els = getEls()
    if (!els.btnSave) return

    // Detach old handler
    if (this._saveHandler) els.btnSave.removeEventListener('click', this._saveHandler)

    // Update text if provided
    if (newText) this.resetSaveBtn(newText)

    // Wrap new handler
    this._saveHandler = async () => {
      const btn = els.btnSave
      const original = btn.innerHTML
      btn.disabled = true
      btn.innerHTML = '<span class="spinner-border spinner-border-sm me-1" role="status"></span>'
      try {
        const result = await newOnSave(els.body)
        if (result !== false) {
          this.close()
        } else {
          btn.disabled = false
          btn.innerHTML = original
        }
      } catch (err) {
        btn.disabled = false
        btn.innerHTML = original
      }
    }

    els.btnSave.addEventListener('click', this._saveHandler)
  },

  showLoading(message = 'Cargando...') {
    const els = getEls()
    if (!els.body) return

    els.body.innerHTML = `
      <div class="d-flex flex-column align-items-center justify-content-center py-5">
        <div class="spinner-border text-primary mb-3" role="status">
          <span class="visually-hidden">Cargando...</span>
        </div>
        <p class="text-muted mb-0">${escapeHTML(message)}</p>
      </div>
    `

    els.btnSave.style.display = 'none'
    els.btnCancel.style.display = 'none'
  },

  hideLoading() {
    const els = getEls()
    if (!els.btnSave) return
    els.btnSave.style.display = ''
    els.btnCancel.style.display = ''
  }
}

// src/shared/utils/__tests__/asyncMutex.test.js
import { describe, it, expect, vi } from 'vitest'
import { createAsyncMutex } from '../asyncMutex.js'

describe('asyncMutex', () => {
  it('should prevent concurrent execution of guarded functions', async () => {
    const mutex = createAsyncMutex()
    const callOrder = []

    const slowFunc1 = vi.fn(async () => {
      callOrder.push('start-1')
      await new Promise(resolve => setTimeout(resolve, 100))
      callOrder.push('end-1')
    })

    const slowFunc2 = vi.fn(async () => {
      callOrder.push('start-2')
      await new Promise(resolve => setTimeout(resolve, 50))
      callOrder.push('end-2')
    })

    // Call both functions concurrently
    const [result1, result2] = await Promise.all([
      mutex.run(slowFunc1),
      mutex.run(slowFunc2)
    ])

    // func2 should start AFTER func1 ends, not before
    expect(callOrder).toEqual(['start-1', 'end-1', 'start-2', 'end-2'])
    expect(slowFunc1).toHaveBeenCalled()
    expect(slowFunc2).toHaveBeenCalled()
  })

  it('should return the result of the guarded function', async () => {
    const mutex = createAsyncMutex()
    const result = await mutex.run(async () => 'hello')
    expect(result).toBe('hello')
  })

  it('should propagate errors from guarded function', async () => {
    const mutex = createAsyncMutex()
    await expect(
      mutex.run(async () => {
        throw new Error('test error')
      })
    ).rejects.toThrow('test error')
  })

  it('should release lock even if function throws', async () => {
    const mutex = createAsyncMutex()
    const callOrder = []

    const failingFunc = vi.fn(async () => {
      callOrder.push('start-fail')
      throw new Error('oops')
    })

    const successFunc = vi.fn(async () => {
      callOrder.push('start-success')
    })

    // First call fails
    try {
      await mutex.run(failingFunc)
    } catch (_e) {
      // Expected
    }

    // Second call should still execute
    await mutex.run(successFunc)

    expect(callOrder).toEqual(['start-fail', 'start-success'])
  })
})

/**
 * sanitize.js — Single source of truth for escaping and input sanitization.
 *
 * Rules:
 *  - escapeHTML  → use when rendering user data inside innerHTML templates
 *  - sanitizeText → use before saving free-text fields to the database
 *  - sanitizeFormData → use at form submit to clean an entire data object
 *
 * This module has NO external dependencies. DOMPurify is intentionally NOT
 * used here because we control what goes into innerHTML via escapeHTML, and
 * we do NOT allow rich HTML input from end users anywhere in this app.
 */

// ---------------------------------------------------------------------------
// HTML escaping — prevents XSS when interpolating data into innerHTML
// ---------------------------------------------------------------------------

const HTML_ESCAPE_MAP = {
  '&': '&amp;',
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#39;',
  '/': '&#x2F;',
}

/**
 * Escape all HTML-special characters in a string so it renders as plain text.
 * Use this every time you interpolate user-supplied data into an innerHTML template.
 *
 * @param {*} value - Any value (non-strings are coerced or returned as '')
 * @returns {string}
 *
 * @example
 * element.innerHTML = `<p>${escapeHTML(user.nombre)}</p>`
 */
export function escapeHTML(value) {
  if (value === null || value === undefined) return ''
  return String(value).replace(/[&<>"'/]/g, ch => HTML_ESCAPE_MAP[ch])
}

// ---------------------------------------------------------------------------
// Text sanitization — strips control characters and dangerous patterns
// before persisting to the database
// ---------------------------------------------------------------------------

/**
 * Sanitize a plain-text string before saving it.
 * - Removes null bytes and other ASCII control characters (except tab/newline)
 * - Strips `javascript:` URI schemes (belt-and-suspenders)
 * - Trims leading/trailing whitespace
 * - Enforces an optional max length
 *
 * Does NOT strip HTML tags — that is escapeHTML's job at render time.
 *
 * @param {string} value
 * @param {{ maxLength?: number }} [options]
 * @returns {string}
 */
export function sanitizeText(value, { maxLength } = {}) {
  if (!value) return ''
  let result = String(value)
    .trim()
    // Remove null bytes and ASCII control chars except \t (9) and \n (10)
    .replace(/[\x00-\x08\x0B-\x1F\x7F]/g, '')
    // Strip javascript: URI scheme (case-insensitive, with optional whitespace/encoding)
    .replace(/j\s*a\s*v\s*a\s*s\s*c\s*r\s*i\s*p\s*t\s*:/gi, '')
  if (maxLength && result.length > maxLength) {
    result = result.slice(0, maxLength)
  }
  return result
}

// ---------------------------------------------------------------------------
// Form data sanitizer — applies sanitizeText to every string field in an object
// ---------------------------------------------------------------------------

/**
 * Sanitize all string fields in a plain data object.
 * Non-string values (numbers, booleans, nulls, arrays) are passed through unchanged.
 * Nested objects are NOT recursed — pass nested objects separately if needed.
 *
 * @param {Record<string, unknown>} data
 * @param {Record<string, { maxLength?: number }>} [fieldOptions] - Per-field options
 * @returns {Record<string, unknown>} New object with sanitized string fields
 *
 * @example
 * const clean = sanitizeFormData(
 *   { nombre: rawNombre, correo: rawEmail, nota: rawNota },
 *   { nota: { maxLength: 500 } }
 * )
 */
export function sanitizeFormData(data, fieldOptions = {}) {
  const result = {}
  for (const [key, value] of Object.entries(data)) {
    if (typeof value === 'string') {
      result[key] = sanitizeText(value, fieldOptions[key] ?? {})
    } else {
      result[key] = value
    }
  }
  return result
}

// ---------------------------------------------------------------------------
// Convenience re-export for callers that previously used common.js
// ---------------------------------------------------------------------------
export default { escapeHTML, sanitizeText, sanitizeFormData }

/**
 * Shared Validators
 * Validaciones comunes reutilizables
 */

export const Validators = {
  /**
   * Valida email
   */
  email(value) {
    if (!value) return true // opcional
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)
  },

  /**
   * Valida longitud mínima y máxima
   */
  length(value, min = 0, max = Infinity) {
    if (!value) return min === 0
    return value.length >= min && value.length <= max
  },

  /**
   * Valida campo requerido
   */
  required(value) {
    return value !== undefined && value !== null && String(value).trim() !== ''
  },

  /**
   * Valida número en rango
   */
  range(value, min = -Infinity, max = Infinity) {
    const num = Number(value)
    return !isNaN(num) && num >= min && num <= max
  },

  /**
   * Valida fecha no futura
   */
  notFuture(value) {
    if (!value) return true
    return new Date(value) <= new Date()
  },

  /**
   * Valida teléfono (formato básico)
   */
  phone(value) {
    if (!value) return true
    return /^[\d\s\+\-\(\)]{7,20}$/.test(value)
  },

  /**
   * Valida cédula (solo dígitos, longitud)
   */
  cedula(value) {
    if (!value) return true
    return /^\d{5,20}$/.test(value.trim())
  },

  /**
   * Valida URL
   */
  url(value) {
    if (!value) return true
    try {
      new URL(value)
      return true
    } catch {
      return false
    }
  },

  /**
   * Ejecuta múltiples validaciones
   * @returns {string[]} Array de mensajes de error
   */
  run(validations) {
    const errors = []
    for (const { test, message } of validations) {
      if (!test()) errors.push(message)
    }
    return errors
  },
}
